INSERT INTO public.questions (id, title, prompt, schema_name, difficulty, estimated_time_minutes, solution_sql) VALUES
('a74fc12b-3606-42e3-8082-ef632e8af50b', 'List all airports with their iata_code, city, and ...', 'List all airports with their iata_code, city, and country, ordered alphabetically by city.', 'airlines', 'Easy', 5, 'SELECT iata_code, city, country FROM airports ORDER BY city;'),
('ae78514e-172d-47b4-a7e9-ec480d77febe', 'Find all flights with status ''Cancelled''. Show fli...', 'Find all flights with status ''Cancelled''. Show flight_id, flight_no, and scheduled_dep.', 'airlines', 'Easy', 5, 'SELECT flight_id, flight_no, scheduled_dep FROM flights WHERE status = ''Cancelled'';'),
('d4cf9f74-46f7-462e-a292-7a1ed12b2a69', 'Show all bookings in Business class. Show booking_...', 'Show all bookings in Business class. Show booking_id, flight_id, seat_no, and price.', 'airlines', 'Easy', 5, 'SELECT booking_id, flight_id, seat_no, price FROM bookings WHERE cabin_class = ''Business'';'),
('7f734462-2dff-4ebf-8e74-c78d4a632e1f', 'List all aircraft models and their seating_capacit...', 'List all aircraft models and their seating_capacity, ordered by capacity descending.', 'airlines', 'Easy', 5, 'SELECT model, manufacturer, seating_capacity FROM aircraft ORDER BY seating_capacity DESC;'),
('0be5bf53-8552-4033-828c-8d1f54becb47', 'Find all passengers with nationality ''American''. S...', 'Find all passengers with nationality ''American''. Show first_name, last_name, passport_no.', 'airlines', 'Easy', 5, 'SELECT first_name, last_name, passport_no FROM passengers WHERE nationality = ''American'';'),
('0f7063de-35ba-47ff-ad73-9f370d048011', 'Count the total number of bookings. Return a singl...', 'Count the total number of bookings. Return a single value total_bookings.', 'airlines', 'Easy', 5, 'SELECT COUNT(*) AS total_bookings FROM bookings;'),
('31619ba1-1bcd-42aa-b193-8434768aaf9f', 'List the top 5 most expensive bookings. Show booki...', 'List the top 5 most expensive bookings. Show booking_id, flight_id, price.', 'airlines', 'Easy', 5, 'SELECT booking_id, flight_id, price FROM bookings ORDER BY price DESC LIMIT 5;'),
('9c7328b0-7eba-4c57-b5e4-aad183ff7804', 'Find all flights that departed from JFK airport (o...', 'Find all flights that departed from JFK airport (origin_id = 1). Show flight_no, scheduled_dep, destination_id.', 'airlines', 'Easy', 5, 'SELECT flight_no, scheduled_dep, destination_id FROM flights WHERE origin_id = 1;'),
('3ea395a5-926a-45cb-898f-6474d6689ac9', 'Find bookings with no seat number assigned (seat_n...', 'Find bookings with no seat number assigned (seat_no IS NULL). Show booking_id, passenger_id, flight_id.', 'airlines', 'Easy', 5, 'SELECT booking_id, passenger_id, flight_id FROM bookings WHERE seat_no IS NULL;'),
('0a9b28b7-68a3-4bdf-b0d0-6b4de5bbadf7', 'Count how many passengers booked each cabin class....', 'Count how many passengers booked each cabin class. Show cabin_class and count.', 'airlines', 'Easy', 5, 'SELECT cabin_class, COUNT(*) AS count FROM bookings GROUP BY cabin_class ORDER BY count DESC;'),
('e359ec76-71a8-42ef-ac0c-b919a186e95d', 'List all routes showing origin_id, destination_id,...', 'List all routes showing origin_id, destination_id, distance_km, ordered by distance DESC.', 'airlines', 'Easy', 5, 'SELECT origin_id, destination_id, distance_km, avg_duration_mins FROM routes ORDER BY distance_km DESC;'),
('75a6e01a-3207-415e-a0ab-b50dfa35b03a', 'Find all flights scheduled in January 2024. Show f...', 'Find all flights scheduled in January 2024. Show flight_no and scheduled_dep.', 'airlines', 'Easy', 5, 'SELECT flight_no, scheduled_dep FROM flights WHERE scheduled_dep BETWEEN ''2024-01-01'' AND ''2024-01-31 23:59:59'';'),
('040238e3-1ec4-4f41-b8d8-c25abf31ed2f', 'Show all crew members with the role of Captain. Sh...', 'Show all crew members with the role of Captain. Show crew_id, flight_id, employee_id.', 'airlines', 'Easy', 5, 'SELECT crew_id, flight_id, employee_id FROM crew WHERE role = ''Captain'';'),
('b480023f-f230-40d3-8ba0-541ccb131679', 'Calculate the average booking price. Return a sing...', 'Calculate the average booking price. Return a single value labeled avg_price.', 'airlines', 'Easy', 5, 'SELECT ROUND(AVG(price), 2) AS avg_price FROM bookings;'),
('357783ad-ac20-4a72-95e5-c3b611c1b692', 'Find all passengers born after 1990. Show first_na...', 'Find all passengers born after 1990. Show first_name, last_name, dob.', 'airlines', 'Easy', 5, 'SELECT first_name, last_name, dob FROM passengers WHERE dob > ''1990-01-01'' ORDER BY dob;'),
('fd735f37-1f02-43f0-ac89-fd721308ead0', 'List all aircraft manufactured after 2016. Show mo...', 'List all aircraft manufactured after 2016. Show model, manufacturer, year_manufactured.', 'airlines', 'Easy', 5, 'SELECT model, manufacturer, year_manufactured FROM aircraft WHERE year_manufactured > 2016 ORDER BY year_manufactured;'),
('a42c4c60-48fe-4ced-9c15-388d13efd75c', 'Count how many flights each aircraft has handled. ...', 'Count how many flights each aircraft has handled. Show aircraft_id and flight_count.', 'airlines', 'Easy', 5, 'SELECT aircraft_id, COUNT(*) AS flight_count FROM flights GROUP BY aircraft_id ORDER BY flight_count DESC;'),
('3e8ea080-8e50-484d-ad53-8542a25118d3', 'Show all distinct countries with airports in the d...', 'Show all distinct countries with airports in the dataset. Return country, ordered alphabetically.', 'airlines', 'Easy', 5, 'SELECT DISTINCT country FROM airports ORDER BY country;'),
('2e7bf630-a8c9-4a3b-ab84-7bd7ca2773f6', 'Find all flights that arrived (status = Arrived). ...', 'Find all flights that arrived (status = Arrived). Show flight_no, actual_arr.', 'airlines', 'Easy', 5, 'SELECT flight_no, actual_arr FROM flights WHERE status = ''Arrived'';'),
('ec37695b-9d34-42f6-a507-28eac6c7cd8c', 'Count total bookings per flight. Show flight_id an...', 'Count total bookings per flight. Show flight_id and booking_count, ordered by booking_count DESC.', 'airlines', 'Easy', 5, 'SELECT flight_id, COUNT(*) AS booking_count FROM bookings GROUP BY flight_id ORDER BY booking_count DESC;'),
('b7b5d483-b17a-42cc-b38c-5f55f80d1a5b', 'Show each flight with its origin and destination c...', 'Show each flight with its origin and destination city. Show flight_no, origin city, destination city.', 'airlines', 'Medium', 15, 'SELECT f.flight_no, a1.city AS origin_city, a2.city AS destination_city FROM flights f JOIN airports a1 ON f.origin_id = a1.airport_id JOIN airports a2 ON f.destination_id = a2.airport_id;'),
('d87f15bc-8d62-4cf2-842e-3cbe3c107506', 'Calculate total revenue per flight (sum of booking...', 'Calculate total revenue per flight (sum of bookings price). Show flight_no and total_revenue, ordered DESC.', 'airlines', 'Medium', 15, 'SELECT f.flight_no, SUM(b.price) AS total_revenue FROM flights f JOIN bookings b ON f.flight_id = b.flight_id GROUP BY f.flight_id ORDER BY total_revenue DESC;'),
('82c3c36c-95ce-40d6-936d-93905d337f4f', 'Show the busiest routes by number of flights. Show...', 'Show the busiest routes by number of flights. Show route: origin IATA → destination IATA and flight_count.', 'airlines', 'Medium', 15, 'SELECT a1.iata_code || '' → '' || a2.iata_code AS route, COUNT(*) AS flight_count FROM flights f JOIN airports a1 ON f.origin_id = a1.airport_id JOIN airports a2 ON f.destination_id = a2.airport_id GROUP BY f.origin_id, f.destination_id ORDER BY flight_count DESC;'),
('20f2d7ee-f8e6-4de8-8c0d-a596b519c4bc', 'Show all passengers who checked in (checked_in = 1...', 'Show all passengers who checked in (checked_in = 1). Show first_name, last_name, flight_no, cabin_class.', 'airlines', 'Medium', 15, 'SELECT p.first_name, p.last_name, f.flight_no, b.cabin_class FROM bookings b JOIN passengers p ON b.passenger_id = p.passenger_id JOIN flights f ON b.flight_id = f.flight_id WHERE b.checked_in = 1;'),
('e01e039c-7fe0-4458-99b0-ba80e134f3b6', 'Calculate the actual delay in minutes for each fli...', 'Calculate the actual delay in minutes for each flight that arrived (actual_arr - scheduled_arr). Show flight_no, delay_minutes (negative = early). Order by delay_minutes DESC.', 'airlines', 'Medium', 15, 'SELECT flight_no, ROUND((julianday(actual_arr) - julianday(scheduled_arr)) * 1440) AS delay_minutes FROM flights WHERE actual_arr IS NOT NULL ORDER BY delay_minutes DESC;'),
('1bd1ad89-96cc-4491-a699-822a635e4e8b', 'Find flights that have no bookings. Show flight_id...', 'Find flights that have no bookings. Show flight_id and flight_no.', 'airlines', 'Medium', 15, 'SELECT f.flight_id, f.flight_no FROM flights f LEFT JOIN bookings b ON f.flight_id = b.flight_id WHERE b.booking_id IS NULL;'),
('6c6107a6-cb72-4ab4-8467-5a6eec52d95f', 'Show the average booking price per cabin class and...', 'Show the average booking price per cabin class and per flight status. Show cabin_class, status, and avg_price.', 'airlines', 'Medium', 15, 'SELECT b.cabin_class, f.status, ROUND(AVG(b.price), 2) AS avg_price FROM bookings b JOIN flights f ON b.flight_id = f.flight_id GROUP BY b.cabin_class, f.status ORDER BY cabin_class, status;'),
('ae776880-4be0-4f2b-bee3-c9b2078c51b3', 'Find the most booked aircraft model. Show model an...', 'Find the most booked aircraft model. Show model and total_bookings.', 'airlines', 'Medium', 15, 'SELECT ac.model, COUNT(b.booking_id) AS total_bookings FROM aircraft ac JOIN flights f ON ac.aircraft_id = f.aircraft_id JOIN bookings b ON f.flight_id = b.flight_id GROUP BY ac.aircraft_id, ac.model ORDER BY total_bookings DESC LIMIT 1;'),
('05487f68-b03e-4871-8ea7-c670592a4bef', 'Show total revenue collected from each country (ba...', 'Show total revenue collected from each country (based on passenger nationality). Show nationality and total_revenue.', 'airlines', 'Medium', 15, 'SELECT p.nationality, SUM(b.price) AS total_revenue FROM bookings b JOIN passengers p ON b.passenger_id = p.passenger_id GROUP BY p.nationality ORDER BY total_revenue DESC;'),
('7708f675-e4ec-405c-aa77-1ec343c5dbe7', 'Find passengers who have taken more than 1 flight....', 'Find passengers who have taken more than 1 flight. Show first_name, last_name, and flight_count.', 'airlines', 'Medium', 15, 'SELECT p.first_name, p.last_name, COUNT(b.flight_id) AS flight_count FROM passengers p JOIN bookings b ON p.passenger_id = b.passenger_id GROUP BY p.passenger_id HAVING COUNT(b.flight_id) > 1 ORDER BY flight_count DESC;'),
('2a34f023-9e00-463a-b5ec-63e8ea8a0693', 'Show total bookings per origin country. JOIN fligh...', 'Show total bookings per origin country. JOIN flights → airports → bookings. Show country and booking_count.', 'airlines', 'Medium', 15, 'SELECT a.country, COUNT(b.booking_id) AS booking_count FROM flights f JOIN airports a ON f.origin_id = a.airport_id JOIN bookings b ON f.flight_id = b.flight_id GROUP BY a.country ORDER BY booking_count DESC;'),
('b72ce39d-6542-4b10-abb8-3478ca4451fb', 'Calculate the load factor per flight (booked seats...', 'Calculate the load factor per flight (booked seats / aircraft capacity × 100%). Show flight_no, capacity, booked_seats, and load_factor_pct.', 'airlines', 'Medium', 15, 'SELECT f.flight_no, ac.seating_capacity, COUNT(b.booking_id) AS booked_seats, ROUND(100.0 * COUNT(b.booking_id) / ac.seating_capacity, 1) AS load_factor_pct FROM flights f JOIN aircraft ac ON f.aircraft_id = ac.aircraft_id LEFT JOIN bookings b ON f.flight_id = b.flight_id GROUP BY f.flight_id ORDER BY load_factor_pct DESC;'),
('4d07af33-992f-4e3e-828e-26592379fd77', 'Show the expected vs actual flight duration for ea...', 'Show the expected vs actual flight duration for each arrived flight (in minutes). Show flight_no, expected_mins, actual_mins, difference.', 'airlines', 'Medium', 15, 'SELECT f.flight_no, ROUND((julianday(f.scheduled_arr) - julianday(f.scheduled_dep)) * 1440) AS expected_mins, ROUND((julianday(f.actual_arr) - julianday(f.actual_dep)) * 1440) AS actual_mins, ROUND((julianday(f.actual_arr) - julianday(f.actual_dep)) * 1440) - ROUND((julianday(f.scheduled_arr) - julianday(f.scheduled_dep)) * 1440) AS difference FROM flights f WHERE f.actual_arr IS NOT NULL AND f.actual_dep IS NOT NULL ORDER BY difference DESC;'),
('03d362ae-721f-4701-90f4-12ffd253ed47', 'Show the most expensive booking per flight. Show f...', 'Show the most expensive booking per flight. Show flight_no and max_price.', 'airlines', 'Medium', 15, 'SELECT f.flight_no, MAX(b.price) AS max_price FROM flights f JOIN bookings b ON f.flight_id = b.flight_id GROUP BY f.flight_id ORDER BY max_price DESC;'),
('717a2add-e281-4324-8cda-0c3bdc03d154', 'Show each route distance and the number of flights...', 'Show each route distance and the number of flights serving it. JOIN routes to flights on origin and destination.', 'airlines', 'Medium', 15, 'SELECT r.origin_id, r.destination_id, r.distance_km, COUNT(f.flight_id) AS flight_count FROM routes r LEFT JOIN flights f ON r.origin_id = f.origin_id AND r.destination_id = f.destination_id GROUP BY r.route_id ORDER BY distance_km DESC;'),
('c159e1bc-9d4e-4bf7-8741-c50c72375f0f', 'Find the nationality with the highest average book...', 'Find the nationality with the highest average booking price. Show nationality and avg_price.', 'airlines', 'Medium', 15, 'SELECT p.nationality, ROUND(AVG(b.price), 2) AS avg_price FROM bookings b JOIN passengers p ON b.passenger_id = p.passenger_id GROUP BY p.nationality ORDER BY avg_price DESC LIMIT 1;'),
('74cc4900-4307-433e-b02d-52bac975e3b9', 'Show the cancellation rate per aircraft type. Show...', 'Show the cancellation rate per aircraft type. Show model and cancellation_rate_pct.', 'airlines', 'Medium', 15, 'SELECT ac.model, ROUND(100.0 * SUM(CASE WHEN f.status = ''Cancelled'' THEN 1 ELSE 0 END) / COUNT(*), 1) AS cancellation_rate_pct FROM aircraft ac JOIN flights f ON ac.aircraft_id = f.aircraft_id GROUP BY ac.aircraft_id ORDER BY cancellation_rate_pct DESC;'),
('5a6bcbec-5b2f-43a0-9338-db1cc210e815', 'Find passengers who spent more than the average bo...', 'Find passengers who spent more than the average booking price. Show first_name, last_name, and total_spent.', 'airlines', 'Medium', 15, 'SELECT p.first_name, p.last_name, SUM(b.price) AS total_spent FROM passengers p JOIN bookings b ON p.passenger_id = b.passenger_id GROUP BY p.passenger_id HAVING SUM(b.price) > (SELECT AVG(price) FROM bookings) ORDER BY total_spent DESC;'),
('f2fecb58-5300-408e-bc6b-1724bafb89ba', 'Show the number of crew members per flight. Show f...', 'Show the number of crew members per flight. Show flight_no and crew_count.', 'airlines', 'Medium', 15, 'SELECT f.flight_no, COUNT(c.crew_id) AS crew_count FROM flights f JOIN crew c ON f.flight_id = c.flight_id GROUP BY f.flight_id ORDER BY crew_count DESC;'),
('d2f9c760-aacd-4f62-83ae-ebdda10e10ac', 'Calculate average delay (scheduled_arr to actual_a...', 'Calculate average delay (scheduled_arr to actual_arr) per origin airport for arrived flights. Show origin city and avg_delay_mins.', 'airlines', 'Medium', 15, 'SELECT a.city AS origin_city, ROUND(AVG((julianday(f.actual_arr) - julianday(f.scheduled_arr)) * 1440), 1) AS avg_delay_mins FROM flights f JOIN airports a ON f.origin_id = a.airport_id WHERE f.actual_arr IS NOT NULL GROUP BY a.airport_id ORDER BY avg_delay_mins DESC;'),
('cad5fab0-12e9-469a-9220-4e304277962c', 'Find the aircraft that generated the most revenue ...', 'Find the aircraft that generated the most revenue (sum of bookings). Show model, manufacturer, and total_revenue.', 'airlines', 'Medium', 15, 'SELECT ac.model, ac.manufacturer, SUM(b.price) AS total_revenue FROM aircraft ac JOIN flights f ON ac.aircraft_id = f.aircraft_id JOIN bookings b ON f.flight_id = b.flight_id GROUP BY ac.aircraft_id ORDER BY total_revenue DESC LIMIT 1;'),
('03f10ba5-d4a0-40eb-8604-0112d097fd81', 'Show on-time performance per aircraft (% flights n...', 'Show on-time performance per aircraft (% flights not delayed or cancelled). Show model and on_time_pct.', 'airlines', 'Medium', 15, 'SELECT ac.model, ROUND(100.0 * SUM(CASE WHEN f.status = ''Arrived'' AND f.actual_arr <= f.scheduled_arr THEN 1 ELSE 0 END) / COUNT(*), 1) AS on_time_pct FROM aircraft ac JOIN flights f ON ac.aircraft_id = f.aircraft_id GROUP BY ac.aircraft_id ORDER BY on_time_pct DESC;'),
('815e723b-060e-4662-bfa2-97b9a4f5a11f', 'Find the average route distance for each origin co...', 'Find the average route distance for each origin country. Show country and avg_distance_km.', 'airlines', 'Medium', 15, 'SELECT a.country, ROUND(AVG(r.distance_km), 0) AS avg_distance_km FROM routes r JOIN airports a ON r.origin_id = a.airport_id GROUP BY a.country ORDER BY avg_distance_km DESC;'),
('4dc33fe0-f6bf-478b-882a-55aed5ae992d', 'Show total revenue and number of passengers per fl...', 'Show total revenue and number of passengers per flight status. Show status, total_revenue, passenger_count.', 'airlines', 'Medium', 15, 'SELECT f.status, SUM(b.price) AS total_revenue, COUNT(b.booking_id) AS passenger_count FROM flights f LEFT JOIN bookings b ON f.flight_id = b.flight_id GROUP BY f.status ORDER BY total_revenue DESC;'),
('db9687e9-8c03-4a47-9988-66344e1f46e8', 'Show the check-in rate per flight (checked_in / to...', 'Show the check-in rate per flight (checked_in / total bookings × 100). Show flight_no and checkin_rate_pct.', 'airlines', 'Medium', 15, 'SELECT f.flight_no, ROUND(100.0 * SUM(b.checked_in) / COUNT(b.booking_id), 1) AS checkin_rate_pct FROM flights f JOIN bookings b ON f.flight_id = b.flight_id GROUP BY f.flight_id ORDER BY checkin_rate_pct DESC;'),
('083f3a81-1cd7-42cb-8a5a-eb12bfc4db76', 'Rank passengers by total spending using DENSE_RANK...', 'Rank passengers by total spending using DENSE_RANK. Show passenger name, total_spent, and spending_rank.', 'airlines', 'Hard', 25, 'SELECT passenger_name, total_spent, DENSE_RANK() OVER (ORDER BY total_spent DESC) AS spending_rank FROM (SELECT p.first_name || '' '' || p.last_name AS passenger_name, SUM(b.price) AS total_spent FROM passengers p JOIN bookings b ON p.passenger_id = b.passenger_id GROUP BY p.passenger_id) ORDER BY spending_rank;'),
('5c3f8df9-4e2a-461b-88cc-631bd51262f3', 'Find the cheapest booking per flight using ROW_NUM...', 'Find the cheapest booking per flight using ROW_NUMBER(). Show flight_no, passenger name, price, and rn where rn = 1.', 'airlines', 'Hard', 25, 'SELECT flight_no, passenger_name, price FROM (SELECT f.flight_no, p.first_name || '' '' || p.last_name AS passenger_name, b.price, ROW_NUMBER() OVER (PARTITION BY b.flight_id ORDER BY b.price ASC) AS rn FROM bookings b JOIN passengers p ON b.passenger_id = p.passenger_id JOIN flights f ON b.flight_id = f.flight_id) WHERE rn = 1 ORDER BY price;'),
('8ff6890a-01bf-44e9-945a-2b2984e437a6', 'Calculate a running total of revenue by flight_id ...', 'Calculate a running total of revenue by flight_id order. Show flight_id, flight_no, flight_revenue, and running_total.', 'airlines', 'Hard', 25, 'WITH rev AS (SELECT f.flight_id, f.flight_no, SUM(b.price) AS flight_revenue FROM flights f JOIN bookings b ON f.flight_id = b.flight_id GROUP BY f.flight_id) SELECT flight_id, flight_no, flight_revenue, SUM(flight_revenue) OVER (ORDER BY flight_id ROWS UNBOUNDED PRECEDING) AS running_total FROM rev ORDER BY flight_id;'),
('a957a08a-8a43-4b1f-b8d3-9436e086d4b6', 'For each flight route, compare the current flight''...', 'For each flight route, compare the current flight''s delay to the previous flight on the same route using LAG. Show flight_no, origin_id, destination_id, delay_mins, and prev_delay_mins.', 'airlines', 'Hard', 25, 'WITH delays AS (SELECT flight_id, flight_no, origin_id, destination_id, scheduled_dep, ROUND((julianday(actual_arr) - julianday(scheduled_arr)) * 1440) AS delay_mins FROM flights WHERE actual_arr IS NOT NULL) SELECT flight_no, origin_id, destination_id, delay_mins, LAG(delay_mins) OVER (PARTITION BY origin_id, destination_id ORDER BY scheduled_dep) AS prev_delay_mins FROM delays ORDER BY origin_id, destination_id, scheduled_dep;'),
('a5e8fff2-385d-47e6-9553-487ef230c450', 'Create a revenue leaderboard: rank flights by reve...', 'Create a revenue leaderboard: rank flights by revenue within each cabin class using RANK(). Show cabin_class, flight_no, flight_revenue, and cabin_rank.', 'airlines', 'Hard', 25, 'WITH rev AS (SELECT f.flight_no, b.cabin_class, SUM(b.price) AS flight_revenue FROM flights f JOIN bookings b ON f.flight_id = b.flight_id GROUP BY f.flight_id, b.cabin_class) SELECT cabin_class, flight_no, flight_revenue, RANK() OVER (PARTITION BY cabin_class ORDER BY flight_revenue DESC) AS cabin_rank FROM rev ORDER BY cabin_class, cabin_rank;'),
('ef5cca6e-688e-4140-a56f-ce889acc82a2', 'Compute the month-over-month revenue change for th...', 'Compute the month-over-month revenue change for the airline. Show month, monthly_revenue, prev_month_revenue, and revenue_change.', 'airlines', 'Hard', 25, 'WITH monthly AS (SELECT strftime(''%Y-%m'', f.scheduled_dep) AS month, SUM(b.price) AS monthly_revenue FROM flights f JOIN bookings b ON f.flight_id = b.flight_id GROUP BY month) SELECT month, monthly_revenue, LAG(monthly_revenue) OVER (ORDER BY month) AS prev_month_revenue, monthly_revenue - LAG(monthly_revenue) OVER (ORDER BY month) AS revenue_change FROM monthly ORDER BY month;'),
('e24d2dc8-713d-4882-8337-e7f700fe939c', 'Identify the top-earning employee (by role) across...', 'Identify the top-earning employee (by role) across all crew roles using NTILE(3). Show employee_id, role, flight_count, and tercile.', 'airlines', 'Hard', 25, 'SELECT employee_id, role, flight_count, NTILE(3) OVER (ORDER BY flight_count DESC) AS tercile FROM (SELECT employee_id, role, COUNT(*) AS flight_count FROM crew GROUP BY employee_id, role) ORDER BY tercile, flight_count DESC;'),
('92ffec63-8cab-404b-8650-2fef1dae73a7', 'Find passengers who flew on both a Boeing and an A...', 'Find passengers who flew on both a Boeing and an Airbus aircraft. Show first_name and last_name.', 'airlines', 'Hard', 25, 'SELECT p.first_name, p.last_name FROM passengers p JOIN bookings b ON p.passenger_id = b.passenger_id JOIN flights f ON b.flight_id = f.flight_id JOIN aircraft ac ON f.aircraft_id = ac.aircraft_id GROUP BY p.passenger_id HAVING SUM(CASE WHEN ac.manufacturer = ''Boeing'' THEN 1 ELSE 0 END) > 0 AND SUM(CASE WHEN ac.manufacturer = ''Airbus'' THEN 1 ELSE 0 END) > 0;'),
('da03a85b-bb9c-4ad7-89ad-e3ff57385d11', 'For each booked passenger, find the next flight th...', 'For each booked passenger, find the next flight they are booked on (ordered by booked_at). Show passenger_id, flight_no, booked_at, and next_flight_no.', 'airlines', 'Hard', 25, 'SELECT b.passenger_id, f.flight_no, b.booked_at, LEAD(f.flight_no) OVER (PARTITION BY b.passenger_id ORDER BY b.booked_at) AS next_flight_no FROM bookings b JOIN flights f ON b.flight_id = f.flight_id ORDER BY b.passenger_id, b.booked_at;'),
('c93ac47d-00fc-4896-90a3-bac4ae9c21ac', 'Calculate a 3-flight rolling average revenue (by f...', 'Calculate a 3-flight rolling average revenue (by flight_id). Show flight_id, flight_revenue, and rolling_avg_3.', 'airlines', 'Hard', 25, 'WITH rev AS (SELECT f.flight_id, SUM(b.price) AS flight_revenue FROM flights f JOIN bookings b ON f.flight_id = b.flight_id GROUP BY f.flight_id) SELECT flight_id, flight_revenue, ROUND(AVG(flight_revenue) OVER (ORDER BY flight_id ROWS BETWEEN 2 PRECEDING AND CURRENT ROW), 2) AS rolling_avg_3 FROM rev ORDER BY flight_id;'),
('cb27985b-7691-4038-9849-d036cad7d271', 'Show the percentage of total airline revenue each ...', 'Show the percentage of total airline revenue each flight represents. Show flight_no, flight_revenue, and revenue_pct_of_total.', 'airlines', 'Hard', 25, 'WITH rev AS (SELECT f.flight_no, SUM(b.price) AS flight_revenue FROM flights f JOIN bookings b ON f.flight_id = b.flight_id GROUP BY f.flight_id) SELECT flight_no, flight_revenue, ROUND(100.0 * flight_revenue / SUM(flight_revenue) OVER (), 2) AS revenue_pct_of_total FROM rev ORDER BY revenue_pct_of_total DESC;'),
('f250da89-f4ad-4d0f-8649-cb5634386ccd', 'For each route, calculate average delay and compar...', 'For each route, calculate average delay and compare it to the overall average delay (deviation). Show route, avg_delay, overall_avg, and deviation.', 'airlines', 'Hard', 25, 'WITH route_delays AS (SELECT f.origin_id, f.destination_id, ROUND(AVG((julianday(f.actual_arr) - julianday(f.scheduled_arr)) * 1440), 1) AS avg_delay FROM flights f WHERE f.actual_arr IS NOT NULL GROUP BY f.origin_id, f.destination_id) SELECT origin_id || ''→'' || destination_id AS route, avg_delay, ROUND(AVG(avg_delay) OVER (), 1) AS overall_avg, ROUND(avg_delay - AVG(avg_delay) OVER (), 1) AS deviation FROM route_delays ORDER BY deviation DESC;'),
('7c930f1e-33e6-4eb2-97a1-0cb7c443b7f0', 'Calculate revenue per passenger-kilometer (yield) ...', 'Calculate revenue per passenger-kilometer (yield) per flight: total_revenue / (passengers × distance_km). Show flight_no and yield_per_pkm.', 'airlines', 'Hard', 25, 'WITH rev AS (SELECT f.flight_id, f.flight_no, f.origin_id, f.destination_id, SUM(b.price) AS revenue, COUNT(b.booking_id) AS pax FROM flights f JOIN bookings b ON f.flight_id = b.flight_id GROUP BY f.flight_id) SELECT r.flight_no, ROUND(r.revenue / (r.pax * rt.distance_km), 4) AS yield_per_pkm FROM rev r JOIN routes rt ON r.origin_id = rt.origin_id AND r.destination_id = rt.destination_id ORDER BY yield_per_pkm DESC;'),
('2aa36857-4581-44ba-882b-29e1216cd235', 'Identify flight ''families'' using FIRST_VALUE(): fo...', 'Identify flight ''families'' using FIRST_VALUE(): for each origin airport, show the first (earliest scheduled) flight and the revenue of each subsequent flight. Show origin_id, flight_no, scheduled_dep, revenue, and first_flight_no.', 'airlines', 'Hard', 25, 'WITH rev AS (SELECT f.flight_id, f.flight_no, f.origin_id, f.scheduled_dep, SUM(b.price) AS revenue FROM flights f LEFT JOIN bookings b ON f.flight_id = b.flight_id GROUP BY f.flight_id) SELECT origin_id, flight_no, scheduled_dep, revenue, FIRST_VALUE(flight_no) OVER (PARTITION BY origin_id ORDER BY scheduled_dep) AS first_flight_no FROM rev ORDER BY origin_id, scheduled_dep;'),
('c0949351-9fdc-4e5c-b0d1-691bb5e82c41', 'Create a complete flight performance scorecard: fo...', 'Create a complete flight performance scorecard: for each flight show flight_no, delay_mins, revenue, load_factor_pct, and a composite_score = (100-delay_mins) + revenue/100 + load_factor_pct. Rank by composite_score DESC.', 'airlines', 'Hard', 25, 'WITH perf AS (SELECT f.flight_no, ROUND((julianday(f.actual_arr) - julianday(f.scheduled_arr)) * 1440, 0) AS delay_mins, SUM(b.price) AS revenue, ROUND(100.0 * COUNT(b.booking_id) / ac.seating_capacity, 1) AS load_factor_pct FROM flights f LEFT JOIN bookings b ON f.flight_id = b.flight_id JOIN aircraft ac ON f.aircraft_id = ac.aircraft_id WHERE f.actual_arr IS NOT NULL GROUP BY f.flight_id) SELECT flight_no, delay_mins, revenue, load_factor_pct, ROUND((100 - COALESCE(delay_mins, 0)) + revenue / 100.0 + load_factor_pct, 1) AS composite_score, RANK() OVER (ORDER BY (100 - COALESCE(delay_mins, 0)) + revenue / 100.0 + load_factor_pct DESC) AS perf_rank FROM perf ORDER BY perf_rank;'),
('70e0e85b-18aa-41ff-a5c2-0e86adef898d', 'List all customers with their first_name, last_nam...', 'List all customers with their first_name, last_name, and email.', 'banking', 'Easy', 5, 'SELECT first_name, last_name, email FROM customers;'),
('866ae950-1e1c-460b-b880-1aca3bb3e976', 'Find all active accounts (is_active = 1). Show acc...', 'Find all active accounts (is_active = 1). Show account_id, customer_id, type, and balance.', 'banking', 'Easy', 5, 'SELECT account_id, customer_id, type, balance FROM accounts WHERE is_active = 1 ORDER BY balance DESC;'),
('4e4a1138-0ba5-4c26-806a-780dda380165', 'Show all savings accounts. Show account_id, custom...', 'Show all savings accounts. Show account_id, customer_id, balance.', 'banking', 'Easy', 5, 'SELECT account_id, customer_id, balance FROM accounts WHERE type = ''Savings'' ORDER BY balance DESC;'),
('29c36cf7-3ef6-4d74-bf0d-e675dc002948', 'Count how many accounts are of each type. Show acc...', 'Count how many accounts are of each type. Show account type and count.', 'banking', 'Easy', 5, 'SELECT type, COUNT(*) AS account_count FROM accounts GROUP BY type ORDER BY account_count DESC;'),
('322dee53-14c7-40fc-a62c-93a58d5c597f', 'List the top 5 highest-balance accounts. Show acco...', 'List the top 5 highest-balance accounts. Show account_id, type, and balance.', 'banking', 'Easy', 5, 'SELECT account_id, type, balance FROM accounts ORDER BY balance DESC LIMIT 5;'),
('6baab830-82d8-4a36-90a4-b948b1d08a26', 'Find all transactions of type ''Deposit''. Show txn_...', 'Find all transactions of type ''Deposit''. Show txn_id, account_id, amount, txn_date.', 'banking', 'Easy', 5, 'SELECT txn_id, account_id, amount, txn_date FROM transactions WHERE type = ''Deposit'' ORDER BY txn_date DESC;'),
('9b48dbf5-aab2-495d-b63c-1dc72d39b385', 'Show all branches with their name and city....', 'Show all branches with their name and city.', 'banking', 'Easy', 5, 'SELECT name, city, country FROM branches;'),
('e0358b4d-bd70-46c8-8611-bfe9efe21467', 'Find all loans that are currently Active. Show loa...', 'Find all loans that are currently Active. Show loan_id, customer_id, principal, status.', 'banking', 'Easy', 5, 'SELECT loan_id, customer_id, principal, status FROM loans WHERE status = ''Active'';'),
('9cd1621a-5a42-46c2-804f-7289db882d2f', 'Calculate total deposits per account. Show account...', 'Calculate total deposits per account. Show account_id and total_deposited.', 'banking', 'Easy', 5, 'SELECT account_id, SUM(amount) AS total_deposited FROM transactions WHERE type = ''Deposit'' GROUP BY account_id ORDER BY total_deposited DESC;'),
('40213d61-bacd-4d07-b122-c6afa8964c8f', 'Count total number of employees. Return a single n...', 'Count total number of employees. Return a single number labeled employee_count.', 'banking', 'Easy', 5, 'SELECT COUNT(*) AS employee_count FROM employees;'),
('0b0f6ad4-9917-43de-91f2-d11cbca2e036', 'Find all accounts with a balance of zero or negati...', 'Find all accounts with a balance of zero or negative. Show account_id, customer_id, balance.', 'banking', 'Easy', 5, 'SELECT account_id, customer_id, balance FROM accounts WHERE balance <= 0;'),
('412ad117-0045-483c-8958-6f9b83710078', 'Find all employees who are Branch Managers. Show e...', 'Find all employees who are Branch Managers. Show employee_id, first_name, last_name, branch_id.', 'banking', 'Easy', 5, 'SELECT employee_id, first_name, last_name, branch_id FROM employees WHERE role = ''Branch Manager'';'),
('6a75dac0-c847-4ab5-86f3-7f54543138a5', 'Show all loan payments that were late (is_late = 1...', 'Show all loan payments that were late (is_late = 1). Show payment_id, loan_id, amount, paid_at.', 'banking', 'Easy', 5, 'SELECT payment_id, loan_id, amount, paid_at FROM loan_payments WHERE is_late = 1;'),
('53082b00-e3d8-4aca-b678-63e56a3babab', 'Find all accounts opened in 2022. Show account_id,...', 'Find all accounts opened in 2022. Show account_id, type, opened_at.', 'banking', 'Easy', 5, 'SELECT account_id, type, opened_at FROM accounts WHERE strftime(''%Y'', opened_at) = ''2022'';'),
('d35f92b5-c308-4439-8b0b-8a33ede48897', 'List the 3 largest loans by principal. Show loan_i...', 'List the 3 largest loans by principal. Show loan_id, customer_id, principal.', 'banking', 'Easy', 5, 'SELECT loan_id, customer_id, principal FROM loans ORDER BY principal DESC LIMIT 3;'),
('bd3015b3-035c-4a53-bfc4-00c9c65e4abf', 'Find customers with no phone on file (phone IS NUL...', 'Find customers with no phone on file (phone IS NULL). Show customer_id, first_name, last_name.', 'banking', 'Easy', 5, 'SELECT customer_id, first_name, last_name FROM customers WHERE phone IS NULL;'),
('d52251f8-3d2e-4f8d-9697-a7d6837aaf68', 'Show the average salary per role among employees. ...', 'Show the average salary per role among employees. Show role and avg_salary.', 'banking', 'Easy', 5, 'SELECT role, ROUND(AVG(salary), 2) AS avg_salary FROM employees GROUP BY role ORDER BY avg_salary DESC;'),
('f1d10dd3-7179-41f7-a40e-2d35eb6d62c8', 'Find all transactions with amount greater than 500...', 'Find all transactions with amount greater than 5000. Show txn_id, account_id, type, amount.', 'banking', 'Easy', 5, 'SELECT txn_id, account_id, type, amount FROM transactions WHERE amount > 5000 ORDER BY amount DESC;'),
('437e5b27-f3de-4edf-aa73-dbf34e4d75eb', 'Count transactions per type. Show type and transac...', 'Count transactions per type. Show type and transaction_count.', 'banking', 'Easy', 5, 'SELECT type, COUNT(*) AS transaction_count FROM transactions GROUP BY type ORDER BY transaction_count DESC;'),
('ffe2f78f-a766-42b0-a9a9-38a0aee87140', 'Show all loans with interest_rate above 6%. Show l...', 'Show all loans with interest_rate above 6%. Show loan_id, customer_id, interest_rate, principal.', 'banking', 'Easy', 5, 'SELECT loan_id, customer_id, interest_rate, principal FROM loans WHERE interest_rate > 6 ORDER BY interest_rate DESC;'),
('6df51dc8-8d28-4434-9b99-54c168cd072f', 'Show each customer with their total account balanc...', 'Show each customer with their total account balance across all accounts. Show customer name and total_balance.', 'banking', 'Medium', 15, 'SELECT c.first_name || '' '' || c.last_name AS customer_name, SUM(a.balance) AS total_balance FROM customers c JOIN accounts a ON c.customer_id = a.customer_id GROUP BY c.customer_id ORDER BY total_balance DESC;'),
('71092144-bee7-465e-9086-3fcfde2dfc06', 'Calculate total loan amount per branch. Show branc...', 'Calculate total loan amount per branch. Show branch name and total_loans.', 'banking', 'Medium', 15, 'SELECT b.name AS branch_name, SUM(l.principal) AS total_loans FROM branches b JOIN loans l ON b.branch_id = l.branch_id GROUP BY b.branch_id ORDER BY total_loans DESC;'),
('0959220d-be26-4a9b-b527-96b03eed577d', 'Show the total number of transactions per account,...', 'Show the total number of transactions per account, with the account type. Show account_id, type, and txn_count.', 'banking', 'Medium', 15, 'SELECT a.account_id, a.type, COUNT(t.txn_id) AS txn_count FROM accounts a LEFT JOIN transactions t ON a.account_id = t.account_id GROUP BY a.account_id ORDER BY txn_count DESC;'),
('7f9816d7-5b92-4e7c-953f-a2cb7dad1bc0', 'Find customers with total loan principal above 50,...', 'Find customers with total loan principal above 50,000. Show customer name and total_principal.', 'banking', 'Medium', 15, 'SELECT c.first_name || '' '' || c.last_name AS customer_name, SUM(l.principal) AS total_principal FROM customers c JOIN loans l ON c.customer_id = l.customer_id GROUP BY c.customer_id HAVING SUM(l.principal) > 50000 ORDER BY total_principal DESC;'),
('f3346b14-9a10-49bb-9f64-945014db5093', 'Calculate the debt-to-savings ratio per customer (...', 'Calculate the debt-to-savings ratio per customer (total loans / savings balance). Show customer name and ratio (rounded to 2 decimals).', 'banking', 'Medium', 15, 'SELECT c.first_name || '' '' || c.last_name AS customer_name, ROUND(COALESCE(SUM(l.principal), 0) / NULLIF(SUM(CASE WHEN a.type = ''Savings'' THEN a.balance ELSE 0 END), 0), 2) AS debt_to_savings FROM customers c LEFT JOIN accounts a ON c.customer_id = a.customer_id LEFT JOIN loans l ON c.customer_id = l.customer_id GROUP BY c.customer_id HAVING SUM(a.balance) > 0 ORDER BY debt_to_savings DESC;'),
('7d07bd44-0b54-479b-adeb-04cfe0415f44', 'Show branch performance: total deposits, total wit...', 'Show branch performance: total deposits, total withdrawals per branch. Show branch name, total_deposits, total_withdrawals.', 'banking', 'Medium', 15, 'SELECT b.name, SUM(CASE WHEN t.type=''Deposit'' THEN t.amount ELSE 0 END) AS total_deposits, SUM(CASE WHEN t.type=''Withdrawal'' THEN t.amount ELSE 0 END) AS total_withdrawals FROM branches b JOIN accounts a ON b.branch_id = a.branch_id LEFT JOIN transactions t ON a.account_id = t.account_id GROUP BY b.branch_id ORDER BY total_deposits DESC;'),
('619f06df-d0c8-43cf-9d09-9034f6c204cc', 'Find customers who have no loans. Show customer_id...', 'Find customers who have no loans. Show customer_id, first_name, last_name.', 'banking', 'Medium', 15, 'SELECT c.customer_id, c.first_name, c.last_name FROM customers c LEFT JOIN loans l ON c.customer_id = l.customer_id WHERE l.loan_id IS NULL;'),
('ae75381c-8d34-46be-87e7-e7bd7c90da3b', 'Calculate total loan payments collected per loan. ...', 'Calculate total loan payments collected per loan. Show loan_id and total_collected.', 'banking', 'Medium', 15, 'SELECT loan_id, SUM(amount) AS total_collected FROM loan_payments GROUP BY loan_id ORDER BY total_collected DESC;'),
('1e2aa892-70f2-4103-8c97-9c9f4c643a77', 'Show the highest-paid employee per branch. Show br...', 'Show the highest-paid employee per branch. Show branch name, employee name, and salary.', 'banking', 'Medium', 15, 'SELECT b.name AS branch_name, e.first_name || '' '' || e.last_name AS employee_name, e.salary FROM employees e JOIN branches b ON e.branch_id = b.branch_id WHERE e.salary = (SELECT MAX(e2.salary) FROM employees e2 WHERE e2.branch_id = e.branch_id) ORDER BY e.salary DESC;'),
('7f1d8a48-5692-41df-a218-72c86c37480c', 'Calculate each loan''s total monthly payment and mo...', 'Calculate each loan''s total monthly payment and months remaining. Show loan_id, monthly_payment (principal / term_months rounded to 2), term_months, and payments_made.', 'banking', 'Medium', 15, 'SELECT l.loan_id, ROUND(l.principal / l.term_months, 2) AS monthly_payment, l.term_months, COUNT(lp.payment_id) AS payments_made, l.term_months - COUNT(lp.payment_id) AS remaining_payments FROM loans l LEFT JOIN loan_payments lp ON l.loan_id = lp.loan_id GROUP BY l.loan_id ORDER BY remaining_payments DESC;'),
('a4c64c75-8b98-49c0-be88-1c942bfc9d9d', 'Show the average transaction amount per account ty...', 'Show the average transaction amount per account type. Show type and avg_transaction.', 'banking', 'Medium', 15, 'SELECT a.type, ROUND(AVG(t.amount), 2) AS avg_transaction FROM accounts a JOIN transactions t ON a.account_id = t.account_id GROUP BY a.type ORDER BY avg_transaction DESC;'),
('6b5215c9-aa96-4817-915c-d2dad761bd51', 'List employees and their manager''s name. Show empl...', 'List employees and their manager''s name. Show employee name and manager name (NULL for top-level).', 'banking', 'Medium', 15, 'SELECT e.first_name || '' '' || e.last_name AS employee_name, COALESCE(m.first_name || '' '' || m.last_name, ''No Manager'') AS manager_name FROM employees e LEFT JOIN employees m ON e.manager_id = m.employee_id ORDER BY manager_name, employee_name;'),
('3496c465-7e09-41ea-ab15-7589a112be3d', 'Find accounts where the balance is above the avera...', 'Find accounts where the balance is above the average balance for all accounts of the same type. Show account_id, type, balance.', 'banking', 'Medium', 15, 'SELECT account_id, type, balance FROM accounts a WHERE balance > (SELECT AVG(balance) FROM accounts a2 WHERE a2.type = a.type) ORDER BY type, balance DESC;'),
('4c6ced8f-64f9-4ded-9eb0-78cc352df6bb', 'Show the total number of late loan payments per lo...', 'Show the total number of late loan payments per loan. Show loan_id and late_payments.', 'banking', 'Medium', 15, 'SELECT loan_id, SUM(is_late) AS late_payments FROM loan_payments GROUP BY loan_id HAVING SUM(is_late) > 0 ORDER BY late_payments DESC;'),
('6d8626e8-e374-404c-8f08-60606d7c58cd', 'Show each customer''s most recent transaction date ...', 'Show each customer''s most recent transaction date and the amount. Show customer name, last_txn_date, last_amount.', 'banking', 'Medium', 15, 'SELECT c.first_name || '' '' || c.last_name AS customer_name, MAX(t.txn_date) AS last_txn_date FROM customers c JOIN accounts a ON c.customer_id = a.customer_id JOIN transactions t ON a.account_id = t.account_id GROUP BY c.customer_id ORDER BY last_txn_date DESC;'),
('b06b0e31-e064-4578-bd2f-a1b3de51a9ab', 'Rank customers by total account balance using DENS...', 'Rank customers by total account balance using DENSE_RANK. Show customer name, total_balance, and balance_rank.', 'banking', 'Hard', 25, 'SELECT customer_name, total_balance, DENSE_RANK() OVER (ORDER BY total_balance DESC) AS balance_rank FROM (SELECT c.first_name || '' '' || c.last_name AS customer_name, SUM(a.balance) AS total_balance FROM customers c JOIN accounts a ON c.customer_id = a.customer_id GROUP BY c.customer_id) ORDER BY balance_rank;'),
('bb9cc201-1235-41dc-901f-40ec28e8656c', 'For each account, show the running balance after e...', 'For each account, show the running balance after each transaction using a window SUM. Show account_id, txn_date, type, amount, and running_balance.', 'banking', 'Hard', 25, 'SELECT account_id, txn_date, type, amount, SUM(CASE WHEN type IN (''Deposit'',''Transfer'') THEN amount ELSE -amount END) OVER (PARTITION BY account_id ORDER BY txn_date ROWS UNBOUNDED PRECEDING) AS running_balance FROM transactions ORDER BY account_id, txn_date;'),
('9f93d423-a9ad-45ae-9c01-17805d5bedbb', 'Use a CTE to detect accounts with suspicious activ...', 'Use a CTE to detect accounts with suspicious activity: 3+ transactions in a single day. Show account_id, txn_date, and daily_txn_count.', 'banking', 'Hard', 25, 'WITH daily AS (SELECT account_id, DATE(txn_date) AS txn_day, COUNT(*) AS daily_txn_count FROM transactions GROUP BY account_id, DATE(txn_date)) SELECT account_id, txn_day AS txn_date, daily_txn_count FROM daily WHERE daily_txn_count >= 3 ORDER BY daily_txn_count DESC;'),
('a8a82d06-84a1-4379-ae18-707925c36358', 'For each branch, find the top 2 highest-balance ac...', 'For each branch, find the top 2 highest-balance accounts using ROW_NUMBER(). Show branch_name, account_id, balance, and rn for rn <= 2.', 'banking', 'Hard', 25, 'SELECT branch_name, account_id, balance FROM (SELECT b.name AS branch_name, a.account_id, a.balance, ROW_NUMBER() OVER (PARTITION BY a.branch_id ORDER BY a.balance DESC) AS rn FROM accounts a JOIN branches b ON a.branch_id = b.branch_id) WHERE rn <= 2 ORDER BY branch_name, balance DESC;'),
('d2e44f6c-1400-4c9c-a33a-29ec5d26df9f', 'Calculate month-over-month change in total deposit...', 'Calculate month-over-month change in total deposits. Show month, total_deposits, prev_month_deposits, and change.', 'banking', 'Hard', 25, 'WITH monthly AS (SELECT strftime(''%Y-%m'', txn_date) AS month, SUM(amount) AS total_deposits FROM transactions WHERE type = ''Deposit'' GROUP BY month) SELECT month, total_deposits, LAG(total_deposits) OVER (ORDER BY month) AS prev_month_deposits, total_deposits - LAG(total_deposits) OVER (ORDER BY month) AS change FROM monthly ORDER BY month;');
INSERT INTO public.questions (id, title, prompt, schema_name, difficulty, estimated_time_minutes, solution_sql) VALUES
('86848c1a-7f1b-4088-9b97-c622b782d184', 'Use a recursive CTE to build the management hierar...', 'Use a recursive CTE to build the management hierarchy of the bank. Show employee name, their manager name, and level in hierarchy.', 'banking', 'Hard', 25, 'WITH RECURSIVE hierarchy AS (SELECT employee_id, first_name || '' '' || last_name AS employee_name, manager_id, first_name || '' '' || last_name AS manager_name, 1 AS level FROM employees WHERE manager_id IS NULL UNION ALL SELECT e.employee_id, e.first_name || '' '' || e.last_name, e.manager_id, h.employee_name, h.level + 1 FROM employees e JOIN hierarchy h ON e.manager_id = h.employee_id) SELECT employee_name, manager_name, level FROM hierarchy ORDER BY level, employee_name;'),
('1f4a5bac-0649-4c84-98cb-ad04799f28a0', 'Calculate each account''s balance percentile using ...', 'Calculate each account''s balance percentile using PERCENT_RANK(). Show account_id, type, balance, and percentile (0-100 scale, rounded).', 'banking', 'Hard', 25, 'SELECT account_id, type, balance, ROUND(PERCENT_RANK() OVER (ORDER BY balance) * 100, 1) AS percentile FROM accounts ORDER BY percentile DESC;'),
('9092147d-4155-4867-9e3f-3640f0d81d32', 'Detect balance drops: for each account show the tr...', 'Detect balance drops: for each account show the transaction where the balance DECREASED the most (largest single withdrawal). Show account_id, txn_date, and withdrawal_amount.', 'banking', 'Hard', 25, 'SELECT account_id, txn_date, amount AS withdrawal_amount FROM transactions WHERE type = ''Withdrawal'' AND amount = (SELECT MAX(amount) FROM transactions t2 WHERE t2.account_id = transactions.account_id AND t2.type = ''Withdrawal'') ORDER BY withdrawal_amount DESC;'),
('20ce6be8-14c8-440c-8faf-c68e0cc10163', 'Calculate NTILE(4) quartiles for loan principal va...', 'Calculate NTILE(4) quartiles for loan principal values. Show loan_id, customer_id, principal, and quartile (1=largest quarter).', 'banking', 'Hard', 25, 'SELECT loan_id, customer_id, principal, NTILE(4) OVER (ORDER BY principal DESC) AS quartile FROM loans ORDER BY quartile, principal DESC;'),
('021fc157-19a4-4972-a156-0dff8024fb6b', 'For each loan, calculate the % of total payments r...', 'For each loan, calculate the % of total payments received vs total expected (principal). Show loan_id, total_paid, principal, and pct_repaid.', 'banking', 'Hard', 25, 'WITH paid AS (SELECT loan_id, SUM(amount) AS total_paid FROM loan_payments GROUP BY loan_id) SELECT l.loan_id, COALESCE(p.total_paid, 0) AS total_paid, l.principal, ROUND(100.0 * COALESCE(p.total_paid, 0) / l.principal, 1) AS pct_repaid FROM loans l LEFT JOIN paid p ON l.loan_id = p.loan_id ORDER BY pct_repaid DESC;'),
('e84a783d-9a3d-4456-a2fc-2dc6c863fb9a', 'Show forecasted transaction dates: for each transa...', 'Show forecasted transaction dates: for each transaction, find the NEXT transaction on the same account. Show account_id, txn_date, amount, and next_txn_date.', 'banking', 'Hard', 25, 'SELECT account_id, txn_date, amount, LEAD(txn_date) OVER (PARTITION BY account_id ORDER BY txn_date) AS next_txn_date FROM transactions ORDER BY account_id, txn_date;'),
('8dd5dda9-4ea7-498b-879a-655d15f58505', 'Build a branch-level KPI: for each branch show tot...', 'Build a branch-level KPI: for each branch show total_accounts, total_balance, total_loans, and rank branches by total_balance. Show branch_name, total_accounts, total_balance, total_loans, balance_rank.', 'banking', 'Hard', 25, 'WITH acc AS (SELECT branch_id, COUNT(*) AS total_accounts, SUM(balance) AS total_balance FROM accounts GROUP BY branch_id), lns AS (SELECT branch_id, SUM(principal) AS total_loans FROM loans GROUP BY branch_id) SELECT b.name AS branch_name, COALESCE(a.total_accounts, 0) AS total_accounts, COALESCE(a.total_balance, 0) AS total_balance, COALESCE(l.total_loans, 0) AS total_loans, RANK() OVER (ORDER BY COALESCE(a.total_balance, 0) DESC) AS balance_rank FROM branches b LEFT JOIN acc a ON b.branch_id = a.branch_id LEFT JOIN lns l ON b.branch_id = l.branch_id ORDER BY balance_rank;'),
('f3555e24-45e6-4213-8e6c-f0b9ca194f40', 'Identify customers at risk: those whose total with...', 'Identify customers at risk: those whose total withdrawals in 2024 exceed their current total savings balance. Show customer_id, total_withdrawals_2024, total_savings.', 'banking', 'Hard', 25, 'WITH w2024 AS (SELECT a.customer_id, SUM(t.amount) AS total_withdrawals FROM accounts a JOIN transactions t ON a.account_id = t.account_id WHERE t.type = ''Withdrawal'' AND strftime(''%Y'', t.txn_date) = ''2024'' GROUP BY a.customer_id), sav AS (SELECT customer_id, SUM(balance) AS total_savings FROM accounts WHERE type = ''Savings'' GROUP BY customer_id) SELECT w.customer_id, w.total_withdrawals AS total_withdrawals_2024, COALESCE(s.total_savings, 0) AS total_savings FROM w2024 w LEFT JOIN sav s ON w.customer_id = s.customer_id WHERE w.total_withdrawals > COALESCE(s.total_savings, 0) ORDER BY w.total_withdrawals DESC;'),
('5e657df8-c959-42a6-b54d-1ee564e8849c', 'Show each employee''s salary as a percentage of the...', 'Show each employee''s salary as a percentage of the total salary budget for their branch. Show employee_name, branch_name, salary, branch_total_salary, and salary_pct.', 'banking', 'Hard', 25, 'SELECT e.first_name || '' '' || e.last_name AS employee_name, b.name AS branch_name, e.salary, SUM(e.salary) OVER (PARTITION BY e.branch_id) AS branch_total_salary, ROUND(100.0 * e.salary / SUM(e.salary) OVER (PARTITION BY e.branch_id), 1) AS salary_pct FROM employees e JOIN branches b ON e.branch_id = b.branch_id ORDER BY branch_name, salary DESC;'),
('b58369a7-3962-4a75-ba81-54aabc500876', 'Calculate projected loan payoff date for each acti...', 'Calculate projected loan payoff date for each active loan based on current payment pace (principal / avg monthly payment × months). Show loan_id, principal, avg_monthly_payment, and projected_months_to_payoff.', 'banking', 'Hard', 25, 'WITH pay_avg AS (SELECT loan_id, AVG(amount) AS avg_monthly_payment FROM loan_payments GROUP BY loan_id) SELECT l.loan_id, l.principal, ROUND(p.avg_monthly_payment, 2) AS avg_monthly_payment, ROUND(l.principal / p.avg_monthly_payment, 0) AS projected_months_to_payoff FROM loans l JOIN pay_avg p ON l.loan_id = p.loan_id WHERE l.status = ''Active'' ORDER BY projected_months_to_payoff;'),
('018e212b-cc75-42ed-9612-04aca90662fd', 'Show a cohort analysis: group customers by year th...', 'Show a cohort analysis: group customers by year they opened their first account, show cohort_year, total_customers, avg_total_balance.', 'banking', 'Hard', 25, 'WITH first_acc AS (SELECT customer_id, strftime(''%Y'', MIN(opened_at)) AS cohort_year FROM accounts GROUP BY customer_id), bal AS (SELECT customer_id, SUM(balance) AS total_balance FROM accounts GROUP BY customer_id) SELECT fa.cohort_year, COUNT(*) AS total_customers, ROUND(AVG(b.total_balance), 2) AS avg_total_balance FROM first_acc fa JOIN bal b ON fa.customer_id = b.customer_id GROUP BY fa.cohort_year ORDER BY fa.cohort_year;'),
('5a5c3602-41b4-4618-a557-6b06123ef0fc', 'Calculate the days between consecutive transaction...', 'Calculate the days between consecutive transactions per account using LEAD. Show account_id, txn_date, next_txn_date, and days_between.', 'banking', 'Hard', 25, 'SELECT account_id, txn_date, LEAD(txn_date) OVER (PARTITION BY account_id ORDER BY txn_date) AS next_txn_date, CAST(julianday(LEAD(txn_date) OVER (PARTITION BY account_id ORDER BY txn_date)) - julianday(txn_date) AS INTEGER) AS days_between FROM transactions ORDER BY account_id, txn_date;'),
('128a9d35-1466-4250-9097-4208eb0853ec', 'Identify the single most profitable month for the ...', 'Identify the single most profitable month for the bank (highest net: deposits - withdrawals). Show month and net_flow.', 'banking', 'Hard', 25, 'WITH monthly AS (SELECT strftime(''%Y-%m'', txn_date) AS month, SUM(CASE WHEN type=''Deposit'' THEN amount ELSE 0 END) - SUM(CASE WHEN type=''Withdrawal'' THEN amount ELSE 0 END) AS net_flow FROM transactions GROUP BY month) SELECT month, net_flow FROM monthly ORDER BY net_flow DESC LIMIT 1;'),
('7fde8f50-f724-4915-bb1c-07b641e91a16', 'Create a full customer scorecard: show customer na...', 'Create a full customer scorecard: show customer name, total_accounts, total_balance, total_loans, total_txns, and a composite health score = total_balance - (0.5 × total_loans). Rank by health_score DESC.', 'banking', 'Hard', 25, 'WITH bal AS (SELECT customer_id, COUNT(*) AS total_accounts, SUM(balance) AS total_balance FROM accounts GROUP BY customer_id), lns AS (SELECT customer_id, SUM(principal) AS total_loans FROM loans GROUP BY customer_id), txns AS (SELECT a.customer_id, COUNT(t.txn_id) AS total_txns FROM accounts a LEFT JOIN transactions t ON a.account_id = t.account_id GROUP BY a.customer_id) SELECT c.first_name || '' '' || c.last_name AS customer_name, COALESCE(b.total_accounts, 0) AS total_accounts, COALESCE(b.total_balance, 0) AS total_balance, COALESCE(l.total_loans, 0) AS total_loans, COALESCE(tx.total_txns, 0) AS total_txns, ROUND(COALESCE(b.total_balance, 0) - 0.5 * COALESCE(l.total_loans, 0), 2) AS health_score FROM customers c LEFT JOIN bal b ON c.customer_id = b.customer_id LEFT JOIN lns l ON c.customer_id = l.customer_id LEFT JOIN txns tx ON c.customer_id = tx.customer_id ORDER BY health_score DESC;'),
('c9685f64-2025-4f62-b4a4-b02c6fa63da9', 'Show a running count of active accounts opened eac...', 'Show a running count of active accounts opened each year, using a cumulative SUM window. Show year, new_accounts, and cumulative_accounts.', 'banking', 'Hard', 25, 'WITH yearly AS (SELECT strftime(''%Y'', opened_at) AS year, COUNT(*) AS new_accounts FROM accounts WHERE is_active = 1 GROUP BY year) SELECT year, new_accounts, SUM(new_accounts) OVER (ORDER BY year ROWS UNBOUNDED PRECEDING) AS cumulative_accounts FROM yearly ORDER BY year;'),
('1c491327-080f-4e9e-896a-becbe62743c8', 'Find accounts where the most recent transaction wa...', 'Find accounts where the most recent transaction was a Withdrawal over $5000 (potential large outflow alert). Show account_id, last_txn_date, last_txn_type, last_amount.', 'banking', 'Hard', 25, 'SELECT account_id, txn_date AS last_txn_date, type AS last_txn_type, amount AS last_amount FROM (SELECT account_id, txn_date, type, amount, ROW_NUMBER() OVER (PARTITION BY account_id ORDER BY txn_date DESC) AS rn FROM transactions) WHERE rn = 1 AND type = ''Withdrawal'' AND amount > 5000 ORDER BY last_amount DESC;'),
('423eef85-c0c8-4f5f-a92b-2872fd0d1ca7', 'Compute the loan default rate per branch (defaulte...', 'Compute the loan default rate per branch (defaulted loans / total loans). Show branch_name and default_rate_pct.', 'banking', 'Hard', 25, 'SELECT b.name AS branch_name, ROUND(100.0 * SUM(CASE WHEN l.status = ''Defaulted'' THEN 1 ELSE 0 END) / COUNT(l.loan_id), 1) AS default_rate_pct FROM branches b LEFT JOIN loans l ON b.branch_id = l.branch_id GROUP BY b.branch_id ORDER BY default_rate_pct DESC;'),
('74e6f947-b387-4fcc-9f41-a5915a36b382', 'Rank loans by effective annual cost (interest_rate...', 'Rank loans by effective annual cost (interest_rate, higher = worse for customer). Show loan_id, customer_id, interest_rate, term_months, and cost_rank.', 'banking', 'Hard', 25, 'SELECT loan_id, customer_id, interest_rate, term_months, RANK() OVER (ORDER BY interest_rate DESC) AS cost_rank FROM loans ORDER BY cost_rank;'),
('0e747b89-6f78-45a1-b068-c95c7b52e73b', 'For each account, find the highest single withdraw...', 'For each account, find the highest single withdrawal ever made and compare it to the account''s current balance. Show account_id, type, current_balance, max_withdrawal, and risk_ratio (max_withdrawal/balance).', 'banking', 'Hard', 25, 'WITH maxw AS (SELECT account_id, MAX(CASE WHEN type=''Withdrawal'' THEN amount ELSE 0 END) AS max_withdrawal FROM transactions GROUP BY account_id) SELECT a.account_id, a.type, a.balance AS current_balance, COALESCE(m.max_withdrawal, 0) AS max_withdrawal, ROUND(COALESCE(m.max_withdrawal, 0) / NULLIF(a.balance, 0), 2) AS risk_ratio FROM accounts a LEFT JOIN maxw m ON a.account_id = m.account_id WHERE a.balance > 0 ORDER BY risk_ratio DESC;'),
('ae6a53eb-2860-41c3-ba0a-15753e27e9a1', 'Build a complete 360° customer wealth report: for ...', 'Build a complete 360° customer wealth report: for each customer show total_assets (balance), total_liabilities (loans), net_worth, and wealth_rank using RANK().', 'banking', 'Hard', 25, 'WITH assets AS (SELECT customer_id, SUM(balance) AS total_assets FROM accounts GROUP BY customer_id), liab AS (SELECT customer_id, SUM(principal) AS total_liabilities FROM loans GROUP BY customer_id) SELECT c.first_name || '' '' || c.last_name AS customer_name, COALESCE(a.total_assets, 0) AS total_assets, COALESCE(l.total_liabilities, 0) AS total_liabilities, COALESCE(a.total_assets, 0) - COALESCE(l.total_liabilities, 0) AS net_worth, RANK() OVER (ORDER BY COALESCE(a.total_assets, 0) - COALESCE(l.total_liabilities, 0) DESC) AS wealth_rank FROM customers c LEFT JOIN assets a ON c.customer_id = a.customer_id LEFT JOIN liab l ON c.customer_id = l.customer_id ORDER BY wealth_rank;'),
('7482c1b5-bf5e-4bf5-abdf-26406749181e', 'List all products with their name and price, order...', 'List all products with their name and price, ordered by price descending.', 'ecommerce', 'Easy', 5, 'SELECT name, price FROM products ORDER BY price DESC;'),
('ed730dfb-c151-4807-95dc-276abf08808d', 'Find all products in the ''Electronics'' category (c...', 'Find all products in the ''Electronics'' category (category_id = 1). Show name and price.', 'ecommerce', 'Easy', 5, 'SELECT name, price FROM products WHERE category_id = 1;'),
('6942a929-79c1-469e-9dbe-b464888df323', 'Show all customers from Canada. Return first_name,...', 'Show all customers from Canada. Return first_name, last_name, city.', 'ecommerce', 'Easy', 5, 'SELECT first_name, last_name, city FROM customers WHERE country = ''Canada'';'),
('1c5863fd-238d-40c8-ae99-511155c36517', 'List all orders placed in January 2024. Show order...', 'List all orders placed in January 2024. Show order_id, customer_id, order_date, status.', 'ecommerce', 'Easy', 5, 'SELECT order_id, customer_id, order_date, status FROM orders WHERE order_date BETWEEN ''2024-01-01'' AND ''2024-01-31'';'),
('49c63dfa-da94-43d6-a23e-34a7e9d33bde', 'Find all products priced under $50. Show name and ...', 'Find all products priced under $50. Show name and price, ordered by price ascending.', 'ecommerce', 'Easy', 5, 'SELECT name, price FROM products WHERE price < 50 ORDER BY price ASC;'),
('42ea8069-4928-415a-b137-83c04e7c7b94', 'Count the total number of orders in the database. ...', 'Count the total number of orders in the database. Return a single value labeled total_orders.', 'ecommerce', 'Easy', 5, 'SELECT COUNT(*) AS total_orders FROM orders;'),
('7d724848-7a26-41e3-91a0-ad13617003eb', 'Show the most expensive product. Return name and p...', 'Show the most expensive product. Return name and price.', 'ecommerce', 'Easy', 5, 'SELECT name, price FROM products ORDER BY price DESC LIMIT 1;'),
('c71feb3d-a1ff-48c8-aaf9-bf9f8ea850a9', 'List customers whose email contains ''gmail''. Show ...', 'List customers whose email contains ''gmail''. Show first_name, last_name, and email.', 'ecommerce', 'Easy', 5, 'SELECT first_name, last_name, email FROM customers WHERE email LIKE ''%gmail%'';'),
('185bab48-4deb-49e2-9c46-f731b4906a56', 'Find all orders with status ''Cancelled''. Show orde...', 'Find all orders with status ''Cancelled''. Show order_id, customer_id, order_date.', 'ecommerce', 'Easy', 5, 'SELECT order_id, customer_id, order_date FROM orders WHERE status = ''Cancelled'';'),
('91e2aee0-b371-4f21-a6fd-77583db53743', 'Show all distinct product categories. Return categ...', 'Show all distinct product categories. Return category_id and name, ordered by name.', 'ecommerce', 'Easy', 5, 'SELECT category_id, name FROM categories ORDER BY name;'),
('bcf18f2d-083e-4c85-b92d-b0a3a564e385', 'List all products ordered by price descending. Sho...', 'List all products ordered by price descending. Show product_id, name, price.', 'ecommerce', 'Easy', 5, 'SELECT product_id, name, price FROM products ORDER BY price DESC;'),
('6664640f-d2e7-40d0-b563-ebe8f2ee261d', 'Find all customers who registered in 2023. Show fi...', 'Find all customers who registered in 2023. Show first_name, last_name, registered_at.', 'ecommerce', 'Easy', 5, 'SELECT first_name, last_name, registered_at FROM customers WHERE strftime(''%Y'', registered_at) = ''2023'';'),
('e32da4d9-eede-456c-8507-773a51eb54bd', 'Show all orders for customer_id = 1. Display order...', 'Show all orders for customer_id = 1. Display order_id, order_date, status.', 'ecommerce', 'Easy', 5, 'SELECT order_id, order_date, status FROM orders WHERE customer_id = 1;'),
('d50088f2-b3d2-431e-9153-cd730ad6117f', 'Count how many products are in each category. Show...', 'Count how many products are in each category. Show category_id and product_count, ordered by count DESC.', 'ecommerce', 'Easy', 5, 'SELECT category_id, COUNT(*) AS product_count FROM products GROUP BY category_id ORDER BY product_count DESC;'),
('e83cfca3-cb38-42dc-b9a8-9abf01296cef', 'Find products with a NULL description. Show produc...', 'Find products with a NULL description. Show product_id and name.', 'ecommerce', 'Easy', 5, 'SELECT product_id, name FROM products WHERE description IS NULL;'),
('48ee089e-0bb5-4a2c-9cee-b0650289e21e', 'List all orders sorted by total revenue (sum of or...', 'List all orders sorted by total revenue (sum of order_items unit_price * quantity) descending. Show order_id and total_amount. Top 10.', 'ecommerce', 'Easy', 5, 'SELECT order_id, SUM(quantity * unit_price) AS total_amount FROM order_items GROUP BY order_id ORDER BY total_amount DESC LIMIT 10;'),
('8aa9c013-d0b9-4996-8f56-f67a98d634a9', 'Show all products with more than 100 units in stoc...', 'Show all products with more than 100 units in stock. Show name and stock_qty.', 'ecommerce', 'Easy', 5, 'SELECT name, stock_qty FROM products WHERE stock_qty > 100 ORDER BY stock_qty DESC;'),
('f2b5eab1-9366-4252-9342-93879c99a7b5', 'Find the cheapest product in each category. Show c...', 'Find the cheapest product in each category. Show category_id, name, and price.', 'ecommerce', 'Easy', 5, 'SELECT category_id, name, price FROM products p WHERE price = (SELECT MIN(price) FROM products p2 WHERE p2.category_id = p.category_id) ORDER BY category_id;'),
('8ee1dcee-dad3-4eab-b599-ff8e7e8bfe3d', 'List customers with no phone number on file (phone...', 'List customers with no phone number on file (phone IS NULL). Show customer_id, first_name, last_name.', 'ecommerce', 'Easy', 5, 'SELECT customer_id, first_name, last_name FROM customers WHERE phone IS NULL;'),
('99c517dc-9855-4303-ba98-467dfb28f239', 'Show all payments made via ''Credit Card''. Show pay...', 'Show all payments made via ''Credit Card''. Show payment_id, order_id, amount, paid_at.', 'ecommerce', 'Easy', 5, 'SELECT payment_id, order_id, amount, paid_at FROM payments WHERE method = ''Credit Card'';'),
('e6909684-8cc0-4286-bc54-e4916f27613a', 'List each order with customer full name and total ...', 'List each order with customer full name and total order amount (sum of items). Show order_id, customer_name, total_amount. Order by total_amount DESC.', 'ecommerce', 'Medium', 15, 'SELECT o.order_id, c.first_name || '' '' || c.last_name AS customer_name, SUM(oi.quantity * oi.unit_price) AS total_amount FROM orders o JOIN customers c ON o.customer_id = c.customer_id JOIN order_items oi ON o.order_id = oi.order_id GROUP BY o.order_id ORDER BY total_amount DESC;'),
('97e00bb6-85ab-424f-a79c-1fcecec4cee9', 'Calculate total revenue per category. Join order_i...', 'Calculate total revenue per category. Join order_items → products → categories. Show category name and total_revenue. Order by revenue DESC.', 'ecommerce', 'Medium', 15, 'SELECT cat.name AS category_name, SUM(oi.quantity * oi.unit_price) AS total_revenue FROM order_items oi JOIN products p ON oi.product_id = p.product_id JOIN categories cat ON p.category_id = cat.category_id GROUP BY cat.category_id, cat.name ORDER BY total_revenue DESC;'),
('3ee69827-4a02-4599-9d44-54dc5a43c0f7', 'Find customers who have placed more than 1 order. ...', 'Find customers who have placed more than 1 order. Show customer_id, first_name, last_name, order_count.', 'ecommerce', 'Medium', 15, 'SELECT c.customer_id, c.first_name, c.last_name, COUNT(o.order_id) AS order_count FROM customers c JOIN orders o ON c.customer_id = o.customer_id GROUP BY c.customer_id HAVING COUNT(o.order_id) > 1 ORDER BY order_count DESC;'),
('924b068b-e5a6-4e25-99e3-08032c3800c1', 'Show the top 5 best-selling products by total quan...', 'Show the top 5 best-selling products by total quantity sold. Show product name and total_quantity.', 'ecommerce', 'Medium', 15, 'SELECT p.name, SUM(oi.quantity) AS total_quantity FROM order_items oi JOIN products p ON oi.product_id = p.product_id GROUP BY p.product_id, p.name ORDER BY total_quantity DESC LIMIT 5;'),
('7848cf3a-b327-464c-b04e-b86f48bbdd9d', 'Find products that have never been ordered. Show p...', 'Find products that have never been ordered. Show product_id and name.', 'ecommerce', 'Medium', 15, 'SELECT p.product_id, p.name FROM products p LEFT JOIN order_items oi ON p.product_id = oi.product_id WHERE oi.item_id IS NULL;'),
('16c206cf-0812-4a1d-88b5-aa572c38c53f', 'Calculate a running revenue total by order_date us...', 'Calculate a running revenue total by order_date using SUM() OVER (ORDER BY order_date). Show order_date, daily_revenue, and running_total.', 'ecommerce', 'Hard', 25, 'SELECT order_date, daily_revenue, SUM(daily_revenue) OVER (ORDER BY order_date ROWS UNBOUNDED PRECEDING) AS running_total FROM (SELECT o.order_date, SUM(oi.quantity * oi.unit_price) AS daily_revenue FROM orders o JOIN order_items oi ON o.order_id = oi.order_id GROUP BY o.order_date) ORDER BY order_date;'),
('4c3b508e-0755-459f-9dd9-5b9f567cfc0b', 'Rank products within each category by total revenu...', 'Rank products within each category by total revenue (quantity * unit_price) using DENSE_RANK. Show category_name, product_name, total_revenue, and rank.', 'ecommerce', 'Hard', 25, 'SELECT cat.name AS category_name, p.name AS product_name, SUM(oi.quantity * oi.unit_price) AS total_revenue, DENSE_RANK() OVER (PARTITION BY cat.category_id ORDER BY SUM(oi.quantity * oi.unit_price) DESC) AS revenue_rank FROM order_items oi JOIN products p ON oi.product_id = p.product_id JOIN categories cat ON p.category_id = cat.category_id GROUP BY cat.category_id, p.product_id ORDER BY category_name, revenue_rank;'),
('4f934e27-9b37-469d-a7bb-4c8a20e925d2', 'Find the top 3 customers per country by total life...', 'Find the top 3 customers per country by total lifetime spend using ROW_NUMBER(). Show country, customer_name, total_spend, and row_num for rows <= 3.', 'ecommerce', 'Hard', 25, 'WITH spend AS (SELECT c.customer_id, c.first_name || '' '' || c.last_name AS customer_name, c.country, SUM(oi.quantity * oi.unit_price) AS total_spend FROM customers c JOIN orders o ON c.customer_id = o.customer_id JOIN order_items oi ON o.order_id = oi.order_id GROUP BY c.customer_id) SELECT country, customer_name, total_spend, ROW_NUMBER() OVER (PARTITION BY country ORDER BY total_spend DESC) AS rn FROM spend WHERE rn <= 3 ORDER BY country, rn;'),
('256c30ce-a891-459b-9d20-30bb4f6e0746', 'Use a recursive CTE to traverse the category hiera...', 'Use a recursive CTE to traverse the category hierarchy (parent → child → grandchild). Show category_name, parent_name, and level.', 'ecommerce', 'Hard', 25, 'WITH RECURSIVE cat_tree AS (SELECT category_id, name, parent_category_id, name AS parent_name, 1 AS level FROM categories WHERE parent_category_id IS NULL UNION ALL SELECT c.category_id, c.name, c.parent_category_id, ct.name AS parent_name, ct.level + 1 FROM categories c JOIN cat_tree ct ON c.parent_category_id = ct.category_id) SELECT name AS category_name, parent_name, level FROM cat_tree ORDER BY level, category_name;'),
('e3f37557-c87a-4c98-890e-7c8dc83a307f', 'Calculate RFM scoring: rank each customer by Recen...', 'Calculate RFM scoring: rank each customer by Recency (days since last order), Frequency (order count), and Monetary (total spend). Show customer_name, days_since_last_order, order_count, total_spend.', 'ecommerce', 'Hard', 25, 'WITH rfm AS (SELECT c.customer_id, c.first_name || '' '' || c.last_name AS customer_name, CAST(julianday(''2024-08-01'') - julianday(MAX(o.order_date)) AS INTEGER) AS days_since_last_order, COUNT(DISTINCT o.order_id) AS order_count, ROUND(SUM(oi.quantity * oi.unit_price), 2) AS total_spend FROM customers c JOIN orders o ON c.customer_id = o.customer_id JOIN order_items oi ON o.order_id = oi.order_id GROUP BY c.customer_id) SELECT customer_name, days_since_last_order, order_count, total_spend FROM rfm ORDER BY total_spend DESC;'),
('6b043a19-1670-41f6-ba51-fb32e0274265', 'E-Commerce Practice Question 1: Write a query to e...', 'E-Commerce Practice Question 1: Write a query to explore the e-commerce dataset.', 'ecommerce', 'Medium', 15, 'SELECT * FROM orders LIMIT 10;'),
('e98cad05-3e48-47c2-82e7-c1fadbff6aac', 'E-Commerce Practice Question 2: Write a query to e...', 'E-Commerce Practice Question 2: Write a query to explore the e-commerce dataset.', 'ecommerce', 'Medium', 15, 'SELECT * FROM orders LIMIT 10;'),
('320f30b8-2f22-4dc0-932e-56d042ce9370', 'E-Commerce Practice Question 3: Write a query to e...', 'E-Commerce Practice Question 3: Write a query to explore the e-commerce dataset.', 'ecommerce', 'Medium', 15, 'SELECT * FROM orders LIMIT 10;'),
('81ee15c4-d03c-483d-be47-d2d967e1e0af', 'E-Commerce Practice Question 4: Write a query to e...', 'E-Commerce Practice Question 4: Write a query to explore the e-commerce dataset.', 'ecommerce', 'Medium', 15, 'SELECT * FROM orders LIMIT 10;'),
('cbc5881d-1580-45e2-ab74-b889f899a7b3', 'E-Commerce Practice Question 5: Write a query to e...', 'E-Commerce Practice Question 5: Write a query to explore the e-commerce dataset.', 'ecommerce', 'Medium', 15, 'SELECT * FROM orders LIMIT 10;'),
('cf654ec9-1814-495e-90ab-664c359e97ca', 'E-Commerce Practice Question 6: Write a query to e...', 'E-Commerce Practice Question 6: Write a query to explore the e-commerce dataset.', 'ecommerce', 'Medium', 15, 'SELECT * FROM orders LIMIT 10;'),
('971969ee-a521-4258-869b-0e30a9ab7afd', 'E-Commerce Practice Question 7: Write a query to e...', 'E-Commerce Practice Question 7: Write a query to explore the e-commerce dataset.', 'ecommerce', 'Medium', 15, 'SELECT * FROM orders LIMIT 10;'),
