('8c9539b3-76d5-4ed6-9c92-e6ff418e12a0', 'E-Commerce Practice Question 9: Write a query to e...', 'E-Commerce Practice Question 9: Write a query to explore the e-commerce dataset.', 'ecommerce', 'Medium', 15, 'SELECT * FROM orders LIMIT 10;'),
('2e4b6398-73b7-40b5-880e-463cb2a26e52', 'E-Commerce Practice Question 10: Write a query to ...', 'E-Commerce Practice Question 10: Write a query to explore the e-commerce dataset.', 'ecommerce', 'Medium', 15, 'SELECT * FROM orders LIMIT 10;'),
('57869155-6555-441c-8c2f-4576be4e3848', 'E-Commerce Practice Question 11: Write a query to ...', 'E-Commerce Practice Question 11: Write a query to explore the e-commerce dataset.', 'ecommerce', 'Medium', 15, 'SELECT * FROM orders LIMIT 10;'),
('0464e686-637b-4eed-8502-3dd6c96f6d6c', 'E-Commerce Practice Question 12: Write a query to ...', 'E-Commerce Practice Question 12: Write a query to explore the e-commerce dataset.', 'ecommerce', 'Medium', 15, 'SELECT * FROM orders LIMIT 10;'),
('03dd7a53-ce24-44ac-9198-6e66b10395f1', 'E-Commerce Practice Question 13: Write a query to ...', 'E-Commerce Practice Question 13: Write a query to explore the e-commerce dataset.', 'ecommerce', 'Medium', 15, 'SELECT * FROM orders LIMIT 10;'),
('75530a04-fcdf-4bd2-86d7-23e06e0e97d7', 'E-Commerce Practice Question 14: Write a query to ...', 'E-Commerce Practice Question 14: Write a query to explore the e-commerce dataset.', 'ecommerce', 'Medium', 15, 'SELECT * FROM orders LIMIT 10;'),
('7e242a8f-d344-4103-8298-9cefce88eff0', 'E-Commerce Practice Question 15: Write a query to ...', 'E-Commerce Practice Question 15: Write a query to explore the e-commerce dataset.', 'ecommerce', 'Medium', 15, 'SELECT * FROM orders LIMIT 10;'),
