('a3f430b3-f542-4251-b9a3-88d37955db53', 'List all patients showing their first_name, last_n...', 'List all patients showing their first_name, last_name, and gender.', 'hospital', 'Easy', 5, 'SELECT first_name, last_name, gender FROM patients;'),
('98c4464c-4549-4841-98bd-3c90625be292', 'Find all patients who are male (gender = ''M''). Sho...', 'Find all patients who are male (gender = ''M''). Show patient_id, first_name, and last_name.', 'hospital', 'Easy', 5, 'SELECT patient_id, first_name, last_name FROM patients WHERE gender = ''M'';'),
('39c9adc2-e4bc-4ca7-a463-5197049de04f', 'List all patients who are allergic to ''Penicillin''...', 'List all patients who are allergic to ''Penicillin''. Show first_name, last_name, and allergies.', 'hospital', 'Easy', 5, 'SELECT first_name, last_name, allergies FROM patients WHERE allergies = ''Penicillin'';'),
('8e58ab66-2df9-420b-bb82-060505296b8f', 'Show all patients born after 1990-01-01, ordered b...', 'Show all patients born after 1990-01-01, ordered by birth_date ascending. Show first_name, last_name, birth_date.', 'hospital', 'Easy', 5, 'SELECT first_name, last_name, birth_date FROM patients WHERE birth_date > ''1990-01-01'' ORDER BY birth_date ASC;'),
('0628c576-ea47-49d5-aeb9-a3449a406a3f', 'Find all patients whose first_name starts with the...', 'Find all patients whose first_name starts with the letter ''J''. Show first_name and last_name.', 'hospital', 'Easy', 5, 'SELECT first_name, last_name FROM patients WHERE first_name LIKE ''J%'';'),
('8107340c-08b5-4d75-824a-1f34ed0f8cb3', 'List patients with a weight between 70 and 90 kg (...', 'List patients with a weight between 70 and 90 kg (inclusive). Show first_name, last_name, and weight.', 'hospital', 'Easy', 5, 'SELECT first_name, last_name, weight FROM patients WHERE weight BETWEEN 70 AND 90;'),
('7a8078f3-e99a-465f-82a4-11a5255c903b', 'Count the total number of patients in the database...', 'Count the total number of patients in the database. Return a single number labeled total_patients.', 'hospital', 'Easy', 5, 'SELECT COUNT(*) AS total_patients FROM patients;'),
('fe83f559-8f52-4944-b694-9a36276b90c3', 'Show all distinct cities that patients come from. ...', 'Show all distinct cities that patients come from. Order alphabetically.', 'hospital', 'Easy', 5, 'SELECT DISTINCT city FROM patients ORDER BY city;'),
('d9add6e6-2f4d-4682-af7c-eb84ca87d50b', 'Find patients with no known allergies (allergies I...', 'Find patients with no known allergies (allergies IS NULL). Show patient_id, first_name, and last_name.', 'hospital', 'Easy', 5, 'SELECT patient_id, first_name, last_name FROM patients WHERE allergies IS NULL;'),
('f1902ea5-b060-4a91-a94e-7f780a7e7ae2', 'List the top 10 heaviest patients. Show first_name...', 'List the top 10 heaviest patients. Show first_name, last_name, and weight, ordered by weight descending.', 'hospital', 'Easy', 5, 'SELECT first_name, last_name, weight FROM patients ORDER BY weight DESC LIMIT 10;'),
('30d4eae0-22f9-4571-9561-634e672f98b9', 'Show all doctors with their first_name, last_name,...', 'Show all doctors with their first_name, last_name, and specialty.', 'hospital', 'Easy', 5, 'SELECT first_name, last_name, specialty FROM doctors;'),
('76c27ba3-6d9c-4f0c-8553-ba6609b22d06', 'List all departments with department_id and depart...', 'List all departments with department_id and department_name.', 'hospital', 'Easy', 5, 'SELECT department_id, department_name FROM departments;'),
('bab15d30-2f01-48d2-9a9a-3c1d49980e8d', 'Find all patients admitted in the year 2023. Show ...', 'Find all patients admitted in the year 2023. Show admission_id, patient_id, admission_date, and diagnosis.', 'hospital', 'Easy', 5, 'SELECT admission_id, patient_id, admission_date, diagnosis FROM admissions WHERE strftime(''%Y'', admission_date) = ''2023'';'),
('58de6cc2-b3bc-497a-91e7-5f70d15f0cb4', 'Show all province names with their province_id and...', 'Show all province names with their province_id and country.', 'hospital', 'Easy', 5, 'SELECT province_id, province_name, country FROM province_names;'),
('faae31d2-831c-4b0f-b3fc-2e692ec5cd56', 'Count how many patients are from each province. Sh...', 'Count how many patients are from each province. Show province_id and patient_count, ordered by patient_count descending.', 'hospital', 'Easy', 5, 'SELECT province_id, COUNT(*) AS patient_count FROM patients GROUP BY province_id ORDER BY patient_count DESC;'),
('ec1e5dde-408f-4738-8767-16fd4024a643', 'List all admissions ordered by admission_date desc...', 'List all admissions ordered by admission_date descending. Show admission_id, patient_id, admission_date, and diagnosis.', 'hospital', 'Easy', 5, 'SELECT admission_id, patient_id, admission_date, diagnosis FROM admissions ORDER BY admission_date DESC;'),
('038f4804-c0c9-4032-b727-0acb21f207d6', 'Find patients whose last_name ends with ''son''. Sho...', 'Find patients whose last_name ends with ''son''. Show first_name, last_name.', 'hospital', 'Easy', 5, 'SELECT first_name, last_name FROM patients WHERE last_name LIKE ''%son'';'),
('3fe19fcd-7107-4da2-ad12-88a0c5ca0340', 'Show all patients taller than 180 cm. Show first_n...', 'Show all patients taller than 180 cm. Show first_name, last_name, and height, ordered by height descending.', 'hospital', 'Easy', 5, 'SELECT first_name, last_name, height FROM patients WHERE height > 180 ORDER BY height DESC;'),
('93f34133-9b8e-4727-ab48-5de4de9ade4c', 'List all doctors whose first_name is ''John''. Show ...', 'List all doctors whose first_name is ''John''. Show doctor_id, first_name, last_name, and specialty.', 'hospital', 'Easy', 5, 'SELECT doctor_id, first_name, last_name, specialty FROM doctors WHERE first_name = ''John'';'),
('9e2cfac1-9b2f-46ef-bf0c-d904f970f322', 'Find all admissions with a diagnosis of ''Diabetes''...', 'Find all admissions with a diagnosis of ''Diabetes''. Show admission_id, patient_id, admission_date, and diagnosis.', 'hospital', 'Easy', 5, 'SELECT admission_id, patient_id, admission_date, diagnosis FROM admissions WHERE diagnosis = ''Diabetes'';');
INSERT INTO public.questions (id, title, prompt, schema_name, difficulty, estimated_time_minutes, solution_sql) VALUES
('7ca65e45-5619-4ddc-92eb-e6d2a4517cbb', 'List each patient with their most recent admission...', 'List each patient with their most recent admission date. Show patient_id, first_name, last_name, and last_admission_date. Order by last_admission_date DESC.', 'hospital', 'Medium', 15, 'SELECT p.patient_id, p.first_name, p.last_name, MAX(a.admission_date) AS last_admission_date FROM patients p JOIN admissions a ON p.patient_id = a.patient_id GROUP BY p.patient_id, p.first_name, p.last_name ORDER BY last_admission_date DESC;'),
('70e7150e-9fa8-49cf-9c4f-93b0cc52eff4', 'Find patients who have been admitted more than onc...', 'Find patients who have been admitted more than once. Show patient_id, first_name, last_name, and admission_count. Order by admission_count DESC.', 'hospital', 'Medium', 15, 'SELECT p.patient_id, p.first_name, p.last_name, COUNT(a.admission_id) AS admission_count FROM patients p JOIN admissions a ON p.patient_id = a.patient_id GROUP BY p.patient_id, p.first_name, p.last_name HAVING COUNT(a.admission_id) > 1 ORDER BY admission_count DESC;'),
('6cd71fc7-e880-412f-8120-bf43c374f06d', 'Find the doctor who handled the most admissions. S...', 'Find the doctor who handled the most admissions. Show doctor_id, first_name, last_name, and admission_count.', 'hospital', 'Medium', 15, 'SELECT d.doctor_id, d.first_name, d.last_name, COUNT(a.admission_id) AS admission_count FROM doctors d JOIN admissions a ON d.doctor_id = a.attending_doctor_id GROUP BY d.doctor_id, d.first_name, d.last_name ORDER BY admission_count DESC LIMIT 1;'),
('3b3b24f5-4ed0-41dd-bb58-25511f51a003', 'List all admissions with patient full name and att...', 'List all admissions with patient full name and attending doctor full name. Show admission_id, patient_name, doctor_name, and diagnosis.', 'hospital', 'Medium', 15, 'SELECT a.admission_id, p.first_name || '' '' || p.last_name AS patient_name, d.first_name || '' '' || d.last_name AS doctor_name, a.diagnosis FROM admissions a JOIN patients p ON a.patient_id = p.patient_id JOIN doctors d ON a.attending_doctor_id = d.doctor_id;'),
('f5fa284a-5dae-4856-a1eb-cafe757f415c', 'Show departments that have more than 3 doctors. Di...', 'Show departments that have more than 3 doctors. Display department_name and doctor_count.', 'hospital', 'Medium', 15, 'SELECT dep.department_name, COUNT(d.doctor_id) AS doctor_count FROM departments dep JOIN doctors d ON dep.department_id = d.department_id GROUP BY dep.department_name HAVING COUNT(d.doctor_id) > 3;'),
('359f131f-956f-440f-8e08-e68595be1655', 'Find patients admitted and discharged on the same ...', 'Find patients admitted and discharged on the same day. Show admission_id, patient_id, admission_date, discharge_date.', 'hospital', 'Medium', 15, 'SELECT admission_id, patient_id, admission_date, discharge_date FROM admissions WHERE admission_date = discharge_date AND discharge_date IS NOT NULL;'),
('9afac3ae-c0b9-410e-932d-ec36f9e9d8a9', 'Calculate the average length of stay (in days) per...', 'Calculate the average length of stay (in days) per department. Only include admissions with a discharge date. Show department_name and avg_stay_days rounded to 2 decimal places.', 'hospital', 'Medium', 15, 'SELECT dep.department_name, ROUND(AVG(julianday(a.discharge_date) - julianday(a.admission_date)), 2) AS avg_stay_days FROM admissions a JOIN doctors d ON a.attending_doctor_id = d.doctor_id JOIN departments dep ON d.department_id = dep.department_id WHERE a.discharge_date IS NOT NULL GROUP BY dep.department_name ORDER BY avg_stay_days DESC;'),
('d207837d-2c34-4a4d-9395-d889da101bcd', 'List all patients with their total number of admis...', 'List all patients with their total number of admissions. Show first_name, last_name, and admission_count. Include patients with zero admissions.', 'hospital', 'Medium', 15, 'SELECT p.first_name, p.last_name, COUNT(a.admission_id) AS admission_count FROM patients p LEFT JOIN admissions a ON p.patient_id = a.patient_id GROUP BY p.patient_id, p.first_name, p.last_name ORDER BY admission_count DESC;'),
('f8942808-158e-466c-9162-29e9e24bd9d3', 'Show the number of admissions per month in 2023. S...', 'Show the number of admissions per month in 2023. Show month (as ''YYYY-MM'') and admission_count, ordered chronologically.', 'hospital', 'Medium', 15, 'SELECT strftime(''%Y-%m'', admission_date) AS month, COUNT(*) AS admission_count FROM admissions WHERE strftime(''%Y'', admission_date) = ''2023'' GROUP BY month ORDER BY month;'),
('0583d589-d729-4a97-b9ca-40094f29b30b', 'Find all admissions where the patient was over 60 ...', 'Find all admissions where the patient was over 60 years old at the time of admission. Show admission_id, patient full name, age_at_admission, and admission_date.', 'hospital', 'Medium', 15, 'SELECT a.admission_id, p.first_name || '' '' || p.last_name AS patient_name, CAST((julianday(a.admission_date) - julianday(p.birth_date)) / 365 AS INTEGER) AS age_at_admission, a.admission_date FROM admissions a JOIN patients p ON a.patient_id = p.patient_id WHERE CAST((julianday(a.admission_date) - julianday(p.birth_date)) / 365 AS INTEGER) > 60 ORDER BY age_at_admission DESC;'),
('01f00d55-74e3-481f-baec-e2cfc41ed1fa', 'List doctors who have never had an admission assig...', 'List doctors who have never had an admission assigned to them. Show doctor_id, first_name, last_name, and specialty.', 'hospital', 'Medium', 15, 'SELECT d.doctor_id, d.first_name, d.last_name, d.specialty FROM doctors d LEFT JOIN admissions a ON d.doctor_id = a.attending_doctor_id WHERE a.admission_id IS NULL;'),
('4592674e-e8df-4e7b-a1a2-e61ecbda5c6a', 'Show patients admitted to the ''Cardiology'' departm...', 'Show patients admitted to the ''Cardiology'' department. Show patient first_name, last_name, admission_date, and diagnosis.', 'hospital', 'Medium', 15, 'SELECT p.first_name, p.last_name, a.admission_date, a.diagnosis FROM admissions a JOIN patients p ON a.patient_id = p.patient_id JOIN doctors d ON a.attending_doctor_id = d.doctor_id JOIN departments dep ON d.department_id = dep.department_id WHERE dep.department_name = ''Cardiology'';'),
('27b05ba4-63f3-4dfd-86bf-335616fedef8', 'Find the most common diagnosis across all admissio...', 'Find the most common diagnosis across all admissions. Show diagnosis and count, ordered by count descending. Show top 5.', 'hospital', 'Medium', 15, 'SELECT diagnosis, COUNT(*) AS diagnosis_count FROM admissions WHERE diagnosis IS NOT NULL GROUP BY diagnosis ORDER BY diagnosis_count DESC LIMIT 5;'),
('4066703c-03f5-401e-9d9b-5422882889f5', 'Update patient ID 2 (Maria Garcia)''s allergies to ...', 'Update patient ID 2 (Maria Garcia)''s allergies to ''Penicillin, Sulfa''. Write the UPDATE statement. Then verify with: SELECT patient_id, first_name, allergies FROM patients WHERE patient_id = 2', 'hospital', 'Medium', 15, 'UPDATE patients SET allergies = ''Penicillin, Sulfa'' WHERE patient_id = 2;'),
('58644e2a-5f7b-4128-8305-088dbb88e768', 'List admissions where both admission_date and disc...', 'List admissions where both admission_date and discharge_date are present. Show admission_id, admission_date, discharge_date, and days_stayed (as an integer). Order by days_stayed DESC.', 'hospital', 'Medium', 15, 'SELECT admission_id, admission_date, discharge_date, CAST(julianday(discharge_date) - julianday(admission_date) AS INTEGER) AS days_stayed FROM admissions WHERE discharge_date IS NOT NULL ORDER BY days_stayed DESC;'),
('90df5ea2-c6c9-4f4b-aa09-e9ef84a1b7bd', 'Show the top 5 provinces by patient count. Show pr...', 'Show the top 5 provinces by patient count. Show province_name and patient_count.', 'hospital', 'Medium', 15, 'SELECT pn.province_name, COUNT(p.patient_id) AS patient_count FROM patients p JOIN province_names pn ON p.province_id = pn.province_id GROUP BY pn.province_name ORDER BY patient_count DESC LIMIT 5;'),
('6192ca46-ad09-4485-a508-dc1b2778349e', 'Find patients whose weight is above the average we...', 'Find patients whose weight is above the average weight of all patients. Show first_name, last_name, and weight. Order by weight DESC.', 'hospital', 'Medium', 15, 'SELECT first_name, last_name, weight FROM patients WHERE weight > (SELECT AVG(weight) FROM patients) ORDER BY weight DESC;'),
('71833ac0-9b26-4451-b051-1f93c9701774', 'List all patients admitted in the last 30 days rel...', 'List all patients admitted in the last 30 days relative to 2024-08-31. Show patient_id, admission_date, and diagnosis.', 'hospital', 'Medium', 15, 'SELECT patient_id, admission_date, diagnosis FROM admissions WHERE admission_date >= date(''2024-08-31'', ''-30 days'') AND admission_date <= ''2024-08-31'';'),
('4b1008cc-eeea-4ba9-ae0d-e10b477c3571', 'Show doctors grouped by specialty with a count of ...', 'Show doctors grouped by specialty with a count of how many doctors have each specialty. Show specialty and doctor_count, ordered by doctor_count DESC.', 'hospital', 'Medium', 15, 'SELECT specialty, COUNT(*) AS doctor_count FROM doctors GROUP BY specialty ORDER BY doctor_count DESC;'),
('2ce719d1-d95e-4c43-bbbe-8eb944cecaa9', 'Find admissions where no discharge date has been s...', 'Find admissions where no discharge date has been set (patient is still admitted). Show admission_id, patient_id, admission_date, and diagnosis.', 'hospital', 'Medium', 15, 'SELECT admission_id, patient_id, admission_date, diagnosis FROM admissions WHERE discharge_date IS NULL;'),
('c79f5a86-d47d-4b21-8199-438546f7cc98', 'Calculate the total number of admissions per docto...', 'Calculate the total number of admissions per doctor per department. Show department_name, doctor full name, and admission_count. Order by department_name, admission_count DESC.', 'hospital', 'Medium', 15, 'SELECT dep.department_name, d.first_name || '' '' || d.last_name AS doctor_name, COUNT(a.admission_id) AS admission_count FROM doctors d JOIN departments dep ON d.department_id = dep.department_id LEFT JOIN admissions a ON d.doctor_id = a.attending_doctor_id GROUP BY dep.department_name, d.doctor_id ORDER BY dep.department_name, admission_count DESC;'),
('749e2cb3-10cf-48f7-b989-b9ed60054e86', 'List all patients with their full name as a single...', 'List all patients with their full name as a single column called ''full_name'' (format: ''First Last''). Also show patient_id.', 'hospital', 'Medium', 15, 'SELECT patient_id, first_name || '' '' || last_name AS full_name FROM patients;'),
('d1059181-c106-4f44-86bd-013b608912cb', 'Find patients who share the same last_name. Show t...', 'Find patients who share the same last_name. Show the last_name and how many patients share it (patient_count). Only include names shared by 2+ patients.', 'hospital', 'Medium', 15, 'SELECT last_name, COUNT(*) AS patient_count FROM patients GROUP BY last_name HAVING COUNT(*) > 1 ORDER BY patient_count DESC, last_name;'),
('f264a44e-c7c5-41f9-9949-65a372899c16', 'Show each doctor''s first admission date and last a...', 'Show each doctor''s first admission date and last admission date they handled. Show doctor full name, first_admission, last_admission.', 'hospital', 'Medium', 15, 'SELECT d.first_name || '' '' || d.last_name AS doctor_name, MIN(a.admission_date) AS first_admission, MAX(a.admission_date) AS last_admission FROM doctors d JOIN admissions a ON d.doctor_id = a.attending_doctor_id GROUP BY d.doctor_id, d.first_name, d.last_name ORDER BY doctor_name;'),
('1268ba2d-cb8a-444d-98ea-b9af94f2e88e', 'Find all diagnoses that appear more than 5 times i...', 'Find all diagnoses that appear more than 5 times in the admissions table. Show diagnosis and diagnosis_count, ordered by count DESC.', 'hospital', 'Medium', 15, 'SELECT diagnosis, COUNT(*) AS diagnosis_count FROM admissions WHERE diagnosis IS NOT NULL GROUP BY diagnosis HAVING COUNT(*) > 5 ORDER BY diagnosis_count DESC;'),
('c81e6ffc-b835-4b39-b1e7-b5b71d0a3f37', 'Rank doctors by their total number of admissions u...', 'Rank doctors by their total number of admissions using RANK(). Show doctor_id, full name, admission_count, and rank. Order by rank.', 'hospital', 'Hard', 25, 'SELECT doctor_id, first_name || '' '' || last_name AS doctor_name, admission_count, RANK() OVER (ORDER BY admission_count DESC) AS doctor_rank FROM (SELECT d.doctor_id, d.first_name, d.last_name, COUNT(a.admission_id) AS admission_count FROM doctors d LEFT JOIN admissions a ON d.doctor_id = a.attending_doctor_id GROUP BY d.doctor_id) ORDER BY doctor_rank;'),
('2ce71ef7-2122-487b-b942-2e8d310288d1', 'For each patient who has multiple admissions, show...', 'For each patient who has multiple admissions, show their previous admission date using LAG(). Display patient_id, admission_date, and prev_admission_date. Order by patient_id, admission_date.', 'hospital', 'Hard', 25, 'SELECT patient_id, admission_date, LAG(admission_date) OVER (PARTITION BY patient_id ORDER BY admission_date) AS prev_admission_date FROM admissions ORDER BY patient_id, admission_date;'),
('8471c5d7-9454-49be-8e50-a94aeeeb3e13', 'Find the top 3 most common diagnoses per departmen...', 'Find the top 3 most common diagnoses per department using ROW_NUMBER(). Show department_name, diagnosis, diagnosis_count, and row_num. Only show rows where row_num <= 3.', 'hospital', 'Hard', 25, 'WITH ranked AS (SELECT dep.department_name, a.diagnosis, COUNT(*) AS diagnosis_count, ROW_NUMBER() OVER (PARTITION BY dep.department_name ORDER BY COUNT(*) DESC) AS row_num FROM admissions a JOIN doctors d ON a.attending_doctor_id = d.doctor_id JOIN departments dep ON d.department_id = dep.department_id WHERE a.diagnosis IS NOT NULL GROUP BY dep.department_name, a.diagnosis) SELECT * FROM ranked WHERE row_num <= 3 ORDER BY department_name, row_num;'),
('b43b0c41-66ee-4a71-b6bd-09d0f24de982', 'Calculate a running total of admissions per month ...', 'Calculate a running total of admissions per month (for all months) using a window SUM. Show month, monthly_count, and running_total. Order chronologically.', 'hospital', 'Hard', 25, 'SELECT month, monthly_count, SUM(monthly_count) OVER (ORDER BY month ROWS UNBOUNDED PRECEDING) AS running_total FROM (SELECT strftime(''%Y-%m'', admission_date) AS month, COUNT(*) AS monthly_count FROM admissions GROUP BY month) ORDER BY month;'),
('99298cbf-6e2f-4228-a237-79dddf4be864', 'Use a CTE to find patients who have been admitted ...', 'Use a CTE to find patients who have been admitted in ALL THREE years: 2022, 2023, AND 2024. Show patient_id, first_name, and last_name.', 'hospital', 'Hard', 25, 'WITH patient_years AS (SELECT patient_id, strftime(''%Y'', admission_date) AS yr FROM admissions WHERE strftime(''%Y'', admission_date) IN (''2022'',''2023'',''2024'') GROUP BY patient_id, yr) SELECT p.patient_id, p.first_name, p.last_name FROM patient_years py JOIN patients p ON py.patient_id = p.patient_id GROUP BY py.patient_id HAVING COUNT(DISTINCT py.yr) = 3 ORDER BY p.patient_id;'),
('4f9482f0-da51-493f-98f8-163e7d7995ee', 'Use a CTE to find patients whose admission count i...', 'Use a CTE to find patients whose admission count is above the average admission count across all patients (who have at least 1 admission). Show patient_id, first_name, last_name, and admission_count.', 'hospital', 'Hard', 25, 'WITH counts AS (SELECT p.patient_id, p.first_name, p.last_name, COUNT(a.admission_id) AS admission_count FROM patients p JOIN admissions a ON p.patient_id = a.patient_id GROUP BY p.patient_id) SELECT * FROM counts WHERE admission_count > (SELECT AVG(admission_count) FROM counts) ORDER BY admission_count DESC;'),
('86aa670f-e95f-4682-ae4e-39249e31f993', 'For each patient with multiple admissions, find th...', 'For each patient with multiple admissions, find the longest gap in days between consecutive admissions. Show patient_id, first_name, and max_gap_days. Order by max_gap_days DESC, limit to 10.', 'hospital', 'Hard', 25, 'WITH gaps AS (SELECT patient_id, CAST(julianday(admission_date) - julianday(LAG(admission_date) OVER (PARTITION BY patient_id ORDER BY admission_date)) AS INTEGER) AS gap_days FROM admissions) SELECT p.patient_id, p.first_name, MAX(g.gap_days) AS max_gap_days FROM gaps g JOIN patients p ON g.patient_id = p.patient_id WHERE g.gap_days IS NOT NULL GROUP BY p.patient_id, p.first_name ORDER BY max_gap_days DESC LIMIT 10;'),
('91b32f48-3d61-46ba-89a9-eb7631a41132', 'Find the 2nd most recent admission per patient usi...', 'Find the 2nd most recent admission per patient using ROW_NUMBER(). Show patient_id, admission_date, diagnosis, and row_num for rows where row_num = 2. Order by patient_id.', 'hospital', 'Hard', 25, 'SELECT patient_id, admission_date, diagnosis, rn FROM (SELECT patient_id, admission_date, diagnosis, ROW_NUMBER() OVER (PARTITION BY patient_id ORDER BY admission_date DESC) AS rn FROM admissions) WHERE rn = 2 ORDER BY patient_id;'),
('a4af6666-5793-4645-81a8-7c758b35e0a6', 'Find patients who were treated by more than 3 diff...', 'Find patients who were treated by more than 3 different doctors across all their admissions. Show patient_id, first_name, and doctor_count.', 'hospital', 'Hard', 25, 'SELECT p.patient_id, p.first_name, COUNT(DISTINCT a.attending_doctor_id) AS doctor_count FROM admissions a JOIN patients p ON a.patient_id = p.patient_id GROUP BY p.patient_id, p.first_name HAVING COUNT(DISTINCT a.attending_doctor_id) > 3 ORDER BY doctor_count DESC;'),
('7dba40bf-052b-47c3-8a92-42083b9c64bb', 'Create a pivot-style report showing monthly admiss...', 'Create a pivot-style report showing monthly admission counts for each month (Jan-Dec) across all years combined, using CASE expressions. Show month_number, month_name, and admission_count.', 'hospital', 'Hard', 25, 'SELECT strftime(''%m'', admission_date) AS month_number, CASE strftime(''%m'', admission_date) WHEN ''01'' THEN ''January'' WHEN ''02'' THEN ''February'' WHEN ''03'' THEN ''March'' WHEN ''04'' THEN ''April'' WHEN ''05'' THEN ''May'' WHEN ''06'' THEN ''June'' WHEN ''07'' THEN ''July'' WHEN ''08'' THEN ''August'' WHEN ''09'' THEN ''September'' WHEN ''10'' THEN ''October'' WHEN ''11'' THEN ''November'' WHEN ''12'' THEN ''December'' END AS month_name, COUNT(*) AS admission_count FROM admissions GROUP BY month_number ORDER BY month_number;'),
('c83a875f-5608-45cd-948a-32729ca20928', 'For each admission, use LEAD() to show the next sc...', 'For each admission, use LEAD() to show the next scheduled admission date for that patient. Show patient_id, admission_date, diagnosis, and next_admission_date. Order by patient_id, admission_date.', 'hospital', 'Hard', 25, 'SELECT patient_id, admission_date, diagnosis, LEAD(admission_date) OVER (PARTITION BY patient_id ORDER BY admission_date) AS next_admission_date FROM admissions ORDER BY patient_id, admission_date;'),
('d6d74411-0117-40a8-90eb-831fc64c59e8', 'Show month-over-month admission growth: for each m...', 'Show month-over-month admission growth: for each month, show the current month count, prior month count, and growth percentage. Show month, admission_count, prev_month_count, and growth_pct (rounded to 1 decimal). Order by month.', 'hospital', 'Hard', 25, 'WITH monthly AS (SELECT strftime(''%Y-%m'', admission_date) AS month, COUNT(*) AS admission_count FROM admissions GROUP BY month) SELECT month, admission_count, LAG(admission_count) OVER (ORDER BY month) AS prev_month_count, ROUND(100.0 * (admission_count - LAG(admission_count) OVER (ORDER BY month)) / LAG(admission_count) OVER (ORDER BY month), 1) AS growth_pct FROM monthly ORDER BY month;'),
('f72ab4b6-caff-42de-9890-80e5f5d9bf1e', 'Identify doctors whose admission count is in the t...', 'Identify doctors whose admission count is in the top 25% using NTILE(4). Show doctor full name, admission_count, and quartile. Only show doctors in quartile 1 (top 25%).', 'hospital', 'Hard', 25, 'SELECT doctor_name, admission_count, quartile FROM (SELECT d.first_name || '' '' || d.last_name AS doctor_name, COUNT(a.admission_id) AS admission_count, NTILE(4) OVER (ORDER BY COUNT(a.admission_id) DESC) AS quartile FROM doctors d LEFT JOIN admissions a ON d.doctor_id = a.attending_doctor_id GROUP BY d.doctor_id) WHERE quartile = 1 ORDER BY admission_count DESC;'),
('65e8e61e-0435-4790-907a-d7123c73efe0', 'Write a recursive CTE to build a hierarchy showing...', 'Write a recursive CTE to build a hierarchy showing each department and its head doctor. Show department_name, head_doctor_name (first_name + last_name), and specialty.', 'hospital', 'Hard', 25, 'SELECT dep.department_name, d.first_name || '' '' || d.last_name AS head_doctor_name, d.specialty FROM departments dep LEFT JOIN doctors d ON dep.head_doctor_id = d.doctor_id ORDER BY dep.department_name;'),
('068c68b1-bad0-4b31-a6dd-d95edc39c4a7', 'Calculate a 30-day readmission rate per department...', 'Calculate a 30-day readmission rate per department: what % of admissions are followed by another admission within 30 days for the same patient? Show department_name and readmission_rate_pct (rounded to 1 decimal).', 'hospital', 'Hard', 25, 'WITH next_admits AS (SELECT a.patient_id, a.admission_date, a.attending_doctor_id, LEAD(a.admission_date) OVER (PARTITION BY a.patient_id ORDER BY a.admission_date) AS next_admission FROM admissions a) SELECT dep.department_name, ROUND(100.0 * SUM(CASE WHEN julianday(na.next_admission) - julianday(na.admission_date) <= 30 THEN 1 ELSE 0 END) / COUNT(*), 1) AS readmission_rate_pct FROM next_admits na JOIN doctors d ON na.attending_doctor_id = d.doctor_id JOIN departments dep ON d.department_id = dep.department_id GROUP BY dep.department_name ORDER BY readmission_rate_pct DESC;'),
('e81153b6-f441-4db2-86c7-b58e10957637', 'List all employees with their first_name, last_nam...', 'List all employees with their first_name, last_name, job_title, and salary.', 'hr', 'Easy', 5, 'SELECT first_name, last_name, job_title, salary FROM employees ORDER BY salary DESC;'),
('f5ca285c-30eb-40d1-aefc-f635ab60414e', 'Find all employees with a salary above 100,000. Sh...', 'Find all employees with a salary above 100,000. Show first_name, last_name, salary.', 'hr', 'Easy', 5, 'SELECT first_name, last_name, salary FROM employees WHERE salary > 100000 ORDER BY salary DESC;'),
('80215f21-bb36-43ff-9bb0-d54337440aa0', 'Count employees per department. Show department_id...', 'Count employees per department. Show department_id and employee_count.', 'hr', 'Easy', 5, 'SELECT department_id, COUNT(*) AS employee_count FROM employees GROUP BY department_id ORDER BY employee_count DESC;'),
('479cb29c-a1a2-40c5-9fb2-c849865dec18', 'List all departments with name, location, and budg...', 'List all departments with name, location, and budget.', 'hr', 'Easy', 5, 'SELECT name, location, budget FROM departments ORDER BY budget DESC;'),
('90f004b3-946e-46c1-ae0d-bd4b05975ab6', 'Find all employees in the Engineering department (...', 'Find all employees in the Engineering department (department_id = 1). Show first_name, last_name, job_title.', 'hr', 'Easy', 5, 'SELECT first_name, last_name, job_title FROM employees WHERE department_id = 1 ORDER BY salary DESC;'),
('1c048efb-99fa-4a55-b36c-1233ce2899b4', 'List all employees ordered by hire_date ascending ...', 'List all employees ordered by hire_date ascending (most senior first). Show first_name, last_name, hire_date.', 'hr', 'Easy', 5, 'SELECT first_name, last_name, hire_date FROM employees ORDER BY hire_date ASC;'),
('6377e42c-3fdb-4241-b7b3-5073a0ab5b01', 'Calculate average salary per department. Show depa...', 'Calculate average salary per department. Show department_id and avg_salary.', 'hr', 'Easy', 5, 'SELECT department_id, ROUND(AVG(salary), 2) AS avg_salary FROM employees GROUP BY department_id ORDER BY avg_salary DESC;'),
('72df1d9a-4a42-42f4-9c85-45e992ced897', 'Find employees hired after 2019-01-01. Show first_...', 'Find employees hired after 2019-01-01. Show first_name, last_name, hire_date.', 'hr', 'Easy', 5, 'SELECT first_name, last_name, hire_date FROM employees WHERE hire_date > ''2019-01-01'' ORDER BY hire_date;'),
('a32a5a2a-7b8d-48c9-99dc-d9ad0f752a09', 'Find employees with no manager (manager_id IS NULL...', 'Find employees with no manager (manager_id IS NULL). Show employee_id, first_name, last_name, job_title.', 'hr', 'Easy', 5, 'SELECT employee_id, first_name, last_name, job_title FROM employees WHERE manager_id IS NULL;'),
('a5e12646-bea6-4c44-82ff-40ab808de335', 'List the top 5 highest-paid employees. Show first_...', 'List the top 5 highest-paid employees. Show first_name, last_name, job_title, salary.', 'hr', 'Easy', 5, 'SELECT first_name, last_name, job_title, salary FROM employees ORDER BY salary DESC LIMIT 5;'),
('b4e2f17a-6a10-48cc-8b93-8f1168f7c8d7', 'Count performance reviews per employee. Show emplo...', 'Count performance reviews per employee. Show employee_id and review_count.', 'hr', 'Easy', 5, 'SELECT employee_id, COUNT(*) AS review_count FROM performance_reviews GROUP BY employee_id ORDER BY review_count DESC;'),
('d805d4f8-7521-41d2-b109-e4352952ab8a', 'Find all employees on Annual leave. Show employee_...', 'Find all employees on Annual leave. Show employee_id, leave_type = Annual and dates.', 'hr', 'Easy', 5, 'SELECT employee_id, type, start_date, end_date FROM leaves WHERE type = ''Annual'';'),
('51b2fc6a-9305-4d11-96e3-c840d1dac6e3', 'Calculate the total salary bill per department. Sh...', 'Calculate the total salary bill per department. Show department_id and total_salary.', 'hr', 'Easy', 5, 'SELECT department_id, SUM(salary) AS total_salary FROM employees GROUP BY department_id ORDER BY total_salary DESC;'),
('dfe79eff-8bbb-4281-9829-8f25a43c286d', 'Find all employees with job_title containing ''Mana...', 'Find all employees with job_title containing ''Manager''. Show first_name, last_name, job_title.', 'hr', 'Easy', 5, 'SELECT first_name, last_name, job_title FROM employees WHERE job_title LIKE ''%Manager%'';'),
('429a2de1-b4ca-4a7b-a4c3-75af350fe6fc', 'Show average performance score per employee across...', 'Show average performance score per employee across all reviews. Show employee_id and avg_score.', 'hr', 'Easy', 5, 'SELECT employee_id, ROUND(AVG(score), 2) AS avg_score FROM performance_reviews GROUP BY employee_id ORDER BY avg_score DESC;'),
('0d6738c1-3396-48cd-9268-4021fd143441', 'List all distinct locations across departments. Sh...', 'List all distinct locations across departments. Show location ordered alphabetically.', 'hr', 'Easy', 5, 'SELECT DISTINCT location FROM departments ORDER BY location;'),
('59025fb3-641f-4d1a-8528-d315fdbd5367', 'Find all leaves that were NOT approved. Show leave...', 'Find all leaves that were NOT approved. Show leave_id, employee_id, type, start_date.', 'hr', 'Easy', 5, 'SELECT leave_id, employee_id, type, start_date FROM leaves WHERE approved = 0;'),
('21f3d6a2-f6c6-4b89-a910-a2e0427f7e2a', 'Count how many leaves each employee has taken. Sho...', 'Count how many leaves each employee has taken. Show employee_id and leave_count.', 'hr', 'Easy', 5, 'SELECT employee_id, COUNT(*) AS leave_count FROM leaves GROUP BY employee_id ORDER BY leave_count DESC;'),
('f8ca9e38-9f9c-46a7-90a9-1bf9a3bbca2e', 'Find employees hired in 2018. Show first_name, las...', 'Find employees hired in 2018. Show first_name, last_name, hire_date.', 'hr', 'Easy', 5, 'SELECT first_name, last_name, hire_date FROM employees WHERE strftime(''%Y'', hire_date) = ''2018'';'),
('a7b65d4a-6bb5-4ae4-aeb0-b5f0cc891e1c', 'Show the highest and lowest salary per department....', 'Show the highest and lowest salary per department. Show department_id, max_salary, min_salary.', 'hr', 'Easy', 5, 'SELECT department_id, MAX(salary) AS max_salary, MIN(salary) AS min_salary FROM employees GROUP BY department_id ORDER BY max_salary DESC;'),
('ac974735-0bc8-454f-82d4-2deb4d15294b', 'Show employees with their department name. Show fi...', 'Show employees with their department name. Show first_name, last_name, job_title, and department_name.', 'hr', 'Medium', 15, 'SELECT e.first_name, e.last_name, e.job_title, d.name AS department_name FROM employees e JOIN departments d ON e.department_id = d.department_id ORDER BY d.name, e.salary DESC;'),
('5221559a-7f4e-4129-9523-d2abaf77c3a2', 'List each employee''s manager. Show employee name a...', 'List each employee''s manager. Show employee name and manager name.', 'hr', 'Medium', 15, 'SELECT e.first_name || '' '' || e.last_name AS employee_name, COALESCE(m.first_name || '' '' || m.last_name, ''No Manager'') AS manager_name FROM employees e LEFT JOIN employees m ON e.manager_id = m.employee_id ORDER BY manager_name;'),
('3a26b123-acfe-4bbc-921e-267e8d43f91c', 'Find the department with the highest total salary ...', 'Find the department with the highest total salary bill. Show department_name and total_salary.', 'hr', 'Medium', 15, 'SELECT d.name AS department_name, SUM(e.salary) AS total_salary FROM departments d JOIN employees e ON d.department_id = e.department_id GROUP BY d.department_id ORDER BY total_salary DESC LIMIT 1;'),
('406d82a0-f4f0-4c97-8ebe-a822b961a6e3', 'Find employees who earn above the average salary o...', 'Find employees who earn above the average salary of their department. Show first_name, last_name, department_id, salary.', 'hr', 'Medium', 15, 'SELECT first_name, last_name, department_id, salary FROM employees e WHERE salary > (SELECT AVG(salary) FROM employees e2 WHERE e2.department_id = e.department_id) ORDER BY department_id, salary DESC;'),
('0949a4c5-a441-4aab-9a81-19277708cbb4', 'Show department budget utilization: total salary v...', 'Show department budget utilization: total salary vs budget. Show department_name, budget, total_salary, and pct_used.', 'hr', 'Medium', 15, 'SELECT d.name AS department_name, d.budget, SUM(e.salary) AS total_salary, ROUND(100.0 * SUM(e.salary) / d.budget, 1) AS pct_used FROM departments d LEFT JOIN employees e ON d.department_id = e.department_id GROUP BY d.department_id ORDER BY pct_used DESC;'),
('cdb4901e-eee4-49b2-9c54-9b5e22956f39', 'Show average performance review score per departme...', 'Show average performance review score per department. Show department_name and avg_review_score.', 'hr', 'Medium', 15, 'SELECT d.name AS department_name, ROUND(AVG(pr.score), 2) AS avg_review_score FROM departments d JOIN employees e ON d.department_id = e.department_id JOIN performance_reviews pr ON e.employee_id = pr.employee_id GROUP BY d.department_id ORDER BY avg_review_score DESC;'),
('1b6bf52e-ccbe-4195-b89b-6cab032c30ef', 'Find employees who received a performance score of...', 'Find employees who received a performance score of 5 (top score) in any review. Show first_name, last_name, and review count with score 5.', 'hr', 'Medium', 15, 'SELECT e.first_name, e.last_name, COUNT(*) AS top_score_reviews FROM employees e JOIN performance_reviews pr ON e.employee_id = pr.employee_id WHERE pr.score = 5 GROUP BY e.employee_id ORDER BY top_score_reviews DESC;'),
('25ec3b77-f7c9-419c-896a-f4e35ff41ebc', 'Calculate total days of leave per employee across ...', 'Calculate total days of leave per employee across all leave types. Show employee name and total_leave_days.', 'hr', 'Medium', 15, 'SELECT e.first_name || '' '' || e.last_name AS employee_name, SUM(CAST(julianday(l.end_date) - julianday(l.start_date) + 1 AS INTEGER)) AS total_leave_days FROM employees e JOIN leaves l ON e.employee_id = l.employee_id GROUP BY e.employee_id ORDER BY total_leave_days DESC;'),
('86373e4e-1125-4144-8e1a-0adbda3b7ea9', 'List employees who have had a salary increase (mor...', 'List employees who have had a salary increase (more than 1 record in salaries). Show first_name, last_name, and number of salary changes.', 'hr', 'Medium', 15, 'SELECT e.first_name, e.last_name, COUNT(s.salary_id) AS salary_changes FROM employees e JOIN salaries s ON e.employee_id = s.employee_id GROUP BY e.employee_id HAVING COUNT(s.salary_id) > 1 ORDER BY salary_changes DESC;'),
('2c5f561f-f1a7-4015-8ed4-b9367b4968f3', 'Show the number of direct reports per manager. Sho...', 'Show the number of direct reports per manager. Show manager name and direct_report_count.', 'hr', 'Medium', 15, 'SELECT m.first_name || '' '' || m.last_name AS manager_name, COUNT(e.employee_id) AS direct_report_count FROM employees m JOIN employees e ON m.employee_id = e.manager_id GROUP BY m.employee_id ORDER BY direct_report_count DESC;'),
('71f50c3e-9338-4fd7-8d38-1db5c61049c7', 'Show total salary cost and headcount per city (fro...', 'Show total salary cost and headcount per city (from department location). Show city, headcount, total_salary.', 'hr', 'Medium', 15, 'SELECT d.location AS city, COUNT(e.employee_id) AS headcount, SUM(e.salary) AS total_salary FROM employees e JOIN departments d ON e.department_id = d.department_id GROUP BY d.location ORDER BY total_salary DESC;'),
('4cf35df8-ae0f-459d-a384-9b3149cfc8df', 'Find employees whose average review score is below...', 'Find employees whose average review score is below 4 (need improvement). Show first_name, last_name, and avg_score.', 'hr', 'Medium', 15, 'SELECT e.first_name, e.last_name, ROUND(AVG(pr.score), 2) AS avg_score FROM employees e JOIN performance_reviews pr ON e.employee_id = pr.employee_id GROUP BY e.employee_id HAVING AVG(pr.score) < 4 ORDER BY avg_score ASC;'),
('890a397a-51fa-42bb-9b8d-a0fe479070a0', 'Calculate years of service for each employee as of...', 'Calculate years of service for each employee as of 2024-01-01. Show first_name, last_name, and years_of_service.', 'hr', 'Medium', 15, 'SELECT first_name, last_name, ROUND((julianday(''2024-01-01'') - julianday(hire_date)) / 365, 1) AS years_of_service FROM employees ORDER BY years_of_service DESC;'),
('f7bdd2d5-17fd-465b-9961-588c50754afb', 'Show which departments have employees currently on...', 'Show which departments have employees currently on Sick leave. Show department_name and sick_leave_count.', 'hr', 'Medium', 15, 'SELECT d.name AS department_name, COUNT(l.leave_id) AS sick_leave_count FROM departments d JOIN employees e ON d.department_id = e.department_id JOIN leaves l ON e.employee_id = l.employee_id WHERE l.type = ''Sick'' GROUP BY d.department_id ORDER BY sick_leave_count DESC;'),
('6d3b9578-bd3f-4df3-8fc3-28be0b663d61', 'Calculate salary growth rate for employees with mu...', 'Calculate salary growth rate for employees with multiple salary records: (latest - earliest) / earliest × 100. Show employee name and salary_growth_pct.', 'hr', 'Medium', 15, 'SELECT e.first_name || '' '' || e.last_name AS employee_name, ROUND(100.0 * (MAX(s.amount) - MIN(s.amount)) / MIN(s.amount), 1) AS salary_growth_pct FROM employees e JOIN salaries s ON e.employee_id = s.employee_id GROUP BY e.employee_id HAVING COUNT(s.salary_id) > 1 ORDER BY salary_growth_pct DESC;'),
('a1880f1e-65c2-4363-bc9f-57a5060c11fb', 'Rank employees by salary within their department u...', 'Rank employees by salary within their department using DENSE_RANK. Show employee name, department_id, salary, and dept_salary_rank.', 'hr', 'Hard', 25, 'SELECT first_name || '' '' || last_name AS employee_name, department_id, salary, DENSE_RANK() OVER (PARTITION BY department_id ORDER BY salary DESC) AS dept_salary_rank FROM employees ORDER BY department_id, dept_salary_rank;'),
('79b9e474-0b3c-4172-9a7e-fc908e3f068e', 'Show salary progression for each employee: previou...', 'Show salary progression for each employee: previous salary and increase amount. Show employee name, effective_from, amount, prev_amount, and increase.', 'hr', 'Hard', 25, 'SELECT e.first_name || '' '' || e.last_name AS employee_name, s.effective_from, s.amount, LAG(s.amount) OVER (PARTITION BY s.employee_id ORDER BY s.effective_from) AS prev_amount, s.amount - LAG(s.amount) OVER (PARTITION BY s.employee_id ORDER BY s.effective_from) AS increase FROM salaries s JOIN employees e ON s.employee_id = e.employee_id ORDER BY employee_name, s.effective_from;'),
('55df0513-d751-4dae-a780-d5bd38ba58a9', 'Build the organizational hierarchy recursively fro...', 'Build the organizational hierarchy recursively from the top level. Show employee name, level, and manager name.', 'hr', 'Hard', 25, 'WITH RECURSIVE org AS (SELECT employee_id, first_name || '' '' || last_name AS employee_name, manager_id, ''Top Level'' AS manager_name, 1 AS org_level FROM employees WHERE manager_id IS NULL UNION ALL SELECT e.employee_id, e.first_name || '' '' || e.last_name, e.manager_id, o.employee_name, o.org_level + 1 FROM employees e JOIN org o ON e.manager_id = o.employee_id) SELECT employee_name, org_level AS level, manager_name FROM org ORDER BY org_level, employee_name;'),
('1d16b80d-8f42-4f06-8fa3-c7937aa9c993', 'Find the highest-reviewed employee in each departm...', 'Find the highest-reviewed employee in each department using ROW_NUMBER(). Show department_name, employee_name, avg_score where row_num = 1.', 'hr', 'Hard', 25, 'SELECT department_name, employee_name, avg_score FROM (SELECT d.name AS department_name, e.first_name || '' '' || e.last_name AS employee_name, ROUND(AVG(pr.score), 2) AS avg_score, ROW_NUMBER() OVER (PARTITION BY d.department_id ORDER BY AVG(pr.score) DESC) AS rn FROM employees e JOIN departments d ON e.department_id = d.department_id JOIN performance_reviews pr ON e.employee_id = pr.employee_id GROUP BY e.employee_id) WHERE rn = 1 ORDER BY department_name;'),
('96836027-2be9-40e2-85ec-fc783d3a428d', 'Calculate year-over-year review score improvement ...', 'Calculate year-over-year review score improvement per employee. Show employee name, year, avg_score, prev_year_score, and improvement.', 'hr', 'Hard', 25, 'WITH yearly AS (SELECT pr.employee_id, strftime(''%Y'', pr.review_date) AS review_year, ROUND(AVG(pr.score), 2) AS avg_score FROM performance_reviews pr GROUP BY pr.employee_id, review_year) SELECT e.first_name || '' '' || e.last_name AS employee_name, review_year, avg_score, LAG(avg_score) OVER (PARTITION BY employee_id ORDER BY review_year) AS prev_year_score, avg_score - LAG(avg_score) OVER (PARTITION BY employee_id ORDER BY review_year) AS improvement FROM yearly JOIN employees e USING (employee_id) ORDER BY employee_name, review_year;'),
('17c3a540-e475-44be-ad87-b84c66fd5198', 'Calculate each employee''s salary as a % of their d...', 'Calculate each employee''s salary as a % of their department''s total salary. Show employee name, department_name, salary, and salary_pct.', 'hr', 'Hard', 25, 'SELECT e.first_name || '' '' || e.last_name AS employee_name, d.name AS department_name, e.salary, ROUND(100.0 * e.salary / SUM(e.salary) OVER (PARTITION BY e.department_id), 2) AS salary_pct FROM employees e JOIN departments d ON e.department_id = d.department_id ORDER BY department_name, salary_pct DESC;'),
('57f01e0e-3f8e-4012-8422-00462fa3cafd', 'Find employees whose latest performance review sco...', 'Find employees whose latest performance review score was lower than their previous score (declining performers). Show employee name, latest_score, prev_score.', 'hr', 'Hard', 25, 'WITH ranked AS (SELECT employee_id, score, review_date, ROW_NUMBER() OVER (PARTITION BY employee_id ORDER BY review_date DESC) AS rn FROM performance_reviews) SELECT e.first_name || '' '' || e.last_name AS employee_name, r1.score AS latest_score, r2.score AS prev_score FROM ranked r1 JOIN ranked r2 ON r1.employee_id = r2.employee_id AND r1.rn = 1 AND r2.rn = 2 JOIN employees e ON r1.employee_id = e.employee_id WHERE r1.score < r2.score ORDER BY r1.score ASC;'),
('e268643c-4e63-494c-b652-7295d1ba69b4', 'Use NTILE(3) to bucket employees into performance ...', 'Use NTILE(3) to bucket employees into performance tiers based on average review score. Show employee name, avg_score, and tier (1=top, 3=bottom).', 'hr', 'Hard', 25, 'SELECT employee_name, avg_score, NTILE(3) OVER (ORDER BY avg_score DESC) AS tier FROM (SELECT e.first_name || '' '' || e.last_name AS employee_name, ROUND(AVG(pr.score), 2) AS avg_score FROM employees e JOIN performance_reviews pr ON e.employee_id = pr.employee_id GROUP BY e.employee_id) ORDER BY tier, avg_score DESC;'),
('c25911a1-c253-4a26-a1d6-fce6086821e7', 'Build a leave balance report: for each employee, s...', 'Build a leave balance report: for each employee, show total annual leave taken and remaining (assume 21 days allotted per year). Show employee name, taken_days, remaining_days.', 'hr', 'Hard', 25, 'WITH taken AS (SELECT l.employee_id, SUM(CAST(julianday(l.end_date) - julianday(l.start_date) + 1 AS INTEGER)) AS taken_days FROM leaves l WHERE l.type = ''Annual'' AND l.approved = 1 GROUP BY l.employee_id) SELECT e.first_name || '' '' || e.last_name AS employee_name, COALESCE(t.taken_days, 0) AS taken_days, 21 - COALESCE(t.taken_days, 0) AS remaining_days FROM employees e LEFT JOIN taken t ON e.employee_id = t.employee_id ORDER BY remaining_days ASC;'),
('148c90a1-53b8-4616-9eff-16e7dc8d99f8', 'Show the next review date for each employee (using...', 'Show the next review date for each employee (using LEAD on review_date). Show employee name, last_review_date, and next_review_date.', 'hr', 'Hard', 25, 'SELECT e.first_name || '' '' || e.last_name AS employee_name, pr.review_date, LEAD(pr.review_date) OVER (PARTITION BY pr.employee_id ORDER BY pr.review_date) AS next_review_date FROM performance_reviews pr JOIN employees e ON pr.employee_id = e.employee_id ORDER BY employee_name, pr.review_date;'),
('55435cb0-c42b-4a46-b094-386050d7c7cd', 'Create a complete employee performance scorecard: ...', 'Create a complete employee performance scorecard: show employee name, avg_review_score, salary, years_of_service, and a composite_score = avg_score × 20 + years × 1000. Rank DESC.', 'hr', 'Hard', 25, 'WITH rev AS (SELECT employee_id, ROUND(AVG(score), 2) AS avg_score FROM performance_reviews GROUP BY employee_id) SELECT e.first_name || '' '' || e.last_name AS employee_name, COALESCE(r.avg_score, 0) AS avg_score, e.salary, ROUND((julianday(''2024-01-01'') - julianday(e.hire_date)) / 365, 1) AS years, ROUND(COALESCE(r.avg_score, 0) * 20 + (julianday(''2024-01-01'') - julianday(e.hire_date)) / 365 * 1000, 0) AS composite_score, RANK() OVER (ORDER BY ROUND(COALESCE(r.avg_score, 0) * 20 + (julianday(''2024-01-01'') - julianday(e.hire_date)) / 365 * 1000, 0) DESC) AS perf_rank FROM employees e LEFT JOIN rev r ON e.employee_id = r.employee_id ORDER BY perf_rank;'),
('1b927162-bef2-417f-8158-8648198e5726', 'Calculate running headcount per month (cumulative ...', 'Calculate running headcount per month (cumulative hires by month). Show month, new_hires, and cumulative_headcount.', 'hr', 'Hard', 25, 'WITH monthly AS (SELECT strftime(''%Y-%m'', hire_date) AS month, COUNT(*) AS new_hires FROM employees GROUP BY month) SELECT month, new_hires, SUM(new_hires) OVER (ORDER BY month ROWS UNBOUNDED PRECEDING) AS cumulative_headcount FROM monthly ORDER BY month;'),
('d268fefa-7d5c-40b7-9d86-99386ee2d58b', 'Show the salary percentile rank of each employee a...', 'Show the salary percentile rank of each employee across the entire company. Show employee name, salary, and salary_percentile_rank (0–100).', 'hr', 'Hard', 25, 'SELECT first_name || '' '' || last_name AS employee_name, salary, ROUND(PERCENT_RANK() OVER (ORDER BY salary) * 100, 1) AS salary_percentile_rank FROM employees ORDER BY salary_percentile_rank DESC;'),
('ca4aa751-6e37-47e2-9c76-b162a4c761f0', 'Find employees who moved departments (appear in jo...', 'Find employees who moved departments (appear in job_history with different department_id). Show employee name and number_of_departments.', 'hr', 'Hard', 25, 'SELECT e.first_name || '' '' || e.last_name AS employee_name, COUNT(DISTINCT jh.department_id) AS number_of_departments FROM employees e JOIN job_history jh ON e.employee_id = jh.employee_id GROUP BY e.employee_id HAVING COUNT(DISTINCT jh.department_id) > 1 ORDER BY number_of_departments DESC;'),
('2d630139-f1a2-43ad-9b23-2b0eb71df551', 'Build a monthly attrition tracker: for each month ...', 'Build a monthly attrition tracker: for each month show new hires and cumulative % of company size by year-end (25 total employees). Show month, new_hires, cumulative_headcount, and pct_of_total.', 'hr', 'Hard', 25, 'WITH monthly AS (SELECT strftime(''%Y-%m'', hire_date) AS month, COUNT(*) AS new_hires FROM employees GROUP BY month) SELECT month, new_hires, SUM(new_hires) OVER (ORDER BY month ROWS UNBOUNDED PRECEDING) AS cumulative_headcount, ROUND(100.0 * SUM(new_hires) OVER (ORDER BY month ROWS UNBOUNDED PRECEDING) / 25.0, 1) AS pct_of_total FROM monthly ORDER BY month;'),
('02fda185-e8ca-4327-8983-3123b0af9026', 'List all books with title, published_year, and gen...', 'List all books with title, published_year, and genre, ordered by published_year.', 'library', 'Easy', 5, 'SELECT title, published_year, genre FROM books ORDER BY published_year;'),
('0910a0b9-05c2-4039-80b3-997fe5e15870', 'Find all books in the Fantasy genre. Show title an...', 'Find all books in the Fantasy genre. Show title and author_id.', 'library', 'Easy', 5, 'SELECT title, author_id FROM books WHERE genre = ''Fantasy'' ORDER BY title;'),
('88cd5e9c-64b0-40ab-98b7-e011bc10a2c2', 'List all library members with first_name, last_nam...', 'List all library members with first_name, last_name, and joined_date, ordered by joined_date DESC.', 'library', 'Easy', 5, 'SELECT first_name, last_name, joined_date FROM members ORDER BY joined_date DESC;'),
('7b5d54a2-89eb-48eb-ae70-98625d355c42', 'Find all active loans (return_date IS NULL). Show ...', 'Find all active loans (return_date IS NULL). Show loan_id, book_id, member_id, loan_date.', 'library', 'Easy', 5, 'SELECT loan_id, book_id, member_id, loan_date FROM loans WHERE return_date IS NULL;'),
('2f788741-5242-4b25-a495-b7b848f001d2', 'Count how many books each author has written. Show...', 'Count how many books each author has written. Show author_id and book_count.', 'library', 'Easy', 5, 'SELECT author_id, COUNT(*) AS book_count FROM books GROUP BY author_id ORDER BY book_count DESC;'),
('9a9151de-5009-4c6c-9295-58289a46026f', 'Show all overdue loans (return_date is after due_d...', 'Show all overdue loans (return_date is after due_date). Show loan_id, book_id, due_date, return_date.', 'library', 'Easy', 5, 'SELECT loan_id, book_id, due_date, return_date FROM loans WHERE return_date > due_date;'),
('ce0f84a5-697b-40c4-b40d-bf6e94afcab8', 'List all library branches with name and location....', 'List all library branches with name and location.', 'library', 'Easy', 5, 'SELECT name, location FROM branches;'),
('88579ba3-9b26-4728-8b58-5d5e583e7eb5', 'Count members per branch. Show branch_id and membe...', 'Count members per branch. Show branch_id and member_count.', 'library', 'Easy', 5, 'SELECT branch_id, COUNT(*) AS member_count FROM members GROUP BY branch_id ORDER BY member_count DESC;'),
('5a3336ec-84f9-4a79-a47f-391504b1c89b', 'List the 5 thickest books (most pages). Show title...', 'List the 5 thickest books (most pages). Show title and pages.', 'library', 'Easy', 5, 'SELECT title, pages FROM books ORDER BY pages DESC LIMIT 5;'),
('4f1d7ff1-917d-4605-9ac9-5d4af4ee551e', 'Count total number of loans in the database. Retur...', 'Count total number of loans in the database. Return total_loans.', 'library', 'Easy', 5, 'SELECT COUNT(*) AS total_loans FROM loans;');
INSERT INTO public.questions (id, title, prompt, schema_name, difficulty, estimated_time_minutes, solution_sql) VALUES
('9f9d6942-cb56-47b2-bc0c-9b9673663011', 'Find all British authors. Show first_name, last_na...', 'Find all British authors. Show first_name, last_name, and birth_year.', 'library', 'Easy', 5, 'SELECT first_name, last_name, birth_year FROM authors WHERE nationality = ''British'' ORDER BY last_name;'),
('681aae6d-288c-4f71-b6a6-5be8c6bd0479', 'Count books by genre. Show genre and count, ordere...', 'Count books by genre. Show genre and count, ordered by count DESC.', 'library', 'Easy', 5, 'SELECT genre, COUNT(*) AS book_count FROM books GROUP BY genre ORDER BY book_count DESC;'),
('0935008b-090c-4ac1-8c1d-68467c95e584', 'Find all unpaid fines (paid_date IS NULL). Show fi...', 'Find all unpaid fines (paid_date IS NULL). Show fine_id, loan_id, amount.', 'library', 'Easy', 5, 'SELECT fine_id, loan_id, amount FROM fines WHERE paid_date IS NULL;'),
('0aa83909-e411-4b3a-8a18-5bfa9ffb511b', 'Calculate total fines collected. Return total_fine...', 'Calculate total fines collected. Return total_fines.', 'library', 'Easy', 5, 'SELECT SUM(amount) AS total_fines FROM fines;'),
('c12545e1-6772-4c8b-a4cd-7ace7b700951', 'Find all loans for member_id = 1. Show loan_id, bo...', 'Find all loans for member_id = 1. Show loan_id, book_id, loan_date, return_date.', 'library', 'Easy', 5, 'SELECT loan_id, book_id, loan_date, return_date FROM loans WHERE member_id = 1;'),
('0aa423c4-407a-46ee-a812-00487fcf530c', 'Find books published before 1900. Show title and p...', 'Find books published before 1900. Show title and published_year.', 'library', 'Easy', 5, 'SELECT title, published_year FROM books WHERE published_year < 1900 ORDER BY published_year;'),
('07a4cee9-5937-4877-97ea-1e934d772681', 'List all distinct genres in the library. Show genr...', 'List all distinct genres in the library. Show genre, ordered alphabetically.', 'library', 'Easy', 5, 'SELECT DISTINCT genre FROM books ORDER BY genre;'),
('11986125-1fca-4953-a437-c426facf0f5f', 'Count total loans per member. Show member_id and l...', 'Count total loans per member. Show member_id and loan_count.', 'library', 'Easy', 5, 'SELECT member_id, COUNT(*) AS loan_count FROM loans GROUP BY member_id ORDER BY loan_count DESC;'),
('256aa831-3069-4f32-b83c-310337e19c03', 'Find all books with more than 500 pages. Show titl...', 'Find all books with more than 500 pages. Show title and pages.', 'library', 'Easy', 5, 'SELECT title, pages FROM books WHERE pages > 500 ORDER BY pages DESC;'),
('5f5d351f-aabd-4f4a-a167-989b8f5b36d1', 'Calculate average book length (pages) per genre. S...', 'Calculate average book length (pages) per genre. Show genre and avg_pages.', 'library', 'Easy', 5, 'SELECT genre, ROUND(AVG(pages), 0) AS avg_pages FROM books GROUP BY genre ORDER BY avg_pages DESC;'),
('823642f3-9f6b-4ed1-a889-8c5e431a5dd7', 'Show each book with its author name. Show title, a...', 'Show each book with its author name. Show title, author name, and genre.', 'library', 'Medium', 15, 'SELECT b.title, a.first_name || '' '' || a.last_name AS author_name, b.genre FROM books b JOIN authors a ON b.author_id = a.author_id ORDER BY b.title;'),
('68c2cf40-b2b0-4b50-89f7-3a188aa80d44', 'Show each member with their total number of loans ...', 'Show each member with their total number of loans and any unpaid fines. Show member name, loan_count, unpaid_fines.', 'library', 'Medium', 15, 'SELECT m.first_name || '' '' || m.last_name AS member_name, COUNT(DISTINCT l.loan_id) AS loan_count, COALESCE(SUM(CASE WHEN f.paid_date IS NULL THEN f.amount ELSE 0 END), 0) AS unpaid_fines FROM members m LEFT JOIN loans l ON m.member_id = l.member_id LEFT JOIN fines f ON l.loan_id = f.loan_id GROUP BY m.member_id ORDER BY unpaid_fines DESC;'),
('4673471e-658d-4dd6-a363-79793138c042', 'Calculate overdue days for each returned loan (ret...', 'Calculate overdue days for each returned loan (return_date - due_date). Show loan_id, book title, overdue_days.', 'library', 'Medium', 15, 'SELECT l.loan_id, b.title AS book_title, CAST(julianday(l.return_date) - julianday(l.due_date) AS INTEGER) AS overdue_days FROM loans l JOIN books b ON l.book_id = b.book_id WHERE l.return_date > l.due_date ORDER BY overdue_days DESC;'),
('4d76b3bd-12e7-4f31-b61d-8e27903532d5', 'Find the most borrowed book. Show title and borrow...', 'Find the most borrowed book. Show title and borrow_count.', 'library', 'Medium', 15, 'SELECT b.title, COUNT(l.loan_id) AS borrow_count FROM books b JOIN loans l ON b.book_id = l.book_id GROUP BY b.book_id ORDER BY borrow_count DESC LIMIT 1;'),
('fae9c837-c487-4b44-8396-7bf669555117', 'Find books that have never been borrowed. Show tit...', 'Find books that have never been borrowed. Show title, author_id, and genre.', 'library', 'Medium', 15, 'SELECT b.title, b.author_id, b.genre FROM books b LEFT JOIN loans l ON b.book_id = l.book_id WHERE l.loan_id IS NULL;'),
('4d8a6dc7-5178-4515-8826-8843bdee0b18', 'Show total number of loans and total fines per bra...', 'Show total number of loans and total fines per branch. Show branch_name, total_loans, total_fines.', 'library', 'Medium', 15, 'SELECT br.name AS branch_name, COUNT(l.loan_id) AS total_loans, COALESCE(SUM(f.amount), 0) AS total_fines FROM branches br LEFT JOIN members m ON br.branch_id = m.branch_id LEFT JOIN loans l ON m.member_id = l.member_id LEFT JOIN fines f ON l.loan_id = f.loan_id GROUP BY br.branch_id ORDER BY total_loans DESC;'),
('3f40bf2b-0456-4fd3-a357-3679bbb9c7b1', 'List authors with more than 3 books. Show author n...', 'List authors with more than 3 books. Show author name and book_count.', 'library', 'Medium', 15, 'SELECT a.first_name || '' '' || a.last_name AS author_name, COUNT(b.book_id) AS book_count FROM authors a JOIN books b ON a.author_id = b.author_id GROUP BY a.author_id HAVING COUNT(b.book_id) > 3 ORDER BY book_count DESC;'),
('fb6a2fdc-c821-4fc4-b52b-cb74a54b2871', 'Calculate how many days each loan was active (retu...', 'Calculate how many days each loan was active (return_date - loan_date). Show loan_id, book_title, and days_borrowed.', 'library', 'Medium', 15, 'SELECT l.loan_id, b.title AS book_title, CAST(julianday(l.return_date) - julianday(l.loan_date) AS INTEGER) AS days_borrowed FROM loans l JOIN books b ON l.book_id = b.book_id WHERE l.return_date IS NOT NULL ORDER BY days_borrowed DESC;'),
('b0261547-9572-4cbb-9ccd-0d4c6ff54090', 'Show member loan activity by month. Show month and...', 'Show member loan activity by month. Show month and loan_count.', 'library', 'Medium', 15, 'SELECT strftime(''%Y-%m'', loan_date) AS month, COUNT(*) AS loan_count FROM loans GROUP BY month ORDER BY month;'),
('93cf23c8-684e-457b-9e78-fd4b52ce50fd', 'Find members who have borrowed more than the avera...', 'Find members who have borrowed more than the average number of loans per member. Show member name and loan_count.', 'library', 'Medium', 15, 'SELECT m.first_name || '' '' || m.last_name AS member_name, COUNT(l.loan_id) AS loan_count FROM members m JOIN loans l ON m.member_id = l.member_id GROUP BY m.member_id HAVING COUNT(l.loan_id) > (SELECT AVG(cnt) FROM (SELECT COUNT(*) AS cnt FROM loans GROUP BY member_id)) ORDER BY loan_count DESC;'),
('02f44882-7d35-42fe-831e-57435c363704', 'Find the most active member per branch (most loans...', 'Find the most active member per branch (most loans). Show branch_name, member_name, loan_count.', 'library', 'Medium', 15, 'SELECT br.name AS branch_name, m.first_name || '' '' || m.last_name AS member_name, COUNT(l.loan_id) AS loan_count FROM branches br JOIN members m ON br.branch_id = m.branch_id JOIN loans l ON m.member_id = l.member_id GROUP BY br.branch_id, m.member_id HAVING COUNT(l.loan_id) = (SELECT MAX(cnt) FROM (SELECT COUNT(*) AS cnt FROM loans l2 JOIN members m2 ON l2.member_id = m2.member_id WHERE m2.branch_id = br.branch_id GROUP BY l2.member_id)) ORDER BY branch_name;'),
('c4e2b020-fef1-4366-bf79-7b6b8c39266a', 'Calculate fine collection rate per member: paid fi...', 'Calculate fine collection rate per member: paid fines / total fines. Show member name and collection_rate_pct.', 'library', 'Medium', 15, 'SELECT m.first_name || '' '' || m.last_name AS member_name, ROUND(100.0 * SUM(CASE WHEN f.paid_date IS NOT NULL THEN 1 ELSE 0 END) / COUNT(f.fine_id), 1) AS collection_rate_pct FROM members m JOIN loans l ON m.member_id = l.member_id JOIN fines f ON l.loan_id = f.loan_id GROUP BY m.member_id ORDER BY collection_rate_pct DESC;'),
('7ce28ab4-393a-49cf-ba8e-924321977ec2', 'Show the average loan duration (days) per genre. S...', 'Show the average loan duration (days) per genre. Show genre and avg_days.', 'library', 'Medium', 15, 'SELECT b.genre, ROUND(AVG(julianday(l.return_date) - julianday(l.loan_date)), 1) AS avg_days FROM books b JOIN loans l ON b.book_id = l.book_id WHERE l.return_date IS NOT NULL GROUP BY b.genre ORDER BY avg_days DESC;'),
('e68933dd-4ed6-4d55-a1ba-a112520f4954', 'Find the top 3 most borrowed genres. Show genre an...', 'Find the top 3 most borrowed genres. Show genre and borrow_count.', 'library', 'Medium', 15, 'SELECT b.genre, COUNT(l.loan_id) AS borrow_count FROM books b JOIN loans l ON b.book_id = l.book_id GROUP BY b.genre ORDER BY borrow_count DESC LIMIT 3;'),
('8f5e4a76-5e0d-45de-bfba-0ff39e430dcd', 'Show members who have borrowed more than one copy ...', 'Show members who have borrowed more than one copy of the same book. Show member_name and book_title.', 'library', 'Medium', 15, 'SELECT m.first_name || '' '' || m.last_name AS member_name, b.title AS book_title, COUNT(*) AS times_borrowed FROM loans l JOIN members m ON l.member_id = m.member_id JOIN books b ON l.book_id = b.book_id GROUP BY l.member_id, l.book_id HAVING COUNT(*) > 1 ORDER BY times_borrowed DESC;'),
('ad120c68-2158-49e8-95f9-848e0513b60a', 'Show the total unpaid fine amount per branch. Show...', 'Show the total unpaid fine amount per branch. Show branch_name and unpaid_total.', 'library', 'Medium', 15, 'SELECT br.name AS branch_name, SUM(f.amount) AS unpaid_total FROM branches br JOIN members m ON br.branch_id = m.branch_id JOIN loans l ON m.member_id = l.member_id JOIN fines f ON l.loan_id = f.loan_id WHERE f.paid_date IS NULL GROUP BY br.branch_id ORDER BY unpaid_total DESC;'),
('d8b890ae-fe56-4dd2-8d90-97222aa99d86', 'Show the overdue return rate per genre: overdue lo...', 'Show the overdue return rate per genre: overdue loans / total loans × 100. Show genre and overdue_rate_pct.', 'library', 'Medium', 15, 'SELECT b.genre, ROUND(100.0 * SUM(CASE WHEN l.return_date > l.due_date THEN 1 ELSE 0 END) / COUNT(l.loan_id), 1) AS overdue_rate_pct FROM books b JOIN loans l ON b.book_id = l.book_id WHERE l.return_date IS NOT NULL GROUP BY b.genre ORDER BY overdue_rate_pct DESC;'),
('94c30059-b4db-41e4-8a51-e68a0d38d893', 'Show the number of books currently on loan per bra...', 'Show the number of books currently on loan per branch. Show branch_name and on_loan_count.', 'library', 'Medium', 15, 'SELECT br.name AS branch_name, COUNT(l.loan_id) AS on_loan_count FROM branches br JOIN members m ON br.branch_id = m.branch_id JOIN loans l ON m.member_id = l.member_id WHERE l.return_date IS NULL GROUP BY br.branch_id ORDER BY on_loan_count DESC;'),
('f99f9fa3-7186-4311-9985-9344d9ac9994', 'Find the author whose books are borrowed most freq...', 'Find the author whose books are borrowed most frequently. Show author name and total_borrows.', 'library', 'Medium', 15, 'SELECT a.first_name || '' '' || a.last_name AS author_name, COUNT(l.loan_id) AS total_borrows FROM authors a JOIN books b ON a.author_id = b.author_id JOIN loans l ON b.book_id = l.book_id GROUP BY a.author_id ORDER BY total_borrows DESC LIMIT 1;'),
('78856894-9a9e-460a-9302-a6c120ed2421', 'Show each loan with fine amount (if any). Show loa...', 'Show each loan with fine amount (if any). Show loan_id, book_title, fine_amount (0 if no fine).', 'library', 'Medium', 15, 'SELECT l.loan_id, b.title AS book_title, COALESCE(f.amount, 0) AS fine_amount FROM loans l JOIN books b ON l.book_id = b.book_id LEFT JOIN fines f ON l.loan_id = f.loan_id ORDER BY fine_amount DESC;'),
('10d46256-c731-496a-a5f2-a1eed9ccfd27', 'Calculate borrowing frequency per member per month...', 'Calculate borrowing frequency per member per month: average loans per month. Show member name and avg_monthly_loans.', 'library', 'Medium', 15, 'SELECT m.first_name || '' '' || m.last_name AS member_name, ROUND(COUNT(l.loan_id) * 1.0 / COUNT(DISTINCT strftime(''%Y-%m'', l.loan_date)), 2) AS avg_monthly_loans FROM members m JOIN loans l ON m.member_id = l.member_id GROUP BY m.member_id ORDER BY avg_monthly_loans DESC;'),
('692203fd-6e6b-4138-8603-b8d6f3754c88', 'Show which branch has the highest fine collection ...', 'Show which branch has the highest fine collection rate (paid / total × 100). Show branch_name and collection_rate_pct.', 'library', 'Medium', 15, 'SELECT br.name AS branch_name, ROUND(100.0 * SUM(CASE WHEN f.paid_date IS NOT NULL THEN 1 ELSE 0 END) / COUNT(f.fine_id), 1) AS collection_rate_pct FROM branches br JOIN members m ON br.branch_id = m.branch_id JOIN loans l ON m.member_id = l.member_id JOIN fines f ON l.loan_id = f.loan_id GROUP BY br.branch_id ORDER BY collection_rate_pct DESC;'),
('b6b6b34b-ca18-44af-bfc1-c5c5ead0a503', 'Show the top 5 members by total fine amount incurr...', 'Show the top 5 members by total fine amount incurred. Show member name and total_fines.', 'library', 'Medium', 15, 'SELECT m.first_name || '' '' || m.last_name AS member_name, SUM(f.amount) AS total_fines FROM members m JOIN loans l ON m.member_id = l.member_id JOIN fines f ON l.loan_id = f.loan_id GROUP BY m.member_id ORDER BY total_fines DESC LIMIT 5;'),
('b34ec4af-81a7-455e-9d2d-63268d5afa94', 'Show the monthly borrowing trend for 2024. Show mo...', 'Show the monthly borrowing trend for 2024. Show month and loan_count.', 'library', 'Medium', 15, 'SELECT strftime(''%m'', loan_date) AS month, COUNT(*) AS loan_count FROM loans WHERE strftime(''%Y'', loan_date) = ''2024'' GROUP BY month ORDER BY month;'),
('cb680167-f061-4acb-a3d4-f4c86059afd0', 'Find genres where the average book length exceeds ...', 'Find genres where the average book length exceeds 400 pages. Show genre and avg_pages.', 'library', 'Medium', 15, 'SELECT genre, ROUND(AVG(pages), 0) AS avg_pages FROM books GROUP BY genre HAVING AVG(pages) > 400 ORDER BY avg_pages DESC;'),
('640aaa30-99ee-471b-b025-930c69e800c6', 'Rank books by borrow frequency using DENSE_RANK. S...', 'Rank books by borrow frequency using DENSE_RANK. Show title, genre, borrow_count, and borrow_rank.', 'library', 'Hard', 25, 'SELECT title, genre, borrow_count, DENSE_RANK() OVER (ORDER BY borrow_count DESC) AS borrow_rank FROM (SELECT b.title, b.genre, COUNT(l.loan_id) AS borrow_count FROM books b LEFT JOIN loans l ON b.book_id = l.book_id GROUP BY b.book_id) ORDER BY borrow_rank;'),
('21c1bfc7-71d1-4e0c-96bb-cf71503eb18c', 'Find the most borrowed book per genre using ROW_NU...', 'Find the most borrowed book per genre using ROW_NUMBER(). Show genre, title, borrow_count where rn=1.', 'library', 'Hard', 25, 'SELECT genre, title, borrow_count FROM (SELECT b.genre, b.title, COUNT(l.loan_id) AS borrow_count, ROW_NUMBER() OVER (PARTITION BY b.genre ORDER BY COUNT(l.loan_id) DESC) AS rn FROM books b LEFT JOIN loans l ON b.book_id = l.book_id GROUP BY b.book_id) WHERE rn = 1 ORDER BY borrow_count DESC;'),
('ebaf63ed-4705-408d-9e43-6e052eea896e', 'Show the running total of fines collected by month...', 'Show the running total of fines collected by month. Show month, monthly_fines, and running_total.', 'library', 'Hard', 25, 'WITH monthly AS (SELECT strftime(''%Y-%m'', paid_date) AS month, SUM(amount) AS monthly_fines FROM fines WHERE paid_date IS NOT NULL GROUP BY month) SELECT month, monthly_fines, SUM(monthly_fines) OVER (ORDER BY month ROWS UNBOUNDED PRECEDING) AS running_total FROM monthly ORDER BY month;'),
('da98d066-2999-4f69-8d9a-b3aa6397260b', 'Calculate each member''s first loan and how many da...', 'Calculate each member''s first loan and how many days ago that was. Show member_name, first_loan_date, and days_since_first_loan.', 'library', 'Hard', 25, 'WITH first_loans AS (SELECT member_id, MIN(loan_date) AS first_loan_date FROM loans GROUP BY member_id) SELECT m.first_name || '' '' || m.last_name AS member_name, fl.first_loan_date, CAST(julianday(''2024-04-01'') - julianday(fl.first_loan_date) AS INTEGER) AS days_since_first_loan FROM members m JOIN first_loans fl ON m.member_id = fl.member_id ORDER BY days_since_first_loan DESC;'),
('a0e52c78-d2a0-4e70-9897-d583689920d2', 'Show fine accumulation over time per member: for e...', 'Show fine accumulation over time per member: for each fine, show a running total of fines per member sorted by date.', 'library', 'Hard', 25, 'SELECT m.first_name || '' '' || m.last_name AS member_name, l.loan_date, f.amount, SUM(f.amount) OVER (PARTITION BY m.member_id ORDER BY l.loan_date ROWS UNBOUNDED PRECEDING) AS running_fine_total FROM members m JOIN loans l ON m.member_id = l.member_id JOIN fines f ON l.loan_id = f.loan_id ORDER BY member_name, l.loan_date;'),
('ab7fd420-c7f4-4155-a627-ff2141721cc3', 'Calculate each book''s borrow share as % of total l...', 'Calculate each book''s borrow share as % of total loans. Show title, borrow_count, and pct_of_total.', 'library', 'Hard', 25, 'SELECT title, borrow_count, ROUND(100.0 * borrow_count / SUM(borrow_count) OVER (), 2) AS pct_of_total FROM (SELECT b.title, COUNT(l.loan_id) AS borrow_count FROM books b JOIN loans l ON b.book_id = l.book_id GROUP BY b.book_id) ORDER BY borrow_count DESC;'),
('9289bb6a-07b9-4eb0-939b-fe4380bfa2e8', 'For each member, show their previous loan book and...', 'For each member, show their previous loan book and next loan book (using LAG and LEAD). Show member_id, current_book, prev_book, next_book.', 'library', 'Hard', 25, 'SELECT l.member_id, b.title AS current_book, LAG(b.title) OVER (PARTITION BY l.member_id ORDER BY l.loan_date) AS prev_book, LEAD(b.title) OVER (PARTITION BY l.member_id ORDER BY l.loan_date) AS next_book FROM loans l JOIN books b ON l.book_id = b.book_id ORDER BY l.member_id, l.loan_date;'),
('9094e284-8deb-4138-89fd-5e9b3066defa', 'Find the time between consecutive borrows for each...', 'Find the time between consecutive borrows for each member (days between loans). Show member_id, loan_date, prev_loan_date, and days_between_loans.', 'library', 'Hard', 25, 'SELECT member_id, loan_date, LAG(loan_date) OVER (PARTITION BY member_id ORDER BY loan_date) AS prev_loan_date, CAST(julianday(loan_date) - julianday(LAG(loan_date) OVER (PARTITION BY member_id ORDER BY loan_date)) AS INTEGER) AS days_between_loans FROM loans ORDER BY member_id, loan_date;'),
('6f273de2-6964-4a7b-a79e-5051bbc800ce', 'Use NTILE(3) to segment members by activity level ...', 'Use NTILE(3) to segment members by activity level (loans taken). Show member_name, loan_count, and activity_tier (1=most active, 3=least active).', 'library', 'Hard', 25, 'SELECT member_name, loan_count, NTILE(3) OVER (ORDER BY loan_count DESC) AS activity_tier FROM (SELECT m.first_name || '' '' || m.last_name AS member_name, COUNT(l.loan_id) AS loan_count FROM members m LEFT JOIN loans l ON m.member_id = l.member_id GROUP BY m.member_id) ORDER BY activity_tier, loan_count DESC;'),
('a4a66265-3ce0-48c6-9348-3b4e35e37552', 'Calculate a 3-month rolling average of library loa...', 'Calculate a 3-month rolling average of library loans. Show month, loan_count, and rolling_avg.', 'library', 'Hard', 25, 'WITH monthly AS (SELECT strftime(''%Y-%m'', loan_date) AS month, COUNT(*) AS loan_count FROM loans GROUP BY month) SELECT month, loan_count, ROUND(AVG(loan_count) OVER (ORDER BY month ROWS BETWEEN 2 PRECEDING AND CURRENT ROW), 1) AS rolling_avg FROM monthly ORDER BY month;'),
('cb528ab9-5314-4bef-8721-b18fe91ad122', 'Build a comprehensive book report: for each book s...', 'Build a comprehensive book report: for each book show title, genre, total_borrows, total_fines_generated, and book_score = borrows × 10 - fines × 5. Rank by book_score.', 'library', 'Hard', 25, 'WITH borrows AS (SELECT book_id, COUNT(*) AS total_borrows FROM loans GROUP BY book_id), fines_per_book AS (SELECT l.book_id, SUM(f.amount) AS total_fines FROM loans l JOIN fines f ON l.loan_id = f.loan_id GROUP BY l.book_id) SELECT b.title, b.genre, COALESCE(br.total_borrows, 0) AS total_borrows, COALESCE(fp.total_fines, 0) AS total_fines_generated, COALESCE(br.total_borrows, 0) * 10 - COALESCE(fp.total_fines, 0) * 5 AS book_score, RANK() OVER (ORDER BY COALESCE(br.total_borrows, 0) * 10 - COALESCE(fp.total_fines, 0) * 5 DESC) AS book_rank FROM books b LEFT JOIN borrows br ON b.book_id = br.book_id LEFT JOIN fines_per_book fp ON b.book_id = fp.book_id ORDER BY book_rank;'),
('8bd39599-897a-443a-bb3f-6b2f6ebcd720', 'Show a year-over-year comparison of library usage ...', 'Show a year-over-year comparison of library usage (loan counts). Show year, total_loans, prev_year_loans, and yoy_change.', 'library', 'Hard', 25, 'WITH yearly AS (SELECT strftime(''%Y'', loan_date) AS year, COUNT(*) AS total_loans FROM loans GROUP BY year) SELECT year, total_loans, LAG(total_loans) OVER (ORDER BY year) AS prev_year_loans, total_loans - LAG(total_loans) OVER (ORDER BY year) AS yoy_change FROM yearly ORDER BY year;'),
('f0f017e0-b505-4ac2-bca4-3cc7bf9438e2', 'Show each loan''s overdue days and rank it as a per...', 'Show each loan''s overdue days and rank it as a percentile among all overdue loans. Show loan_id, overdue_days, and overdue_percentile.', 'library', 'Hard', 25, 'SELECT loan_id, overdue_days, ROUND(PERCENT_RANK() OVER (ORDER BY overdue_days) * 100, 1) AS overdue_percentile FROM (SELECT loan_id, CAST(julianday(return_date) - julianday(due_date) AS INTEGER) AS overdue_days FROM loans WHERE return_date > due_date) ORDER BY overdue_days DESC;'),
('a27c0da3-6d6c-4b80-ace8-c9a6c98d4dd1', 'Identify books that are currently overdue (on loan...', 'Identify books that are currently overdue (on loan and past due_date). Show book_title, member_name, due_date, and days_overdue.', 'library', 'Hard', 25, 'SELECT b.title AS book_title, m.first_name || '' '' || m.last_name AS member_name, l.due_date, CAST(julianday(''2024-04-01'') - julianday(l.due_date) AS INTEGER) AS days_overdue FROM loans l JOIN books b ON l.book_id = b.book_id JOIN members m ON l.member_id = m.member_id WHERE l.return_date IS NULL AND l.due_date < ''2024-04-01'' ORDER BY days_overdue DESC;'),
('4607ae5d-c447-4d39-a222-b0686521b603', 'Build a member loyalty score: total_loans × 5 - to...', 'Build a member loyalty score: total_loans × 5 - total_unpaid_fines × 10. Rank members by loyalty_score. Show member_name, total_loans, unpaid_fines, loyalty_score, and rank.', 'library', 'Hard', 25, 'WITH loan_counts AS (SELECT member_id, COUNT(*) AS total_loans FROM loans GROUP BY member_id), unpaid AS (SELECT l.member_id, SUM(f.amount) AS unpaid_fines FROM loans l JOIN fines f ON l.loan_id = f.loan_id WHERE f.paid_date IS NULL GROUP BY l.member_id) SELECT m.first_name || '' '' || m.last_name AS member_name, COALESCE(lc.total_loans, 0) AS total_loans, COALESCE(u.unpaid_fines, 0) AS unpaid_fines, COALESCE(lc.total_loans, 0) * 5 - COALESCE(u.unpaid_fines, 0) * 10 AS loyalty_score, RANK() OVER (ORDER BY COALESCE(lc.total_loans, 0) * 5 - COALESCE(u.unpaid_fines, 0) * 10 DESC) AS loyalty_rank FROM members m LEFT JOIN loan_counts lc ON m.member_id = lc.member_id LEFT JOIN unpaid u ON m.member_id = u.member_id ORDER BY loyalty_rank;'),
('4722ec95-2bba-4948-9f34-03ea99295aeb', 'List all movies with title, release_year, and rati...', 'List all movies with title, release_year, and rating, ordered by rating DESC.', 'movies', 'Easy', 5, 'SELECT title, release_year, rating FROM movies ORDER BY rating DESC;'),
('09ebc603-6933-4bab-9a0c-e12f5abeb6a4', 'Find all movies released after 2010. Show title, r...', 'Find all movies released after 2010. Show title, release_year, rating.', 'movies', 'Easy', 5, 'SELECT title, release_year, rating FROM movies WHERE release_year > 2010 ORDER BY release_year;'),
('1ca122ce-44e7-4bf7-81bd-4225f7cdb5ae', 'List the top 5 highest-grossing movies. Show title...', 'List the top 5 highest-grossing movies. Show title and box_office.', 'movies', 'Easy', 5, 'SELECT title, box_office FROM movies ORDER BY box_office DESC LIMIT 5;'),
('73f7edfb-2e3d-467b-b6e9-d8cce26df518', 'Find all movies directed by Christopher Nolan (dir...', 'Find all movies directed by Christopher Nolan (director_id = 1). Show title and release_year.', 'movies', 'Easy', 5, 'SELECT title, release_year FROM movies WHERE director_id = 1 ORDER BY release_year;'),
('80d8787b-7a5c-4fc3-93ce-ea33ac4bb0b4', 'Show all movies with a rating above 8.5. Show titl...', 'Show all movies with a rating above 8.5. Show title and rating.', 'movies', 'Easy', 5, 'SELECT title, rating FROM movies WHERE rating > 8.5 ORDER BY rating DESC;'),
('51c3a797-4715-4c82-b189-ca7ab6b282ae', 'List all genres. Show genre_id and name, ordered b...', 'List all genres. Show genre_id and name, ordered by name.', 'movies', 'Easy', 5, 'SELECT genre_id, name FROM genres ORDER BY name;'),
('fdc8c0f0-4654-418e-9ba0-ebd5fdb74611', 'Find all American directors. Show first_name, last...', 'Find all American directors. Show first_name, last_name.', 'movies', 'Easy', 5, 'SELECT first_name, last_name FROM directors WHERE nationality = ''American'' ORDER BY last_name;'),
('6f2cc8dc-2987-4a2d-b36f-04c91c57cd81', 'Count how many movies each director has made. Show...', 'Count how many movies each director has made. Show director_id and movie_count.', 'movies', 'Easy', 5, 'SELECT director_id, COUNT(*) AS movie_count FROM movies GROUP BY director_id ORDER BY movie_count DESC;'),
('a07c7bd8-7b20-46bd-b249-43b6fa764ff4', 'Find movies with no box_office data (box_office IS...', 'Find movies with no box_office data (box_office IS NULL). Show title and release_year.', 'movies', 'Easy', 5, 'SELECT title, release_year FROM movies WHERE box_office IS NULL;'),
('6a7cf9dd-b5cc-4ccd-9329-b85eb896bb4e', 'Show the average movie rating across the dataset. ...', 'Show the average movie rating across the dataset. Return a single value labeled avg_rating.', 'movies', 'Easy', 5, 'SELECT ROUND(AVG(rating), 2) AS avg_rating FROM movies;'),
('fd769b83-4e46-4ff6-abd0-7f9030ceef2d', 'Find movies with a duration over 2.5 hours (150 mi...', 'Find movies with a duration over 2.5 hours (150 mins). Show title and duration_mins.', 'movies', 'Easy', 5, 'SELECT title, duration_mins FROM movies WHERE duration_mins > 150 ORDER BY duration_mins DESC;'),
('e1743820-33cb-4f9e-b7d9-bb65ce60ac0f', 'List all movies released in the 1990s. Show title ...', 'List all movies released in the 1990s. Show title and release_year.', 'movies', 'Easy', 5, 'SELECT title, release_year FROM movies WHERE release_year BETWEEN 1990 AND 1999 ORDER BY release_year;'),
('3b3f936c-181e-4a3f-8a6d-6ce3b96d10ff', 'Calculate average rating per release decade. Show ...', 'Calculate average rating per release decade. Show decade and avg_rating.', 'movies', 'Easy', 5, 'SELECT (release_year / 10) * 10 AS decade, ROUND(AVG(rating), 2) AS avg_rating FROM movies GROUP BY decade ORDER BY decade;'),
('c2da9598-96b8-488c-b979-ea5f98b2f019', 'Find all movies with a budget under $20 million. S...', 'Find all movies with a budget under $20 million. Show title, budget.', 'movies', 'Easy', 5, 'SELECT title, budget FROM movies WHERE budget < 20000000 ORDER BY budget;'),
('bb16a09b-c1fb-49f6-8a32-fdc69e2fd2d8', 'Show the shortest and longest movie. Show min_dura...', 'Show the shortest and longest movie. Show min_duration and max_duration.', 'movies', 'Easy', 5, 'SELECT MIN(duration_mins) AS min_duration, MAX(duration_mins) AS max_duration FROM movies;'),
('1cd02c8d-fdd9-41f0-b8fe-85f8091fddd9', 'Count how many actors are in the database. Return ...', 'Count how many actors are in the database. Return actor_count.', 'movies', 'Easy', 5, 'SELECT COUNT(*) AS actor_count FROM actors;'),
('600c3515-26c9-4b16-8c96-2cb054ac7b66', 'Find all actors born in the 1970s. Show first_name...', 'Find all actors born in the 1970s. Show first_name, last_name, birth_year.', 'movies', 'Easy', 5, 'SELECT first_name, last_name, birth_year FROM actors WHERE birth_year BETWEEN 1970 AND 1979 ORDER BY birth_year;'),
('ce20d9aa-13b7-4259-8253-f23409e79782', 'Calculate the total box office revenue of all movi...', 'Calculate the total box office revenue of all movies combined. Return total_box_office.', 'movies', 'Easy', 5, 'SELECT SUM(box_office) AS total_box_office FROM movies WHERE box_office IS NOT NULL;'),
('9951f73c-c3dc-456f-9136-8fc4b6a65958', 'Find movies that were profitable (box_office > bud...', 'Find movies that were profitable (box_office > budget). Show title, budget, box_office.', 'movies', 'Easy', 5, 'SELECT title, budget, box_office FROM movies WHERE box_office > budget ORDER BY (box_office - budget) DESC;'),
('fff621f7-d2c9-49f3-a722-84227c14b402', 'Count movies per genre using movie_genres. Show ge...', 'Count movies per genre using movie_genres. Show genre_id and movie_count.', 'movies', 'Easy', 5, 'SELECT genre_id, COUNT(*) AS movie_count FROM movie_genres GROUP BY genre_id ORDER BY movie_count DESC;'),
('4a570b80-6f77-490c-b547-5836d13b6d47', 'Show each director with the number of movies and a...', 'Show each director with the number of movies and average rating. Show director name, movie_count, avg_rating.', 'movies', 'Medium', 15, 'SELECT d.first_name || '' '' || d.last_name AS director_name, COUNT(m.movie_id) AS movie_count, ROUND(AVG(m.rating), 2) AS avg_rating FROM directors d LEFT JOIN movies m ON d.director_id = m.director_id GROUP BY d.director_id ORDER BY avg_rating DESC;'),
('3dff6f69-8dad-4dca-8830-f1792f59fae0', 'Calculate profit (box_office - budget) per movie. ...', 'Calculate profit (box_office - budget) per movie. Show title, profit, and ROI% = profit/budget*100. Order by profit DESC.', 'movies', 'Medium', 15, 'SELECT title, (box_office - budget) AS profit, ROUND(100.0 * (box_office - budget) / budget, 1) AS roi_pct FROM movies WHERE box_office IS NOT NULL ORDER BY profit DESC;'),
('0bff7ffa-2803-4da4-a5e7-b25262c01728', 'Show the most common genre combinations (movies ta...', 'Show the most common genre combinations (movies tagged with multiple genres). Show movie title and genre_count.', 'movies', 'Medium', 15, 'SELECT m.title, COUNT(mg.genre_id) AS genre_count FROM movies m JOIN movie_genres mg ON m.movie_id = mg.movie_id GROUP BY m.movie_id ORDER BY genre_count DESC;'),
('3d976590-3220-4d30-bc18-d38c0013a9b4', 'Find the genre with highest average movie rating. ...', 'Find the genre with highest average movie rating. Show genre_name and avg_rating.', 'movies', 'Medium', 15, 'SELECT g.name AS genre_name, ROUND(AVG(m.rating), 2) AS avg_rating FROM genres g JOIN movie_genres mg ON g.genre_id = mg.genre_id JOIN movies m ON mg.movie_id = m.movie_id GROUP BY g.genre_id ORDER BY avg_rating DESC LIMIT 1;'),
('ba8f38a2-92cf-46e3-948a-bc0ffeb429f2', 'Show actors who appeared in more than 2 movies. Sh...', 'Show actors who appeared in more than 2 movies. Show actor name and movie_count.', 'movies', 'Medium', 15, 'SELECT a.first_name || '' '' || a.last_name AS actor_name, COUNT(ma.movie_id) AS movie_count FROM actors a JOIN movie_actors ma ON a.actor_id = ma.actor_id GROUP BY a.actor_id HAVING COUNT(ma.movie_id) > 2 ORDER BY movie_count DESC;'),
('30cbd32e-6496-40c2-95fa-b975a833a445', 'Find movies that have no cast listed (no rows in m...', 'Find movies that have no cast listed (no rows in movie_actors). Show title and release_year.', 'movies', 'Medium', 15, 'SELECT m.title, m.release_year FROM movies m LEFT JOIN movie_actors ma ON m.movie_id = ma.movie_id WHERE ma.actor_id IS NULL;'),
('b62885cc-3090-4902-82f5-6d7bb60b8dfc', 'List total box office revenue per director (only m...', 'List total box office revenue per director (only movies with box_office data). Show director name and total_box_office.', 'movies', 'Medium', 15, 'SELECT d.first_name || '' '' || d.last_name AS director_name, SUM(m.box_office) AS total_box_office FROM directors d JOIN movies m ON d.director_id = m.director_id WHERE m.box_office IS NOT NULL GROUP BY d.director_id ORDER BY total_box_office DESC;'),
('2062a154-a1b5-49a4-b683-5ae611b6a224', 'Show the most prolific actor (most movies). Show a...', 'Show the most prolific actor (most movies). Show actor name and movie_count.', 'movies', 'Medium', 15, 'SELECT a.first_name || '' '' || a.last_name AS actor_name, COUNT(ma.movie_id) AS movie_count FROM actors a JOIN movie_actors ma ON a.actor_id = ma.actor_id GROUP BY a.actor_id ORDER BY movie_count DESC LIMIT 1;'),
('b7b7b7c7-f3ef-40f1-bbcb-eff3fa6e5279', 'Show each movie with its genres as a comma-aggrega...', 'Show each movie with its genres as a comma-aggregated list. Show title and genres.', 'movies', 'Medium', 15, 'SELECT m.title, GROUP_CONCAT(g.name, '', '') AS genres FROM movies m JOIN movie_genres mg ON m.movie_id = mg.movie_id JOIN genres g ON mg.genre_id = g.genre_id GROUP BY m.movie_id ORDER BY m.title;'),
('e5971542-8939-4c94-9a96-4996da31f03e', 'Find directors whose movies consistently rate abov...', 'Find directors whose movies consistently rate above 8.0 (all movies ≥ 8.0). Show director name.', 'movies', 'Medium', 15, 'SELECT d.first_name || '' '' || d.last_name AS director_name, COUNT(*) AS movies, MIN(m.rating) AS min_rating FROM directors d JOIN movies m ON d.director_id = m.director_id GROUP BY d.director_id HAVING MIN(m.rating) >= 8.0 ORDER BY min_rating DESC;'),
('bba1db67-bbbb-4349-b096-7c270f9f4d15', 'Show average budget and box office per genre. Show...', 'Show average budget and box office per genre. Show genre_name, avg_budget, avg_box_office.', 'movies', 'Medium', 15, 'SELECT g.name AS genre_name, ROUND(AVG(m.budget), 0) AS avg_budget, ROUND(AVG(m.box_office), 0) AS avg_box_office FROM genres g JOIN movie_genres mg ON g.genre_id = mg.genre_id JOIN movies m ON mg.movie_id = m.movie_id WHERE m.box_office IS NOT NULL GROUP BY g.genre_id ORDER BY avg_box_office DESC;'),
('aaf2f376-1fad-4302-a0d9-0c4735b4de2b', 'Show actors and the directors they worked with mos...', 'Show actors and the directors they worked with most. Show actor name, director name, collaboration_count.', 'movies', 'Medium', 15, 'SELECT a.first_name || '' '' || a.last_name AS actor_name, d.first_name || '' '' || d.last_name AS director_name, COUNT(*) AS collaboration_count FROM movie_actors ma JOIN movies m ON ma.movie_id = m.movie_id JOIN directors d ON m.director_id = d.director_id JOIN actors a ON ma.actor_id = a.actor_id GROUP BY ma.actor_id, m.director_id ORDER BY collaboration_count DESC;'),
('ac83f474-5030-41c1-b9b8-3cffc6d53252', 'Find movies that out-earned the average box office...', 'Find movies that out-earned the average box office. Show title, box_office, and how much above average.', 'movies', 'Medium', 15, 'SELECT title, box_office, ROUND(box_office - (SELECT AVG(box_office) FROM movies WHERE box_office IS NOT NULL), 0) AS above_avg FROM movies WHERE box_office > (SELECT AVG(box_office) FROM movies WHERE box_office IS NOT NULL) ORDER BY above_avg DESC;'),
('7fe99b17-e95f-4b5a-9813-4f4f1fe07cc0', 'Show box office decade trends: average box_office ...', 'Show box office decade trends: average box_office per decade. Show decade and avg_box_office.', 'movies', 'Medium', 15, 'SELECT (m.release_year / 10) * 10 AS decade, ROUND(AVG(m.box_office), 0) AS avg_box_office FROM movies m WHERE m.box_office IS NOT NULL GROUP BY decade ORDER BY decade;'),
('70b910ee-5d07-460e-99a5-489929b1428b', 'Find actors who have ONLY appeared in Crime movies...', 'Find actors who have ONLY appeared in Crime movies (all their movies are Crime genre). Show actor name.', 'movies', 'Medium', 15, 'SELECT a.first_name || '' '' || a.last_name AS actor_name FROM actors a JOIN movie_actors ma ON a.actor_id = ma.actor_id JOIN movie_genres mg ON ma.movie_id = mg.movie_id JOIN genres g ON mg.genre_id = g.genre_id GROUP BY a.actor_id HAVING SUM(CASE WHEN g.name = ''Crime'' THEN 1 ELSE 0 END) > 0 AND SUM(CASE WHEN g.name != ''Crime'' THEN 1 ELSE 0 END) = 0 ORDER BY actor_name;'),
('293bed13-370b-42c6-b245-175bd7a970e3', 'Rank movies by box_office within each genre using ...', 'Rank movies by box_office within each genre using DENSE_RANK. Show genre_name, title, box_office, and box_office_rank.', 'movies', 'Hard', 25, 'SELECT genre_name, title, box_office, box_office_rank FROM (SELECT g.name AS genre_name, m.title, m.box_office, DENSE_RANK() OVER (PARTITION BY g.genre_id ORDER BY m.box_office DESC) AS box_office_rank FROM genres g JOIN movie_genres mg ON g.genre_id = mg.genre_id JOIN movies m ON mg.movie_id = m.movie_id WHERE m.box_office IS NOT NULL) ORDER BY genre_name, box_office_rank;'),
('7b91cb20-e5a5-465b-a61c-10672e52b6ce', 'Show year-over-year average rating change per dire...', 'Show year-over-year average rating change per director. Show director_name, year, avg_rating, prev_year_avg, change.', 'movies', 'Hard', 25, 'WITH yearly AS (SELECT m.director_id, m.release_year AS year, ROUND(AVG(m.rating), 2) AS avg_rating FROM movies m GROUP BY m.director_id, m.release_year) SELECT d.first_name || '' '' || d.last_name AS director_name, y.year, y.avg_rating, LAG(y.avg_rating) OVER (PARTITION BY y.director_id ORDER BY y.year) AS prev_year_avg, ROUND(y.avg_rating - LAG(y.avg_rating) OVER (PARTITION BY y.director_id ORDER BY y.year), 2) AS change FROM yearly y JOIN directors d ON y.director_id = d.director_id ORDER BY director_name, year;'),
('4b91222c-0473-47df-be11-f7c05e31bff3', 'Calculate each movie''s box office share as a % of ...', 'Calculate each movie''s box office share as a % of its director''s total box office. Show director_name, title, box_office, and pct_of_director_total.', 'movies', 'Hard', 25, 'SELECT d.first_name || '' '' || d.last_name AS director_name, m.title, m.box_office, ROUND(100.0 * m.box_office / SUM(m.box_office) OVER (PARTITION BY m.director_id), 1) AS pct_of_director_total FROM movies m JOIN directors d ON m.director_id = d.director_id WHERE m.box_office IS NOT NULL ORDER BY director_name, pct_of_director_total DESC;'),
('319e9377-f660-49a9-b033-037b52824090', 'Find actor pairs who appeared in the same movies (...', 'Find actor pairs who appeared in the same movies (co-stars). Show actor1_name, actor2_name, and shared_movies count. Only show pairs with 2+ shared movies.', 'movies', 'Hard', 25, 'SELECT a1.first_name || '' '' || a1.last_name AS actor1_name, a2.first_name || '' '' || a2.last_name AS actor2_name, COUNT(*) AS shared_movies FROM movie_actors ma1 JOIN movie_actors ma2 ON ma1.movie_id = ma2.movie_id AND ma1.actor_id < ma2.actor_id JOIN actors a1 ON ma1.actor_id = a1.actor_id JOIN actors a2 ON ma2.actor_id = a2.actor_id GROUP BY ma1.actor_id, ma2.actor_id HAVING COUNT(*) >= 2 ORDER BY shared_movies DESC;'),
('2b279217-8256-47b7-9740-e4e3954c01cc', 'Find the highest-rated movie per director using RO...', 'Find the highest-rated movie per director using ROW_NUMBER(). Show director_name, title, rating, rn where rn=1.', 'movies', 'Hard', 25, 'SELECT director_name, title, rating FROM (SELECT d.first_name || '' '' || d.last_name AS director_name, m.title, m.rating, ROW_NUMBER() OVER (PARTITION BY m.director_id ORDER BY m.rating DESC) AS rn FROM movies m JOIN directors d ON m.director_id = d.director_id) WHERE rn = 1 ORDER BY rating DESC;'),
('e83d7094-a746-4d21-a207-2441050d4b19', 'Calculate cumulative box office revenue in chronol...', 'Calculate cumulative box office revenue in chronological order by release year. Show release_year, year_revenue, and cumulative_revenue.', 'movies', 'Hard', 25, 'WITH yearly AS (SELECT release_year, SUM(box_office) AS year_revenue FROM movies WHERE box_office IS NOT NULL GROUP BY release_year) SELECT release_year, year_revenue, SUM(year_revenue) OVER (ORDER BY release_year ROWS UNBOUNDED PRECEDING) AS cumulative_revenue FROM yearly ORDER BY release_year;'),
('3f9ccdb1-f4e2-4f53-a7ab-b1878aa4a410', 'Use NTILE(4) to categorize movies by ROI (return o...', 'Use NTILE(4) to categorize movies by ROI (return on investment). Show title, roi, and roi_quartile.', 'movies', 'Hard', 25, 'SELECT title, ROUND((box_office - budget) / budget, 2) AS roi, NTILE(4) OVER (ORDER BY (box_office - budget) / budget DESC) AS roi_quartile FROM movies WHERE box_office IS NOT NULL ORDER BY roi_quartile, roi DESC;'),
('0794acd6-ffce-4864-8949-78a1c53ae937', 'Show each movie and the next movie chronologically...', 'Show each movie and the next movie chronologically (LEAD on release_year, ORDER BY release_year). Show title, release_year, and next_movie_title.', 'movies', 'Hard', 25, 'SELECT title, release_year, LEAD(title) OVER (ORDER BY release_year, movie_id) AS next_movie_title FROM movies ORDER BY release_year;'),
('3f421456-c3b5-4441-bb93-68d99e5d8de1', 'Find the director with the highest average ROI acr...', 'Find the director with the highest average ROI across all their movies. Show director_name and avg_roi.', 'movies', 'Hard', 25, 'SELECT director_name, avg_roi FROM (SELECT d.first_name || '' '' || d.last_name AS director_name, ROUND(AVG((m.box_office - m.budget) * 1.0 / m.budget), 2) AS avg_roi FROM directors d JOIN movies m ON d.director_id = m.director_id WHERE m.box_office IS NOT NULL GROUP BY d.director_id) ORDER BY avg_roi DESC LIMIT 1;'),
('db0df0c0-7021-4a0b-9e42-dbb8cbf3fa00', 'Build a movie industry scorecard: for each movie s...', 'Build a movie industry scorecard: for each movie show title, rating, roi, rating_rank, roi_rank, and composite_rank (AVG of both ranks).', 'movies', 'Hard', 25, 'WITH scores AS (SELECT m.title, m.rating, ROUND((m.box_office - m.budget) * 1.0 / m.budget, 2) AS roi FROM movies m WHERE m.box_office IS NOT NULL), ranked AS (SELECT title, rating, roi, RANK() OVER (ORDER BY rating DESC) AS rating_rank, RANK() OVER (ORDER BY roi DESC) AS roi_rank FROM scores) SELECT title, rating, roi, rating_rank, roi_rank, ROUND((rating_rank + roi_rank) / 2.0, 0) AS composite_rank FROM ranked ORDER BY composite_rank;'),
('0adaa994-1f10-4567-a25d-42f4a5d0e8fe', 'Show budget efficiency over time: for each directo...', 'Show budget efficiency over time: for each director, show their movies in order and whether each subsequent movie had a higher ROI than the previous one. Show director_name, title, roi, prev_roi, improved.', 'movies', 'Hard', 25, 'WITH roi AS (SELECT m.movie_id, m.director_id, m.title, m.release_year, ROUND((m.box_office - m.budget) * 1.0 / m.budget, 2) AS roi FROM movies m WHERE m.box_office IS NOT NULL) SELECT d.first_name || '' '' || d.last_name AS director_name, r.title, r.roi, LAG(r.roi) OVER (PARTITION BY r.director_id ORDER BY r.release_year) AS prev_roi, CASE WHEN r.roi > LAG(r.roi) OVER (PARTITION BY r.director_id ORDER BY r.release_year) THEN ''Yes'' ELSE ''No'' END AS improved FROM roi r JOIN directors d ON r.director_id = d.director_id ORDER BY director_name, r.release_year;'),
('8133b950-f32b-4fd9-93f7-484b4a9a3cd1', 'Compute a 3-movie rolling average rating for each ...', 'Compute a 3-movie rolling average rating for each director (ordered by release year). Show director_name, title, release_year, rating, and rolling_avg_rating.', 'movies', 'Hard', 25, 'SELECT d.first_name || '' '' || d.last_name AS director_name, m.title, m.release_year, m.rating, ROUND(AVG(m.rating) OVER (PARTITION BY m.director_id ORDER BY m.release_year ROWS BETWEEN 2 PRECEDING AND CURRENT ROW), 2) AS rolling_avg_rating FROM movies m JOIN directors d ON m.director_id = d.director_id ORDER BY director_name, m.release_year;'),
('f2777212-c3ee-4a30-95a8-bc99af2776a2', 'Show a genre performance matrix: for each genre sh...', 'Show a genre performance matrix: for each genre show avg_rating, avg_roi, total_movies, and rank genres by avg_rating using RANK(). Show genre_name, avg_rating, avg_roi, total_movies, rating_rank.', 'movies', 'Hard', 25, 'SELECT genre_name, avg_rating, avg_roi, total_movies, RANK() OVER (ORDER BY avg_rating DESC) AS rating_rank FROM (SELECT g.name AS genre_name, ROUND(AVG(m.rating), 2) AS avg_rating, ROUND(AVG(CASE WHEN m.box_office IS NOT NULL THEN (m.box_office - m.budget) * 1.0 / m.budget ELSE NULL END), 2) AS avg_roi, COUNT(DISTINCT m.movie_id) AS total_movies FROM genres g JOIN movie_genres mg ON g.genre_id = mg.genre_id JOIN movies m ON mg.movie_id = m.movie_id GROUP BY g.genre_id) ORDER BY rating_rank;'),
('161ccc07-2407-4681-a3bd-b98d9a16d463', 'Find the top genre of each year (by average rating...', 'Find the top genre of each year (by average rating). Show release_year, genre_name, avg_rating where it is the top genre for that year.', 'movies', 'Hard', 25, 'SELECT release_year, genre_name, avg_rating FROM (SELECT m.release_year, g.name AS genre_name, ROUND(AVG(m.rating), 2) AS avg_rating, ROW_NUMBER() OVER (PARTITION BY m.release_year ORDER BY AVG(m.rating) DESC) AS rn FROM movies m JOIN movie_genres mg ON m.movie_id = mg.movie_id JOIN genres g ON mg.genre_id = g.genre_id GROUP BY m.release_year, g.genre_id) WHERE rn = 1 ORDER BY release_year;'),
('59224da6-0a3b-4e3d-9831-265d94adcd84', 'Calculate a director''s "batting average" - their %...', 'Calculate a director''s "batting average" - their % of movies with rating ≥ 8.0. Show director_name, total_movies, high_rated_movies, and batting_avg_pct. Rank by batting_avg_pct DESC.', 'movies', 'Hard', 25, 'SELECT d.first_name || '' '' || d.last_name AS director_name, COUNT(*) AS total_movies, SUM(CASE WHEN m.rating >= 8.0 THEN 1 ELSE 0 END) AS high_rated_movies, ROUND(100.0 * SUM(CASE WHEN m.rating >= 8.0 THEN 1 ELSE 0 END) / COUNT(*), 1) AS batting_avg_pct FROM directors d JOIN movies m ON d.director_id = m.director_id GROUP BY d.director_id HAVING COUNT(*) >= 2 ORDER BY batting_avg_pct DESC;');
INSERT INTO public.questions (id, title, prompt, schema_name, difficulty, estimated_time_minutes, solution_sql) VALUES
('4909ab11-5852-4f6b-9a10-b269fa0df2ad', 'List all artists with name, genre, and country, or...', 'List all artists with name, genre, and country, ordered by name.', 'music', 'Easy', 5, 'SELECT name, genre, country FROM artists ORDER BY name;'),
('b6242c94-dd28-4695-abf3-6f01d977b24d', 'Find all Pop artists. Show name and country....', 'Find all Pop artists. Show name and country.', 'music', 'Easy', 5, 'SELECT name, country FROM artists WHERE genre LIKE ''%Pop%'' ORDER BY name;'),
('af16a07f-3249-4db0-a355-d09c16330078', 'List all albums with title, artist_id, and release...', 'List all albums with title, artist_id, and release_year, ordered by release_year DESC.', 'music', 'Easy', 5, 'SELECT title, artist_id, release_year FROM albums ORDER BY release_year DESC;'),
('bbc2ee96-2815-4ddc-958a-a5c06081203a', 'Count albums per artist. Show artist_id and album_...', 'Count albums per artist. Show artist_id and album_count.', 'music', 'Easy', 5, 'SELECT artist_id, COUNT(*) AS album_count FROM albums GROUP BY artist_id ORDER BY album_count DESC;'),
('7318dfb6-7394-4171-a37d-31ca2fd7a161', 'List the top 5 longest tracks by duration. Show ti...', 'List the top 5 longest tracks by duration. Show title and duration_secs.', 'music', 'Easy', 5, 'SELECT title, duration_secs FROM tracks ORDER BY duration_secs DESC LIMIT 5;'),
('a8c28026-15a9-4488-9c6b-17c805824146', 'Count tracks per album. Show album_id and track_co...', 'Count tracks per album. Show album_id and track_count.', 'music', 'Easy', 5, 'SELECT album_id, COUNT(*) AS track_count FROM tracks GROUP BY album_id ORDER BY track_count DESC;'),
('914bda10-7340-45e4-a6b2-5593dae4dead', 'List all users with username and country, ordered ...', 'List all users with username and country, ordered by joined_at DESC.', 'music', 'Easy', 5, 'SELECT username, country, joined_at FROM users ORDER BY joined_at DESC;'),
('733bce5e-279b-4ca4-9852-6b218ae6d6a5', 'Count total plays in the database. Return total_pl...', 'Count total plays in the database. Return total_plays.', 'music', 'Easy', 5, 'SELECT COUNT(*) AS total_plays FROM plays;'),
('4d424f86-5a46-44c6-ad73-80df178b294f', 'Count plays per user. Show user_id and play_count....', 'Count plays per user. Show user_id and play_count.', 'music', 'Easy', 5, 'SELECT user_id, COUNT(*) AS play_count FROM plays GROUP BY user_id ORDER BY play_count DESC;'),
('14fc320c-9008-4e73-90d9-a650c0da075c', 'Find all tracks with BPM above 130 (energetic song...', 'Find all tracks with BPM above 130 (energetic songs). Show title and bpm.', 'music', 'Easy', 5, 'SELECT title, bpm FROM tracks WHERE bpm > 130 ORDER BY bpm DESC;'),
('ce1e29b7-b3cc-4331-bd8c-cde6898ac4a6', 'Count how many playlists each user has. Show user_...', 'Count how many playlists each user has. Show user_id and playlist_count.', 'music', 'Easy', 5, 'SELECT user_id, COUNT(*) AS playlist_count FROM playlists GROUP BY user_id ORDER BY playlist_count DESC;'),
('82bc6ce2-b537-42e6-9a1b-fcbef5bf32ea', 'Find all public playlists (is_public = 1). Show na...', 'Find all public playlists (is_public = 1). Show name and user_id.', 'music', 'Easy', 5, 'SELECT name, user_id FROM playlists WHERE is_public = 1;'),
('6b8f47cf-e354-413e-9eac-1af9367f1073', 'Count how many tracks are in each playlist. Show p...', 'Count how many tracks are in each playlist. Show playlist_id and track_count.', 'music', 'Easy', 5, 'SELECT playlist_id, COUNT(*) AS track_count FROM playlist_tracks GROUP BY playlist_id ORDER BY track_count DESC;'),
('5cfb5c0d-8cf0-4ce3-a8a3-f7a01ebca22a', 'Find all albums released before 2010. Show title a...', 'Find all albums released before 2010. Show title and release_year.', 'music', 'Easy', 5, 'SELECT title, release_year FROM albums WHERE release_year < 2010 ORDER BY release_year;'),
('3778a622-2adb-4888-9b46-ad23c86b4768', 'Calculate total listening time across all plays (s...', 'Calculate total listening time across all plays (sum of play_duration_secs). Return total_seconds.', 'music', 'Easy', 5, 'SELECT SUM(play_duration_secs) AS total_seconds FROM plays;'),
('f0d0af0f-4ae3-4c64-9dd8-ce1339f529d6', 'Count plays per track. Show track_id and play_coun...', 'Count plays per track. Show track_id and play_count, ordered by play_count DESC.', 'music', 'Easy', 5, 'SELECT track_id, COUNT(*) AS play_count FROM plays GROUP BY track_id ORDER BY play_count DESC;'),
('d4914d96-d2b6-421e-80fc-c259e604d213', 'Find tracks with slow BPM (under 70). Show title, ...', 'Find tracks with slow BPM (under 70). Show title, album_id, and bpm.', 'music', 'Easy', 5, 'SELECT title, album_id, bpm FROM tracks WHERE bpm < 70 ORDER BY bpm;'),
('80b03fb8-7946-4e59-98fb-544026200f44', 'Count plays per date. Show DATE(played_at) and dai...', 'Count plays per date. Show DATE(played_at) and daily_plays.', 'music', 'Easy', 5, 'SELECT DATE(played_at) AS play_date, COUNT(*) AS daily_plays FROM plays GROUP BY play_date ORDER BY play_date;'),
('49b3d286-12d1-4c4d-ba96-48ba5c2cd605', 'Find all UK artists. Show name and genre....', 'Find all UK artists. Show name and genre.', 'music', 'Easy', 5, 'SELECT name, genre FROM artists WHERE country = ''UK'' ORDER BY name;'),
('447328f8-ed10-4103-b10b-eabed237f378', 'Show the shortest track. Return title and duration...', 'Show the shortest track. Return title and duration_secs.', 'music', 'Easy', 5, 'SELECT title, duration_secs FROM tracks ORDER BY duration_secs ASC LIMIT 1;'),
('ac0bea8d-1b64-4b47-aa48-9b6fa2bea668', 'Show each track with its album title and artist na...', 'Show each track with its album title and artist name. Show track title, album title, and artist name.', 'music', 'Medium', 15, 'SELECT t.title AS track_title, al.title AS album_title, ar.name AS artist_name FROM tracks t JOIN albums al ON t.album_id = al.album_id JOIN artists ar ON al.artist_id = ar.artist_id ORDER BY ar.name, al.title;'),
('2d4011e2-af27-4869-8db0-9c9eb2bf3ae4', 'Calculate total play count per artist. Show artist...', 'Calculate total play count per artist. Show artist_name and total_plays.', 'music', 'Medium', 15, 'SELECT ar.name AS artist_name, COUNT(p.play_id) AS total_plays FROM artists ar JOIN albums al ON ar.artist_id = al.artist_id JOIN tracks t ON al.album_id = t.album_id JOIN plays p ON t.track_id = p.track_id GROUP BY ar.artist_id ORDER BY total_plays DESC;'),
('defc500b-9b96-4e5e-acf5-3283829523c5', 'Show each user''s total listening time in hours. Sh...', 'Show each user''s total listening time in hours. Show username and total_hours.', 'music', 'Medium', 15, 'SELECT u.username, ROUND(SUM(p.play_duration_secs) / 3600.0, 2) AS total_hours FROM users u JOIN plays p ON u.user_id = p.user_id GROUP BY u.user_id ORDER BY total_hours DESC;'),
('34a120d7-6878-4909-bdc9-affcdc0a3dfe', 'Find the most-played track. Show title, artist_nam...', 'Find the most-played track. Show title, artist_name, and play_count.', 'music', 'Medium', 15, 'SELECT t.title, ar.name AS artist_name, COUNT(p.play_id) AS play_count FROM tracks t JOIN albums al ON t.album_id = al.album_id JOIN artists ar ON al.artist_id = ar.artist_id JOIN plays p ON t.track_id = p.track_id GROUP BY t.track_id ORDER BY play_count DESC LIMIT 1;'),
('71c409ff-7fd0-41ef-b4a7-71323c9800b2', 'Find tracks that have never been played. Show titl...', 'Find tracks that have never been played. Show title and album_id.', 'music', 'Medium', 15, 'SELECT t.title, t.album_id FROM tracks t LEFT JOIN plays p ON t.track_id = p.track_id WHERE p.play_id IS NULL;'),
('abe2018d-df1a-4746-89ce-04f398b96615', 'Show the most popular genre by total plays. Show g...', 'Show the most popular genre by total plays. Show genre and play_count.', 'music', 'Medium', 15, 'SELECT ar.genre, COUNT(p.play_id) AS play_count FROM artists ar JOIN albums al ON ar.artist_id = al.artist_id JOIN tracks t ON al.album_id = t.album_id JOIN plays p ON t.track_id = p.track_id GROUP BY ar.genre ORDER BY play_count DESC;'),
('4a1c5221-e48a-4118-84bf-e045f1be7356', 'Show average BPM per genre across all tracks. Show...', 'Show average BPM per genre across all tracks. Show genre and avg_bpm.', 'music', 'Medium', 15, 'SELECT ar.genre, ROUND(AVG(t.bpm), 1) AS avg_bpm FROM artists ar JOIN albums al ON ar.artist_id = al.artist_id JOIN tracks t ON al.album_id = t.album_id GROUP BY ar.genre ORDER BY avg_bpm DESC;'),
('27b107cb-cfdc-4f01-b656-e67f455c7e43', 'Find the playlist with the most tracks. Show playl...', 'Find the playlist with the most tracks. Show playlist name and track_count.', 'music', 'Medium', 15, 'SELECT pl.name, COUNT(pt.track_id) AS track_count FROM playlists pl JOIN playlist_tracks pt ON pl.playlist_id = pt.playlist_id GROUP BY pl.playlist_id ORDER BY track_count DESC LIMIT 1;'),
('c311a696-56ad-4509-b758-3f9ff4ad3b53', 'Calculate play count per hour of day. Show hour an...', 'Calculate play count per hour of day. Show hour and play_count.', 'music', 'Medium', 15, 'SELECT strftime(''%H'', played_at) AS hour, COUNT(*) AS play_count FROM plays GROUP BY hour ORDER BY hour;'),
('51bfad43-9f0b-4d4f-b02d-3d556a5a88f9', 'Show total album duration per artist (sum of all t...', 'Show total album duration per artist (sum of all track durations). Show artist_name and total_duration_mins.', 'music', 'Medium', 15, 'SELECT ar.name AS artist_name, ROUND(SUM(t.duration_secs) / 60.0, 1) AS total_duration_mins FROM artists ar JOIN albums al ON ar.artist_id = al.artist_id JOIN tracks t ON al.album_id = t.album_id GROUP BY ar.artist_id ORDER BY total_duration_mins DESC;'),
('68ff6ab7-f962-4f5f-bfef-0db08c0f1723', 'Show the completion rate per track play (play_dura...', 'Show the completion rate per track play (play_duration / track_duration × 100). Show track_title and avg_completion_pct.', 'music', 'Medium', 15, 'SELECT t.title AS track_title, ROUND(AVG(p.play_duration_secs * 100.0 / t.duration_secs), 1) AS avg_completion_pct FROM tracks t JOIN plays p ON t.track_id = p.track_id GROUP BY t.track_id ORDER BY avg_completion_pct DESC;'),
('69ab5ac4-a685-48e2-a622-3a82eb81c57b', 'Find users who listen to 3+ different artists. Sho...', 'Find users who listen to 3+ different artists. Show username and artist_count.', 'music', 'Medium', 15, 'SELECT u.username, COUNT(DISTINCT al.artist_id) AS artist_count FROM users u JOIN plays p ON u.user_id = p.user_id JOIN tracks t ON p.track_id = t.track_id JOIN albums al ON t.album_id = al.album_id GROUP BY u.user_id HAVING COUNT(DISTINCT al.artist_id) >= 3 ORDER BY artist_count DESC;'),
('153c0b94-7d70-4544-b933-28f98cab144e', 'Show the top artist per user (most plays). Show us...', 'Show the top artist per user (most plays). Show username and artist_name.', 'music', 'Medium', 15, 'SELECT username, artist_name FROM (SELECT u.username, ar.name AS artist_name, COUNT(p.play_id) AS play_count, ROW_NUMBER() OVER (PARTITION BY u.user_id ORDER BY COUNT(p.play_id) DESC) AS rn FROM users u JOIN plays p ON u.user_id = p.user_id JOIN tracks t ON p.track_id = t.track_id JOIN albums al ON t.album_id = al.album_id JOIN artists ar ON al.artist_id = ar.artist_id GROUP BY u.user_id, ar.artist_id) WHERE rn = 1 ORDER BY username;'),
('c3f9499b-7ca5-42a2-afbb-201c4403845d', 'Show plays by country. Show country and total_play...', 'Show plays by country. Show country and total_plays.', 'music', 'Medium', 15, 'SELECT u.country, COUNT(p.play_id) AS total_plays FROM users u JOIN plays p ON u.user_id = p.user_id GROUP BY u.country ORDER BY total_plays DESC;'),
('1e3197d9-56e8-4cf8-b8b6-b110e7eeca65', 'Find playlists where the combined track duration e...', 'Find playlists where the combined track duration exceeds 15 minutes. Show playlist_name and total_duration_mins.', 'music', 'Medium', 15, 'SELECT pl.name AS playlist_name, ROUND(SUM(t.duration_secs) / 60.0, 1) AS total_duration_mins FROM playlists pl JOIN playlist_tracks pt ON pl.playlist_id = pt.playlist_id JOIN tracks t ON pt.track_id = t.track_id GROUP BY pl.playlist_id HAVING SUM(t.duration_secs) / 60.0 > 15 ORDER BY total_duration_mins DESC;'),
('97cc2fbd-d3d5-4484-af77-4ed92a1020bd', 'Find tracks that have been played more than the av...', 'Find tracks that have been played more than the average plays per track. Show title and play_count.', 'music', 'Medium', 15, 'SELECT t.title, COUNT(p.play_id) AS play_count FROM tracks t JOIN plays p ON t.track_id = p.track_id GROUP BY t.track_id HAVING COUNT(p.play_id) > (SELECT AVG(cnt) FROM (SELECT COUNT(*) AS cnt FROM plays GROUP BY track_id)) ORDER BY play_count DESC;'),
('83478c9d-dcb1-4e81-9e7d-d593957fd636', 'Show the ratio of Hip-Hop plays to Pop plays per u...', 'Show the ratio of Hip-Hop plays to Pop plays per user. Show user_id and hip_hop_to_pop_ratio.', 'music', 'Medium', 15, 'SELECT u.user_id, ROUND(CAST(SUM(CASE WHEN ar.genre LIKE ''%Hip-Hop%'' THEN 1 ELSE 0 END) AS REAL) / NULLIF(SUM(CASE WHEN ar.genre LIKE ''%Pop%'' AND ar.genre NOT LIKE ''%Hip-Hop%'' THEN 1 ELSE 0 END), 0), 2) AS hip_hop_to_pop_ratio FROM users u JOIN plays p ON u.user_id = p.user_id JOIN tracks t ON p.track_id = t.track_id JOIN albums al ON t.album_id = al.album_id JOIN artists ar ON al.artist_id = ar.artist_id GROUP BY u.user_id ORDER BY hip_hop_to_pop_ratio DESC;'),
('bf5d8c9a-f8e1-4b1f-8b61-16003d7e951b', 'Show plays per album per user (how many different ...', 'Show plays per album per user (how many different albums each user played). Show username and albums_played.', 'music', 'Medium', 15, 'SELECT u.username, COUNT(DISTINCT t.album_id) AS albums_played FROM users u JOIN plays p ON u.user_id = p.user_id JOIN tracks t ON p.track_id = t.track_id GROUP BY u.user_id ORDER BY albums_played DESC;'),
('94483634-9b14-49da-9ee3-60172f767de3', 'Find the most productive year for album releases. ...', 'Find the most productive year for album releases. Show release_year and album_count.', 'music', 'Medium', 15, 'SELECT release_year, COUNT(*) AS album_count FROM albums GROUP BY release_year ORDER BY album_count DESC LIMIT 1;'),
('96fc27b8-36ed-42d5-a6e2-eef0b5d21c77', 'Show the average track count per album by genre. S...', 'Show the average track count per album by genre. Show genre and avg_tracks_per_album.', 'music', 'Medium', 15, 'WITH album_tracks AS (SELECT al.album_id, al.genre, COUNT(t.track_id) AS track_count FROM albums al JOIN tracks t ON al.album_id = t.album_id GROUP BY al.album_id) SELECT genre, ROUND(AVG(track_count), 1) AS avg_tracks_per_album FROM album_tracks GROUP BY genre ORDER BY avg_tracks_per_album DESC;'),
('27d51f9f-2f12-47e4-8f65-acf5200fee60', 'Rank tracks by play count using DENSE_RANK. Show t...', 'Rank tracks by play count using DENSE_RANK. Show title, play_count, and play_rank.', 'music', 'Hard', 25, 'SELECT title, play_count, DENSE_RANK() OVER (ORDER BY play_count DESC) AS play_rank FROM (SELECT t.title, COUNT(p.play_id) AS play_count FROM tracks t LEFT JOIN plays p ON t.track_id = p.track_id GROUP BY t.track_id) ORDER BY play_rank;'),
('ca90ab6d-8abd-4eec-8d30-df5c6c4a33e1', 'Show month-over-month play count change. Show mont...', 'Show month-over-month play count change. Show month, monthly_plays, prev_month_plays, and change.', 'music', 'Hard', 25, 'WITH monthly AS (SELECT strftime(''%Y-%m'', played_at) AS month, COUNT(*) AS monthly_plays FROM plays GROUP BY month) SELECT month, monthly_plays, LAG(monthly_plays) OVER (ORDER BY month) AS prev_month_plays, monthly_plays - LAG(monthly_plays) OVER (ORDER BY month) AS change FROM monthly ORDER BY month;'),
('9bfcebcc-92cf-4a33-ae30-a1188dc3dc02', 'Find the most played track per user using ROW_NUMB...', 'Find the most played track per user using ROW_NUMBER(). Show username, track_title, play_count where rn=1.', 'music', 'Hard', 25, 'SELECT username, track_title, play_count FROM (SELECT u.username, t.title AS track_title, COUNT(p.play_id) AS play_count, ROW_NUMBER() OVER (PARTITION BY u.user_id ORDER BY COUNT(p.play_id) DESC) AS rn FROM users u JOIN plays p ON u.user_id = p.user_id JOIN tracks t ON p.track_id = t.track_id GROUP BY u.user_id, t.track_id) WHERE rn = 1 ORDER BY username;'),
('1af425ca-91ed-4dc5-adb7-75848f4624e3', 'Calculate running play count per user (cumulative ...', 'Calculate running play count per user (cumulative plays over time). Show user_id, played_at, and cumulative_plays.', 'music', 'Hard', 25, 'SELECT user_id, played_at, ROW_NUMBER() OVER (PARTITION BY user_id ORDER BY played_at) AS cumulative_plays FROM plays ORDER BY user_id, played_at;'),
('560c35ff-0519-482f-beab-b772dea0b043', 'Calculate each artist''s share of total plays as a ...', 'Calculate each artist''s share of total plays as a percentage. Show artist_name, play_count, and pct_of_total.', 'music', 'Hard', 25, 'SELECT artist_name, play_count, ROUND(100.0 * play_count / SUM(play_count) OVER (), 2) AS pct_of_total FROM (SELECT ar.name AS artist_name, COUNT(p.play_id) AS play_count FROM artists ar JOIN albums al ON ar.artist_id = al.artist_id JOIN tracks t ON al.album_id = t.album_id JOIN plays p ON t.track_id = p.track_id GROUP BY ar.artist_id) ORDER BY play_count DESC;'),
('da1a7c03-31b1-49e6-b5b3-8a319b3572a0', 'Show listening session gaps per user: time between...', 'Show listening session gaps per user: time between consecutive plays. Show user_id, played_at, next_played_at, and gap_minutes.', 'music', 'Hard', 25, 'SELECT user_id, played_at, LEAD(played_at) OVER (PARTITION BY user_id ORDER BY played_at) AS next_played_at, ROUND((julianday(LEAD(played_at) OVER (PARTITION BY user_id ORDER BY played_at)) - julianday(played_at)) * 1440, 1) AS gap_minutes FROM plays ORDER BY user_id, played_at;'),
('bf2a0019-bd6d-4e94-ad34-e72a4bec3d12', 'Find the fastest-growing track (most plays in 2024...', 'Find the fastest-growing track (most plays in 2024-02 vs 2024-01). Show title, jan_plays, feb_plays, and growth.', 'music', 'Hard', 25, 'WITH monthly AS (SELECT p.track_id, SUM(CASE WHEN strftime(''%Y-%m'', p.played_at) = ''2024-01'' THEN 1 ELSE 0 END) AS jan_plays, SUM(CASE WHEN strftime(''%Y-%m'', p.played_at) = ''2024-02'' THEN 1 ELSE 0 END) AS feb_plays FROM plays p GROUP BY p.track_id) SELECT t.title, m.jan_plays, m.feb_plays, m.feb_plays - m.jan_plays AS growth FROM monthly m JOIN tracks t ON m.track_id = t.track_id ORDER BY growth DESC;'),
('0073a1be-5330-4ee1-8023-5c5909c58e63', 'Calculate listening diversity score per user: rati...', 'Calculate listening diversity score per user: ratio of unique tracks to total plays. Show username, total_plays, unique_tracks, diversity_score.', 'music', 'Hard', 25, 'SELECT u.username, COUNT(p.play_id) AS total_plays, COUNT(DISTINCT p.track_id) AS unique_tracks, ROUND(100.0 * COUNT(DISTINCT p.track_id) / COUNT(p.play_id), 1) AS diversity_score FROM users u JOIN plays p ON u.user_id = p.user_id GROUP BY u.user_id ORDER BY diversity_score DESC;'),
('379da6bf-9e11-4ff3-8426-b854ff78ab53', 'Use NTILE(3) to segment tracks into tiers by play ...', 'Use NTILE(3) to segment tracks into tiers by play count. Show title, play_count, and tier (1=most played, 3=least played).', 'music', 'Hard', 25, 'SELECT title, play_count, NTILE(3) OVER (ORDER BY play_count DESC) AS tier FROM (SELECT t.title, COUNT(p.play_id) AS play_count FROM tracks t LEFT JOIN plays p ON t.track_id = p.track_id GROUP BY t.track_id) ORDER BY tier, play_count DESC;'),
('f9768cb3-cfec-410c-8cbf-d5db37be8f6c', 'Identify users who exclusively listen to one genre...', 'Identify users who exclusively listen to one genre (all their plays are from one genre). Show username and genre.', 'music', 'Hard', 25, 'SELECT u.username, MAX(ar.genre) AS genre FROM users u JOIN plays p ON u.user_id = p.user_id JOIN tracks t ON p.track_id = t.track_id JOIN albums al ON t.album_id = al.album_id JOIN artists ar ON al.artist_id = ar.artist_id GROUP BY u.user_id HAVING COUNT(DISTINCT ar.genre) = 1 ORDER BY username;'),
('f404745f-4bba-43bc-8234-c28f7ca5cc7a', 'Calculate a 3-day rolling average of plays. Show p...', 'Calculate a 3-day rolling average of plays. Show play_date, daily_plays, and rolling_avg_3day.', 'music', 'Hard', 25, 'WITH daily AS (SELECT DATE(played_at) AS play_date, COUNT(*) AS daily_plays FROM plays GROUP BY DATE(played_at)) SELECT play_date, daily_plays, ROUND(AVG(daily_plays) OVER (ORDER BY play_date ROWS BETWEEN 2 PRECEDING AND CURRENT ROW), 1) AS rolling_avg_3day FROM daily ORDER BY play_date;'),
('1013fd73-c499-4b57-afe7-e56110e1b87c', 'For each user, show their first ever played track ...', 'For each user, show their first ever played track and their most recent (using FIRST_VALUE and LAST_VALUE / ROW_NUMBER). Show username, first_track, and latest_track.', 'music', 'Hard', 25, 'WITH first_play AS (SELECT user_id, track_id FROM (SELECT user_id, track_id, ROW_NUMBER() OVER (PARTITION BY user_id ORDER BY played_at ASC) AS rn FROM plays) WHERE rn = 1), last_play AS (SELECT user_id, track_id FROM (SELECT user_id, track_id, ROW_NUMBER() OVER (PARTITION BY user_id ORDER BY played_at DESC) AS rn FROM plays) WHERE rn = 1) SELECT u.username, tf.title AS first_track, tl.title AS latest_track FROM users u JOIN first_play fp ON u.user_id = fp.user_id JOIN last_play lp ON u.user_id = lp.user_id JOIN tracks tf ON fp.track_id = tf.track_id JOIN tracks tl ON lp.track_id = tl.track_id ORDER BY u.username;'),
('d1658e4d-2101-465b-afb5-19e0111edf95', 'Build a music recommendation score: for each track...', 'Build a music recommendation score: for each track, score = play_count × 10 + avg_completion_pct × 5. Show title, play_count, avg_completion_pct, recommendation_score, and rank.', 'music', 'Hard', 25, 'WITH plays_data AS (SELECT p.track_id, COUNT(*) AS play_count, ROUND(AVG(p.play_duration_secs * 100.0 / t.duration_secs), 1) AS avg_completion_pct FROM plays p JOIN tracks t ON p.track_id = t.track_id GROUP BY p.track_id) SELECT t.title, pd.play_count, pd.avg_completion_pct, ROUND(pd.play_count * 10 + pd.avg_completion_pct * 5, 1) AS recommendation_score, RANK() OVER (ORDER BY pd.play_count * 10 + pd.avg_completion_pct * 5 DESC) AS rec_rank FROM tracks t JOIN plays_data pd ON t.track_id = pd.track_id ORDER BY rec_rank;'),
('f53673a6-d0de-4488-a066-bb0366dd7185', 'Compute artist market share growth: compare each a...', 'Compute artist market share growth: compare each artist''s play share in Jan vs Feb 2024. Show artist_name, jan_pct, feb_pct, and growth_pct.', 'music', 'Hard', 25, 'WITH monthly AS (SELECT al.artist_id, SUM(CASE WHEN strftime(''%Y-%m'', p.played_at) = ''2024-01'' THEN 1 ELSE 0 END) AS jan_plays, SUM(CASE WHEN strftime(''%Y-%m'', p.played_at) = ''2024-02'' THEN 1 ELSE 0 END) AS feb_plays FROM plays p JOIN tracks t ON p.track_id = t.track_id JOIN albums al ON t.album_id = al.album_id GROUP BY al.artist_id), totals AS (SELECT SUM(CASE WHEN strftime(''%Y-%m'', played_at) = ''2024-01'' THEN 1 ELSE 0 END) AS total_jan, SUM(CASE WHEN strftime(''%Y-%m'', played_at) = ''2024-02'' THEN 1 ELSE 0 END) AS total_feb FROM plays) SELECT ar.name AS artist_name, ROUND(100.0 * m.jan_plays / NULLIF(t.total_jan, 0), 1) AS jan_pct, ROUND(100.0 * m.feb_plays / NULLIF(t.total_feb, 0), 1) AS feb_pct, ROUND(100.0 * m.feb_plays / NULLIF(t.total_feb, 0), 1) - ROUND(100.0 * m.jan_plays / NULLIF(t.total_jan, 0), 1) AS growth_pct FROM monthly m JOIN artists ar ON m.artist_id = ar.artist_id CROSS JOIN totals t ORDER BY growth_pct DESC;'),
('af3912b8-0fe7-4dda-af7f-a8946cf99c20', 'Create a complete user engagement report: show use...', 'Create a complete user engagement report: show username, total_plays, unique_artists, total_hours, diversity_score, and engagement_rank using RANK().', 'music', 'Hard', 25, 'WITH stats AS (SELECT p.user_id, COUNT(p.play_id) AS total_plays, COUNT(DISTINCT al.artist_id) AS unique_artists, ROUND(SUM(p.play_duration_secs) / 3600.0, 2) AS total_hours, ROUND(100.0 * COUNT(DISTINCT p.track_id) / COUNT(p.play_id), 1) AS diversity_score FROM plays p JOIN tracks t ON p.track_id = t.track_id JOIN albums al ON t.album_id = al.album_id GROUP BY p.user_id) SELECT u.username, s.total_plays, s.unique_artists, s.total_hours, s.diversity_score, RANK() OVER (ORDER BY s.total_plays + s.unique_artists * 5 + s.diversity_score DESC) AS engagement_rank FROM users u JOIN stats s ON u.user_id = s.user_id ORDER BY engagement_rank;'),
('11faca71-a2eb-4d7d-89d0-9f5af6b7c347', 'List all teams with name, city, and founded_year, ...', 'List all teams with name, city, and founded_year, ordered by founded_year.', 'sports', 'Easy', 5, 'SELECT name, city, founded_year FROM teams ORDER BY founded_year;'),
('8c2eb761-aa9f-49c7-b9db-ff8ac4c7077c', 'Find all players in the Forward position. Show fir...', 'Find all players in the Forward position. Show first_name, last_name, team_id.', 'sports', 'Easy', 5, 'SELECT first_name, last_name, team_id FROM players WHERE position = ''Forward'' ORDER BY last_name;'),
('98e2a51b-e26c-452b-9f6f-d5f1de214655', 'Count how many players are in each team. Show team...', 'Count how many players are in each team. Show team_id and player_count.', 'sports', 'Easy', 5, 'SELECT team_id, COUNT(*) AS player_count FROM players GROUP BY team_id ORDER BY player_count DESC;'),
('f1f6225c-2c8b-4f0d-b4d2-381e185d223c', 'Find all matches where the home team won (home_sco...', 'Find all matches where the home team won (home_score > away_score). Show match_id, home_team_id, away_team_id, home_score, away_score.', 'sports', 'Easy', 5, 'SELECT match_id, home_team_id, away_team_id, home_score, away_score FROM matches WHERE home_score > away_score;'),
('6d628b3c-c46c-4eb7-b90c-b0400083882b', 'Count total goals scored per season. Show season_i...', 'Count total goals scored per season. Show season_id and total_goals.', 'sports', 'Easy', 5, 'SELECT m.season_id, COUNT(g.goal_id) AS total_goals FROM matches m JOIN goals g ON m.match_id = g.match_id GROUP BY m.season_id ORDER BY total_goals DESC;'),
('b6d9283d-2065-4f95-8a72-ec8acf607d04', 'Find all draws (home_score = away_score). Show mat...', 'Find all draws (home_score = away_score). Show match_id, match_date, home_score, away_score.', 'sports', 'Easy', 5, 'SELECT match_id, match_date, home_score, away_score FROM matches WHERE home_score = away_score;'),
('ffa1bda9-1044-4e1a-bb63-65ceaf960901', 'List all seasons with name, start_date, and end_da...', 'List all seasons with name, start_date, and end_date.', 'sports', 'Easy', 5, 'SELECT name, start_date, end_date FROM seasons ORDER BY start_date;'),
('5759779b-cbf2-4b78-a845-56821578614a', 'Find the highest-scoring match (by total goals). S...', 'Find the highest-scoring match (by total goals). Show match_id and total_goals.', 'sports', 'Easy', 5, 'SELECT match_id, (home_score + away_score) AS total_goals FROM matches ORDER BY total_goals DESC LIMIT 1;'),
('af43175f-4cdc-41f0-be67-50068a6fda63', 'Find all own goals (is_own_goal = 1). Show goal_id...', 'Find all own goals (is_own_goal = 1). Show goal_id, match_id, player_id.', 'sports', 'Easy', 5, 'SELECT goal_id, match_id, player_id FROM goals WHERE is_own_goal = 1;'),
('624e4bab-0891-43fa-b72a-358bd057392a', 'Count total number of goals in the database. Retur...', 'Count total number of goals in the database. Return total_goals.', 'sports', 'Easy', 5, 'SELECT COUNT(*) AS total_goals FROM goals;'),
('6b8d6f4a-aad9-427a-9e64-209a9df7f278', 'Count goals per match. Show match_id and goal_coun...', 'Count goals per match. Show match_id and goal_count.', 'sports', 'Easy', 5, 'SELECT match_id, COUNT(*) AS goal_count FROM goals GROUP BY match_id ORDER BY goal_count DESC;'),
('da73ecac-1c47-4e5c-89e1-b5e000df1146', 'Find all Norwegian players. Show first_name, last_...', 'Find all Norwegian players. Show first_name, last_name, team_id.', 'sports', 'Easy', 5, 'SELECT first_name, last_name, team_id FROM players WHERE nationality = ''Norwegian'';'),
('56a508bd-993b-4297-919e-6eef4f62c15e', 'Show total wins per team based on standings (seaso...', 'Show total wins per team based on standings (season_id = 3). Show team_id and won.', 'sports', 'Easy', 5, 'SELECT team_id, won FROM standings WHERE season_id = 3 ORDER BY won DESC;'),
('0fe6a0c4-0e15-4f9b-9d20-1737169050a5', 'Find all matches in the most recent season (season...', 'Find all matches in the most recent season (season_id = 3). Show match_id, match_date, home_team_id, away_team_id.', 'sports', 'Easy', 5, 'SELECT match_id, match_date, home_team_id, away_team_id FROM matches WHERE season_id = 3 ORDER BY match_date;'),
('f397f550-f3f3-4dc3-a122-a6d2997745f7', 'Count goals scored by each player (not own goals)....', 'Count goals scored by each player (not own goals). Show player_id and goal_count.', 'sports', 'Easy', 5, 'SELECT player_id, COUNT(*) AS goal_count FROM goals WHERE is_own_goal = 0 GROUP BY player_id ORDER BY goal_count DESC;'),
('3aa51d8c-b8e8-4a61-b237-e17420a501d1', 'Find all teams in the Premier division. Show name ...', 'Find all teams in the Premier division. Show name and city.', 'sports', 'Easy', 5, 'SELECT name, city FROM teams WHERE division = ''Premier'' ORDER BY name;'),
('7805adfe-3170-4b08-9d8c-a3ed22539c28', 'Show the team with the most points in the 2023-24 ...', 'Show the team with the most points in the 2023-24 season (season_id = 3). Show team_id and points.', 'sports', 'Easy', 5, 'SELECT team_id, points FROM standings WHERE season_id = 3 ORDER BY points DESC LIMIT 1;'),
('46459aa5-381b-430c-bc66-b1f5b3aa1b98', 'Count how many players each nationality group has....', 'Count how many players each nationality group has. Show nationality and player_count.', 'sports', 'Easy', 5, 'SELECT nationality, COUNT(*) AS player_count FROM players GROUP BY nationality ORDER BY player_count DESC;'),
('e80bf28a-5fc1-431b-a84a-260c767aa615', 'Find all goals scored after minute 80 (late goals)...', 'Find all goals scored after minute 80 (late goals). Show goal_id, match_id, player_id, minute.', 'sports', 'Easy', 5, 'SELECT goal_id, match_id, player_id, minute FROM goals WHERE minute > 80 ORDER BY minute;'),
('fb073488-9ff6-44df-a983-a648f5b6e28e', 'Show average goals per match across the entire dat...', 'Show average goals per match across the entire dataset. Return avg_goals_per_match.', 'sports', 'Easy', 5, 'SELECT ROUND(AVG(home_score + away_score), 2) AS avg_goals_per_match FROM matches;'),
('ba5433bd-2318-41b0-8eba-46fcc83e0ed2', 'Show each team with its win/draw/loss record from ...', 'Show each team with its win/draw/loss record from standings. Show team name, won, drawn, lost, points.', 'sports', 'Medium', 15, 'SELECT t.name, s.won, s.drawn, s.lost, s.points FROM standings s JOIN teams t ON s.team_id = t.team_id WHERE s.season_id = 3 ORDER BY s.points DESC;'),
('4b96f195-76d5-4221-ad8f-d340ee0d9241', 'Show the top goalscorer per season. Show season_id...', 'Show the top goalscorer per season. Show season_id, player name, and goal_count.', 'sports', 'Medium', 15, 'SELECT season_id, player_name, goal_count FROM (SELECT m.season_id, p.first_name || '' '' || p.last_name AS player_name, COUNT(g.goal_id) AS goal_count, ROW_NUMBER() OVER (PARTITION BY m.season_id ORDER BY COUNT(g.goal_id) DESC) AS rn FROM goals g JOIN matches m ON g.match_id = m.match_id JOIN players p ON g.player_id = p.player_id WHERE g.is_own_goal = 0 GROUP BY m.season_id, g.player_id) WHERE rn = 1 ORDER BY season_id;'),
('4068f955-af63-447c-a262-530b9652122c', 'Calculate home vs away win rates across all teams....', 'Calculate home vs away win rates across all teams. Show overall home_wins, away_wins, draws and their percentage.', 'sports', 'Medium', 15, 'SELECT SUM(CASE WHEN home_score > away_score THEN 1 ELSE 0 END) AS home_wins, SUM(CASE WHEN away_score > home_score THEN 1 ELSE 0 END) AS away_wins, SUM(CASE WHEN home_score = away_score THEN 1 ELSE 0 END) AS draws, COUNT(*) AS total_matches, ROUND(100.0 * SUM(CASE WHEN home_score > away_score THEN 1 ELSE 0 END) / COUNT(*), 1) AS home_win_pct FROM matches;'),
('fbd5ddaf-9bea-4603-a463-5c92a1908702', 'Show total goals scored and conceded for each team...', 'Show total goals scored and conceded for each team (home + away). Show team_name, goals_scored, goals_conceded, and goal_difference.', 'sports', 'Medium', 15, 'SELECT t.name AS team_name, SUM(CASE WHEN m.home_team_id = t.team_id THEN m.home_score ELSE m.away_score END) AS goals_scored, SUM(CASE WHEN m.home_team_id = t.team_id THEN m.away_score ELSE m.home_score END) AS goals_conceded, SUM(CASE WHEN m.home_team_id = t.team_id THEN m.home_score - m.away_score ELSE m.away_score - m.home_score END) AS goal_difference FROM teams t JOIN matches m ON t.team_id = m.home_team_id OR t.team_id = m.away_team_id GROUP BY t.team_id ORDER BY goals_scored DESC;'),
('0739eb43-c83f-4e9e-852a-87037544c6ba', 'Show the number of goals scored per minute range (...', 'Show the number of goals scored per minute range (1-30, 31-60, 61-90). Show time_range and goal_count.', 'sports', 'Medium', 15, 'SELECT CASE WHEN minute <= 30 THEN ''1-30'' WHEN minute <= 60 THEN ''31-60'' ELSE ''61-90'' END AS time_range, COUNT(*) AS goal_count FROM goals WHERE is_own_goal = 0 GROUP BY time_range ORDER BY time_range;'),
('57ff1c3d-3330-4789-bab2-3281c9f74cca', 'Find the team with the best home record (most home...', 'Find the team with the best home record (most home wins). Show team_name and home_wins.', 'sports', 'Medium', 15, 'SELECT t.name AS team_name, COUNT(*) AS home_wins FROM matches m JOIN teams t ON m.home_team_id = t.team_id WHERE m.home_score > m.away_score GROUP BY m.home_team_id ORDER BY home_wins DESC LIMIT 1;'),
('847d083f-1173-4c1d-affc-b03cdf38dab2', 'Calculate average matchday attendance (goals as pr...', 'Calculate average matchday attendance (goals as proxy: avg goals per matchday). Show matchday and avg_goals.', 'sports', 'Medium', 15, 'SELECT matchday, ROUND(AVG(home_score + away_score), 2) AS avg_goals FROM matches GROUP BY matchday ORDER BY matchday;'),
('b676df3e-9685-45ad-8f28-465ec6138829', 'Show total goals contributed (scored + assists) pe...', 'Show total goals contributed (scored + assists) per player (use goals table only). Show player name and total_goals.', 'sports', 'Medium', 15, 'SELECT p.first_name || '' '' || p.last_name AS player_name, COUNT(g.goal_id) AS total_goals FROM players p JOIN goals g ON p.player_id = g.player_id WHERE g.is_own_goal = 0 GROUP BY p.player_id ORDER BY total_goals DESC;'),
('cc855f25-b86e-4050-b753-b38fcefe2b90', 'Find the team that conceded the most goals across ...', 'Find the team that conceded the most goals across all seasons. Show team_name and goals_conceded.', 'sports', 'Medium', 15, 'SELECT t.name AS team_name, SUM(CASE WHEN m.home_team_id = t.team_id THEN m.away_score ELSE m.home_score END) AS goals_conceded FROM teams t JOIN matches m ON t.team_id = m.home_team_id OR t.team_id = m.away_team_id GROUP BY t.team_id ORDER BY goals_conceded DESC LIMIT 1;'),
('737e860f-003f-47e5-a488-29b9254b2f26', 'Show win rate per team across all seasons. Show te...', 'Show win rate per team across all seasons. Show team_name and win_rate_pct.', 'sports', 'Medium', 15, 'WITH results AS (SELECT team_id, SUM(won) AS total_wins, SUM(played) AS total_played FROM standings GROUP BY team_id) SELECT t.name AS team_name, ROUND(100.0 * r.total_wins / r.total_played, 1) AS win_rate_pct FROM teams t JOIN results r ON t.team_id = r.team_id ORDER BY win_rate_pct DESC;'),
('f0b92e2c-a8f4-41c1-99d8-6f86ba4fa21d', 'Show the average goals per game for each team (as ...', 'Show the average goals per game for each team (as home + away combined). Show team_name and avg_goals_per_game.', 'sports', 'Medium', 15, 'WITH goals AS (SELECT t.team_id, t.name, SUM(CASE WHEN m.home_team_id = t.team_id THEN m.home_score ELSE m.away_score END) AS total_goals, COUNT(m.match_id) AS total_games FROM teams t JOIN matches m ON t.team_id = m.home_team_id OR t.team_id = m.away_team_id GROUP BY t.team_id) SELECT name AS team_name, ROUND(CAST(total_goals AS REAL) / total_games, 2) AS avg_goals_per_game FROM goals ORDER BY avg_goals_per_game DESC;'),
('ef9f5620-75d7-4a5b-ac30-45f626f10792', 'Show which position scores the most goals. Show po...', 'Show which position scores the most goals. Show position and goal_count.', 'sports', 'Medium', 15, 'SELECT p.position, COUNT(g.goal_id) AS goal_count FROM players p JOIN goals g ON p.player_id = g.player_id WHERE g.is_own_goal = 0 GROUP BY p.position ORDER BY goal_count DESC;'),
('244eeed7-170e-491e-93f8-bb09645c0e99', 'Show head-to-head record between team_id 1 and tea...', 'Show head-to-head record between team_id 1 and team_id 2. Show home_team_name, away_team_name, home_score, away_score for all their matches.', 'sports', 'Medium', 15, 'SELECT t1.name AS home_team_name, t2.name AS away_team_name, m.home_score, m.away_score, m.match_date FROM matches m JOIN teams t1 ON m.home_team_id = t1.team_id JOIN teams t2 ON m.away_team_id = t2.team_id WHERE (m.home_team_id = 1 AND m.away_team_id = 2) OR (m.home_team_id = 2 AND m.away_team_id = 1) ORDER BY m.match_date;'),
('85dfef72-525e-4206-b4f1-64b706dae88c', 'Find players who scored goals in multiple matches ...', 'Find players who scored goals in multiple matches (not just 1 match). Show player name and matches_with_goals.', 'sports', 'Medium', 15, 'SELECT p.first_name || '' '' || p.last_name AS player_name, COUNT(DISTINCT g.match_id) AS matches_with_goals FROM players p JOIN goals g ON p.player_id = g.player_id WHERE g.is_own_goal = 0 GROUP BY p.player_id HAVING COUNT(DISTINCT g.match_id) > 1 ORDER BY matches_with_goals DESC;'),
('bfdd42bb-1e89-4a97-b098-d0e4b4105e96', 'Show season standings (season_id = 3): team name, ...', 'Show season standings (season_id = 3): team name, points, won, drawn, lost, goals_scored (from standing or goals table). Order by points DESC, won DESC.', 'sports', 'Medium', 15, 'SELECT t.name AS team_name, s.points, s.won, s.drawn, s.lost FROM standings s JOIN teams t ON s.team_id = t.team_id WHERE s.season_id = 3 ORDER BY s.points DESC, s.won DESC;'),
('ad85632a-a406-40a0-a5bb-11b318544cec', 'Rank players by total goals using DENSE_RANK. Show...', 'Rank players by total goals using DENSE_RANK. Show player name, total_goals, and goal_rank.', 'sports', 'Hard', 25, 'SELECT player_name, total_goals, DENSE_RANK() OVER (ORDER BY total_goals DESC) AS goal_rank FROM (SELECT p.first_name || '' '' || p.last_name AS player_name, COUNT(g.goal_id) AS total_goals FROM players p JOIN goals g ON p.player_id = g.player_id WHERE g.is_own_goal = 0 GROUP BY p.player_id) ORDER BY goal_rank;'),
('1eff4eae-843d-49cd-8238-c509978fc5dd', 'Track team form: for each season show a team''s poi...', 'Track team form: for each season show a team''s points vs previous season. Show team_name, season_id, points, prev_season_points, and points_change.', 'sports', 'Hard', 25, 'SELECT t.name AS team_name, s.season_id, s.points, LAG(s.points) OVER (PARTITION BY s.team_id ORDER BY s.season_id) AS prev_season_points, s.points - LAG(s.points) OVER (PARTITION BY s.team_id ORDER BY s.season_id) AS points_change FROM standings s JOIN teams t ON s.team_id = t.team_id ORDER BY team_name, s.season_id;'),
('83865d08-c1ae-4e80-b836-edfb5a0ace58', 'Show the top 3 goalscorers per season using ROW_NU...', 'Show the top 3 goalscorers per season using ROW_NUMBER(). Show season_name, player_name, goals, and rn where rn <= 3.', 'sports', 'Hard', 25, 'SELECT se.name AS season_name, player_name, goal_count, rn FROM (SELECT m.season_id, p.first_name || '' '' || p.last_name AS player_name, COUNT(g.goal_id) AS goal_count, ROW_NUMBER() OVER (PARTITION BY m.season_id ORDER BY COUNT(g.goal_id) DESC) AS rn FROM goals g JOIN matches m ON g.match_id = m.match_id JOIN players p ON g.player_id = p.player_id WHERE g.is_own_goal = 0 GROUP BY m.season_id, g.player_id) JOIN seasons se ON season_id = se.season_id WHERE rn <= 3 ORDER BY season_id, rn;'),
('00a274a0-f76d-4aee-9df5-a033449e7c6f', 'Calculate running total goals per matchday (season...', 'Calculate running total goals per matchday (season 3). Show matchday, goals_on_day, and cumulative_goals.', 'sports', 'Hard', 25, 'WITH daily AS (SELECT m.matchday, COUNT(g.goal_id) AS goals_on_day FROM matches m LEFT JOIN goals g ON m.match_id = g.match_id WHERE m.season_id = 3 GROUP BY m.matchday) SELECT matchday, goals_on_day, SUM(goals_on_day) OVER (ORDER BY matchday ROWS UNBOUNDED PRECEDING) AS cumulative_goals FROM daily ORDER BY matchday;'),
('ebadd2fb-541b-4d1d-b8e4-8a1ca2015699', 'Calculate each team''s points % of maximum possible...', 'Calculate each team''s points % of maximum possible points (38 games × 3 = 114 max). Show team_name, points, and efficiency_pct using season 3.', 'sports', 'Hard', 25, 'SELECT t.name AS team_name, s.points, ROUND(100.0 * s.points / 114, 1) AS efficiency_pct, RANK() OVER (ORDER BY s.points DESC) AS points_rank FROM standings s JOIN teams t ON s.team_id = t.team_id WHERE s.season_id = 3 ORDER BY points_rank;'),
('652612fb-3b98-4539-8ae6-d82666febff2', 'Show goal-scoring momentum: for each player, show ...', 'Show goal-scoring momentum: for each player, show each goal and their running total. Show player_name, match_id, minute, and career_goals_so_far.', 'sports', 'Hard', 25, 'SELECT p.first_name || '' '' || p.last_name AS player_name, g.match_id, g.minute, ROW_NUMBER() OVER (PARTITION BY g.player_id ORDER BY g.match_id, g.minute) AS career_goals_so_far FROM goals g JOIN players p ON g.player_id = p.player_id WHERE g.is_own_goal = 0 ORDER BY player_name, g.match_id, g.minute;'),
('904100e2-4994-4581-8b07-e0b97a947006', 'Show each match and the next match for each team. ...', 'Show each match and the next match for each team. Show team_id, match_date, and next_match_date.', 'sports', 'Hard', 25, 'SELECT home_team_id AS team_id, match_date, LEAD(match_date) OVER (PARTITION BY home_team_id ORDER BY match_date) AS next_match_date FROM matches ORDER BY home_team_id, match_date;'),
('f3eaa362-fa52-456c-acf0-17ebf2ef13e5', 'Use NTILE(4) to bucket teams into performance quar...', 'Use NTILE(4) to bucket teams into performance quartiles based on points (season 3). Show team_name, points, and quartile.', 'sports', 'Hard', 25, 'SELECT t.name AS team_name, s.points, NTILE(4) OVER (ORDER BY s.points DESC) AS quartile FROM standings s JOIN teams t ON s.team_id = t.team_id WHERE s.season_id = 3 ORDER BY quartile, s.points DESC;'),
('e069880b-e7a3-4575-a092-5bc0fd2ba3a6', 'Find teams that improved their points total every ...', 'Find teams that improved their points total every season (each season higher than the previous). Show team_name and seasons_of_improvement.', 'sports', 'Hard', 25, 'WITH ranked AS (SELECT s.team_id, s.season_id, s.points, LAG(s.points) OVER (PARTITION BY s.team_id ORDER BY s.season_id) AS prev_points FROM standings s) SELECT t.name AS team_name, COUNT(*) - 1 AS seasons_of_data, SUM(CASE WHEN prev_points IS NULL OR points > prev_points THEN 1 ELSE 0 END) - 1 AS seasons_improved FROM ranked r JOIN teams t ON r.team_id = t.team_id GROUP BY r.team_id HAVING COUNT(*) > 1 AND SUM(CASE WHEN prev_points IS NOT NULL AND points <= prev_points THEN 1 ELSE 0 END) = 0 ORDER BY seasons_improved DESC;'),
('1f41c66e-d4aa-412b-8586-490f93b18665', 'Compute team efficiency score per season: goals_sc...', 'Compute team efficiency score per season: goals_scored / goals_conceded (GF/GA ratio). Rank teams by this ratio. Show team_name, season_id, goals_for, goals_against, ratio.', 'sports', 'Hard', 25, 'WITH team_goals AS (SELECT t.team_id, t.name, m.season_id, SUM(CASE WHEN m.home_team_id = t.team_id THEN m.home_score ELSE m.away_score END) AS goals_for, SUM(CASE WHEN m.home_team_id = t.team_id THEN m.away_score ELSE m.home_score END) AS goals_against FROM teams t JOIN matches m ON t.team_id = m.home_team_id OR t.team_id = m.away_team_id GROUP BY t.team_id, m.season_id) SELECT name AS team_name, season_id, goals_for, goals_against, ROUND(CAST(goals_for AS REAL) / NULLIF(goals_against, 0), 2) AS ratio FROM team_goals ORDER BY ratio DESC;');
INSERT INTO public.questions (id, title, prompt, schema_name, difficulty, estimated_time_minutes, solution_sql) VALUES
('1176f6ea-e45c-411f-8660-9675993179c5', 'Create a full league table for season 3 with ranki...', 'Create a full league table for season 3 with rankings using RANK(). Show rank, team_name, played, won, drawn, lost, goals_scored, goals_conceded, goal_diff, points.', 'sports', 'Hard', 25, 'SELECT RANK() OVER (ORDER BY s.points DESC, (s.won * 3 + s.drawn) DESC) AS table_rank, t.name AS team_name, s.played, s.won, s.drawn, s.lost, s.points FROM standings s JOIN teams t ON s.team_id = t.team_id WHERE s.season_id = 3 ORDER BY table_rank;'),
('c0ac3a22-a4f3-434d-9550-de8450103257', 'Show season-by-season goal trend per player using ...', 'Show season-by-season goal trend per player using LAG. Show player_name, season_id, season_goals, prev_season_goals, and form_trend (Improving/Declining/Same).', 'sports', 'Hard', 25, 'WITH sg AS (SELECT m.season_id, g.player_id, COUNT(*) AS season_goals FROM goals g JOIN matches m ON g.match_id = m.match_id WHERE g.is_own_goal = 0 GROUP BY m.season_id, g.player_id) SELECT p.first_name || '' '' || p.last_name AS player_name, sg.season_id, sg.season_goals, LAG(sg.season_goals) OVER (PARTITION BY sg.player_id ORDER BY sg.season_id) AS prev_season_goals, CASE WHEN LAG(sg.season_goals) OVER (PARTITION BY sg.player_id ORDER BY sg.season_id) IS NULL THEN ''N/A'' WHEN sg.season_goals > LAG(sg.season_goals) OVER (PARTITION BY sg.player_id ORDER BY sg.season_id) THEN ''Improving'' WHEN sg.season_goals < LAG(sg.season_goals) OVER (PARTITION BY sg.player_id ORDER BY sg.season_id) THEN ''Declining'' ELSE ''Same'' END AS form_trend FROM sg JOIN players p ON sg.player_id = p.player_id ORDER BY player_name, sg.season_id;'),
('7be8e527-12f5-47e6-a2fb-b80af591c4b4', 'Show a 5-match rolling average of goals per matchd...', 'Show a 5-match rolling average of goals per matchday for season 3. Show matchday, goals_on_day, and rolling_avg.', 'sports', 'Hard', 25, 'WITH daily AS (SELECT m.matchday, COUNT(g.goal_id) AS goals_on_day FROM matches m LEFT JOIN goals g ON m.match_id = g.match_id WHERE m.season_id = 3 GROUP BY m.matchday) SELECT matchday, goals_on_day, ROUND(AVG(goals_on_day) OVER (ORDER BY matchday ROWS BETWEEN 4 PRECEDING AND CURRENT ROW), 2) AS rolling_avg FROM daily ORDER BY matchday;'),
('48c9eabd-ecd6-401a-8383-faa47fa68016', 'Create a comprehensive player scorecard: show play...', 'Create a comprehensive player scorecard: show player_name, team_name, position, career_goals, career_matches, goals_per_match, and goal_rank using RANK().', 'sports', 'Hard', 25, 'WITH stats AS (SELECT g.player_id, COUNT(g.goal_id) AS career_goals, COUNT(DISTINCT g.match_id) AS career_matches FROM goals g WHERE g.is_own_goal = 0 GROUP BY g.player_id) SELECT p.first_name || '' '' || p.last_name AS player_name, t.name AS team_name, p.position, COALESCE(s.career_goals, 0) AS career_goals, COALESCE(s.career_matches, 0) AS career_matches, ROUND(CAST(COALESCE(s.career_goals, 0) AS REAL) / NULLIF(s.career_matches, 0), 2) AS goals_per_match, RANK() OVER (ORDER BY COALESCE(s.career_goals, 0) DESC) AS goal_rank FROM players p JOIN teams t ON p.team_id = t.team_id LEFT JOIN stats s ON p.player_id = s.player_id ORDER BY goal_rank;'),
('2fbf49cb-8da7-44e7-9e2a-16689bf74b21', 'Compute team''s points-per-game (PPG) for each seas...', 'Compute team''s points-per-game (PPG) for each season and compare to their career PPG. Show team_name, season_id, season_ppg, career_ppg, and deviation from career.', 'sports', 'Hard', 25, 'WITH ppg AS (SELECT s.team_id, s.season_id, ROUND(CAST(s.points AS REAL) / s.played, 2) AS season_ppg FROM standings s) SELECT t.name AS team_name, p.season_id, p.season_ppg, ROUND(AVG(p.season_ppg) OVER (PARTITION BY p.team_id), 2) AS career_ppg, ROUND(p.season_ppg - AVG(p.season_ppg) OVER (PARTITION BY p.team_id), 2) AS deviation FROM ppg p JOIN teams t ON p.team_id = t.team_id ORDER BY team_name, p.season_id;'),
('2fe20035-c7d7-4cb5-8ad6-7c0ff5b0cb61', 'List all students with their first_name, last_name...', 'List all students with their first_name, last_name, and major.', 'university', 'Easy', 5, 'SELECT first_name, last_name, major FROM students;'),
('c9f5b6bc-a51f-4321-880f-fc929714ad8a', 'Find all students majoring in ''Computer Science''. ...', 'Find all students majoring in ''Computer Science''. Show first_name, last_name.', 'university', 'Easy', 5, 'SELECT first_name, last_name FROM students WHERE major = ''Computer Science'';'),
('4045b7aa-7ec8-49fa-a440-b8eaed509755', 'List all professors who have tenure (tenure = 1). ...', 'List all professors who have tenure (tenure = 1). Show first_name, last_name, and email.', 'university', 'Easy', 5, 'SELECT first_name, last_name, email FROM professors WHERE tenure = 1;'),
('ec00b80e-698e-40d3-bc75-d8d6b3eb2a51', 'List all courses ordered by credit_hours descendin...', 'List all courses ordered by credit_hours descending. Show title and credit_hours.', 'university', 'Easy', 5, 'SELECT title, credit_hours FROM courses ORDER BY credit_hours DESC;'),
('4e89d118-7b16-4656-bde5-15bc819be27e', 'Find all classrooms with a capacity greater than 5...', 'Find all classrooms with a capacity greater than 50. Show building, room_number, capacity.', 'university', 'Easy', 5, 'SELECT building, room_number, capacity FROM classrooms WHERE capacity > 50 ORDER BY capacity DESC;'),
('0c727732-8951-48da-ab2e-7c245cfb1f53', 'Count the number of students per major. Show major...', 'Count the number of students per major. Show major and student_count, ordered by count DESC.', 'university', 'Easy', 5, 'SELECT major, COUNT(*) AS student_count FROM students GROUP BY major ORDER BY student_count DESC;'),
('b29e6b57-3251-4cb6-8182-63884db0533d', 'Show all grades with letter_grade = ''A''. Show grad...', 'Show all grades with letter_grade = ''A''. Show grade_id, enrollment_id, final_score.', 'university', 'Easy', 5, 'SELECT grade_id, enrollment_id, final_score FROM grades WHERE letter_grade = ''A'';'),
('e7e2bb83-8d40-48d0-8859-7a67e51b81c7', 'List all semesters with their name, start_date, an...', 'List all semesters with their name, start_date, and end_date, ordered by start_date.', 'university', 'Easy', 5, 'SELECT name, start_date, end_date FROM semesters ORDER BY start_date;'),
('3196ee64-d0ab-4a0d-a3e3-34fcbf9597f0', 'Find courses worth 4 credit hours. Show course_id ...', 'Find courses worth 4 credit hours. Show course_id and title.', 'university', 'Easy', 5, 'SELECT course_id, title FROM courses WHERE credit_hours = 4;'),
('e40c478d-b331-4fa3-984e-ccf9adb6f2fa', 'Count how many professors are in the database. Ret...', 'Count how many professors are in the database. Return a single number labeled professor_count.', 'university', 'Easy', 5, 'SELECT COUNT(*) AS professor_count FROM professors;'),
('2c2be49b-1db9-445a-8606-6c10e006e83b', 'Find students with no advisor assigned (advisor_id...', 'Find students with no advisor assigned (advisor_id IS NULL). Show first_name, last_name, major.', 'university', 'Easy', 5, 'SELECT first_name, last_name, major FROM students WHERE advisor_id IS NULL;'),
('7431c7d7-987d-4136-93e3-afa5c16eb85f', 'Show courses and their department name. Show title...', 'Show courses and their department name. Show title, credit_hours, and department name.', 'university', 'Easy', 5, 'SELECT c.title, c.credit_hours, d.name AS department_name FROM courses c JOIN departments d ON c.department_id = d.department_id;'),
('4c46e037-0e44-47e1-a4ae-e93dc4b822ca', 'Find students who enrolled before 2022. Show first...', 'Find students who enrolled before 2022. Show first_name, last_name, enrolled_since.', 'university', 'Easy', 5, 'SELECT first_name, last_name, enrolled_since FROM students WHERE enrolled_since < ''2022-01-01'';'),
('1741e6b4-19ff-4ae7-a5cf-9ae79ba032ac', 'Count enrollments per semester. Show semester_id a...', 'Count enrollments per semester. Show semester_id and enrollment_count.', 'university', 'Easy', 5, 'SELECT semester_id, COUNT(*) AS enrollment_count FROM enrollments GROUP BY semester_id ORDER BY semester_id;'),
('47186568-aa48-44a9-a1e0-de1db42da301', 'Show the top 5 professors by earliest hire date (m...', 'Show the top 5 professors by earliest hire date (most senior). Show first_name, last_name, hired_at.', 'university', 'Easy', 5, 'SELECT first_name, last_name, hired_at FROM professors ORDER BY hired_at ASC LIMIT 5;'),
('b0b205ef-3ac2-47f0-8df9-c560eecf9dab', 'List all courses in the Computer Science departmen...', 'List all courses in the Computer Science department (department_id = 1). Show title.', 'university', 'Easy', 5, 'SELECT title FROM courses WHERE department_id = 1;'),
('d936c448-aacf-4e3f-ba7b-19cbe99258bf', 'Show all departments with their name and building....', 'Show all departments with their name and building.', 'university', 'Easy', 5, 'SELECT name, building FROM departments;'),
('7876ef46-8356-4b6c-aa48-936ff52ed256', 'Count how many courses each department offers. Sho...', 'Count how many courses each department offers. Show department_id and course_count.', 'university', 'Easy', 5, 'SELECT department_id, COUNT(*) AS course_count FROM courses GROUP BY department_id ORDER BY course_count DESC;'),
('3d63ff31-2f49-41b8-8861-3c7532c02b28', 'Find all grades with final_score above 90. Show gr...', 'Find all grades with final_score above 90. Show grade_id, final_score, letter_grade.', 'university', 'Easy', 5, 'SELECT grade_id, final_score, letter_grade FROM grades WHERE final_score > 90 ORDER BY final_score DESC;'),
('717cdfca-c37d-4d28-8c9f-cd802a7d3ec3', 'Find all courses that have a prerequisite (prereq_...', 'Find all courses that have a prerequisite (prereq_course_id IS NOT NULL). Show title and prereq_course_id.', 'university', 'Easy', 5, 'SELECT title, prereq_course_id FROM courses WHERE prereq_course_id IS NOT NULL;'),
('f667d244-bc90-499a-a9b7-4e848223cc82', 'Calculate the average grade score per course. Show...', 'Calculate the average grade score per course. Show course title and avg_score. Order by avg_score DESC.', 'university', 'Medium', 15, 'SELECT c.title, ROUND(AVG(g.final_score), 2) AS avg_score FROM enrollments e JOIN grades g ON e.enrollment_id = g.grade_id JOIN courses c ON e.course_id = c.course_id GROUP BY c.course_id, c.title ORDER BY avg_score DESC;'),
('9f49f835-0206-4a49-9ee5-6119cd5029a1', 'Show the student with the highest average final sc...', 'Show the student with the highest average final score across all their enrolled courses. Show student name and avg_score.', 'university', 'Medium', 15, 'SELECT s.first_name || '' '' || s.last_name AS student_name, ROUND(AVG(g.final_score), 2) AS avg_score FROM students s JOIN enrollments e ON s.student_id = e.student_id JOIN grades g ON e.enrollment_id = g.grade_id GROUP BY s.student_id ORDER BY avg_score DESC LIMIT 1;'),
('16271575-23ce-472c-b39c-0f6a7892080e', 'Find departments with more than 5 courses. Show de...', 'Find departments with more than 5 courses. Show department name and course_count.', 'university', 'Medium', 15, 'SELECT d.name, COUNT(c.course_id) AS course_count FROM departments d JOIN courses c ON d.department_id = c.department_id GROUP BY d.department_id HAVING COUNT(c.course_id) > 5;'),
('8afcba12-0769-4af0-9a9a-d4e068e68dd5', 'List professors who have no students assigned to t...', 'List professors who have no students assigned to them as advisor. Show first_name, last_name.', 'university', 'Medium', 15, 'SELECT p.first_name, p.last_name FROM professors p LEFT JOIN students s ON p.professor_id = s.advisor_id WHERE s.student_id IS NULL;'),
('99b632f2-5a3a-4b4c-a7f9-7b090c6fa0f7', 'Count how many students are enrolled in each cours...', 'Count how many students are enrolled in each course. Show course title and student_count.', 'university', 'Medium', 15, 'SELECT c.title, COUNT(e.student_id) AS student_count FROM courses c JOIN enrollments e ON c.course_id = e.course_id GROUP BY c.course_id, c.title ORDER BY student_count DESC;'),
('63999e17-8965-454b-9468-645a86cf08ac', 'Find students who have enrolled in more courses th...', 'Find students who have enrolled in more courses than the average number of enrollments per student. Show first_name, last_name, course_count.', 'university', 'Medium', 15, 'SELECT s.first_name, s.last_name, COUNT(e.enrollment_id) AS course_count FROM students s JOIN enrollments e ON s.student_id = e.student_id GROUP BY s.student_id HAVING COUNT(e.enrollment_id) > (SELECT AVG(cnt) FROM (SELECT COUNT(*) AS cnt FROM enrollments GROUP BY student_id));'),
('05376dc6-50fe-4691-b613-90dd051c2f10', 'Show each student their advisor name. Show student...', 'Show each student their advisor name. Show student name and advisor name.', 'university', 'Medium', 15, 'SELECT s.first_name || '' '' || s.last_name AS student_name, p.first_name || '' '' || p.last_name AS advisor_name FROM students s LEFT JOIN professors p ON s.advisor_id = p.professor_id ORDER BY student_name;'),
('54c6ea99-63db-4253-bf52-0d7325f4bc70', 'Find departments with the highest average course c...', 'Find departments with the highest average course credit_hours. Show department_name and avg_credits.', 'university', 'Medium', 15, 'SELECT d.name AS department_name, ROUND(AVG(c.credit_hours), 2) AS avg_credits FROM departments d JOIN courses c ON d.department_id = c.department_id GROUP BY d.department_id, d.name ORDER BY avg_credits DESC;'),
('aaf9fb75-1aa3-40df-8fde-df00b22bfda7', 'Show the grade distribution (count per letter grad...', 'Show the grade distribution (count per letter grade) for all students. Show letter_grade and count.', 'university', 'Medium', 15, 'SELECT letter_grade, COUNT(*) AS grade_count FROM grades GROUP BY letter_grade ORDER BY letter_grade;'),
('c56211e7-a7a5-4a8a-87f1-b2d9c5e80599', 'Find the semester with the most enrollments. Show ...', 'Find the semester with the most enrollments. Show semester name and enrollment_count.', 'university', 'Medium', 15, 'SELECT s.name AS semester_name, COUNT(e.enrollment_id) AS enrollment_count FROM semesters s JOIN enrollments e ON s.semester_id = e.semester_id GROUP BY s.semester_id, s.name ORDER BY enrollment_count DESC LIMIT 1;'),
('2a9b286f-8f11-473b-a406-323324075430', 'List all professors with the number of students th...', 'List all professors with the number of students they advise. Show professor name and advisee_count.', 'university', 'Medium', 15, 'SELECT p.first_name || '' '' || p.last_name AS professor_name, COUNT(s.student_id) AS advisee_count FROM professors p LEFT JOIN students s ON p.professor_id = s.advisor_id GROUP BY p.professor_id ORDER BY advisee_count DESC;'),
('1d3a3bb8-4318-491c-ae7d-9b054ea80392', 'Calculate average midterm_score and average final_...', 'Calculate average midterm_score and average final_score per department. Show department_name, avg_midterm, avg_final.', 'university', 'Medium', 15, 'SELECT d.name AS department_name, ROUND(AVG(g.midterm_score), 2) AS avg_midterm, ROUND(AVG(g.final_score), 2) AS avg_final FROM grades g JOIN enrollments e ON g.grade_id = e.enrollment_id JOIN courses c ON e.course_id = c.course_id JOIN departments d ON c.department_id = d.department_id GROUP BY d.department_id ORDER BY avg_final DESC;'),
('cad70d9b-8b7d-4ae8-833b-832fdc42689d', 'Show courses along with their prerequisite course ...', 'Show courses along with their prerequisite course title. Show course title and prereq_title (use LEFT JOIN for courses with no prereq).', 'university', 'Medium', 15, 'SELECT c1.title, c2.title AS prereq_title FROM courses c1 LEFT JOIN courses c2 ON c1.prereq_course_id = c2.course_id ORDER BY c1.title;'),
('d22a4444-e83d-473b-a6e4-2ba44e3794d9', 'Find students who received at least one F grade. S...', 'Find students who received at least one F grade. Show student_id and count_of_Fs.', 'university', 'Medium', 15, 'SELECT e.student_id, COUNT(*) AS count_of_Fs FROM enrollments e JOIN grades g ON e.enrollment_id = g.grade_id WHERE g.letter_grade = ''F'' GROUP BY e.student_id;'),
('7083fc34-7868-41e3-b885-38caeb0b3bac', 'Show how many courses each student has completed (...', 'Show how many courses each student has completed (total enrolled). Show student name and total_courses.', 'university', 'Medium', 15, 'SELECT s.first_name || '' '' || s.last_name AS student_name, COUNT(e.enrollment_id) AS total_courses FROM students s LEFT JOIN enrollments e ON s.student_id = e.student_id GROUP BY s.student_id ORDER BY total_courses DESC;'),
('12ae7116-6a2f-40f4-8854-652bf97c1079', 'Find the most popular major (by student count). Sh...', 'Find the most popular major (by student count). Show major and count.', 'university', 'Medium', 15, 'SELECT major, COUNT(*) AS student_count FROM students GROUP BY major ORDER BY student_count DESC LIMIT 1;'),
('0d24678e-736f-42ca-8709-31fe68d333a9', 'Calculate how long each professor has been employe...', 'Calculate how long each professor has been employed (in years). Show professor name and years_employed.', 'university', 'Medium', 15, 'SELECT first_name || '' '' || last_name AS professor_name, ROUND((julianday(''2024-01-01'') - julianday(hired_at)) / 365, 1) AS years_employed FROM professors ORDER BY years_employed DESC;'),
('cc0fc36a-a99d-4249-a5a5-b32f8e872e6d', 'Show the pass rate per course (percentage of A or ...', 'Show the pass rate per course (percentage of A or B grades). Show title and pass_rate_pct.', 'university', 'Medium', 15, 'SELECT c.title, ROUND(100.0 * SUM(CASE WHEN g.letter_grade IN (''A'',''B'') THEN 1 ELSE 0 END) / COUNT(*), 1) AS pass_rate_pct FROM courses c JOIN enrollments e ON c.course_id = e.course_id JOIN grades g ON e.enrollment_id = g.grade_id GROUP BY c.course_id ORDER BY pass_rate_pct DESC;'),
('060c6cda-3861-4127-8c9d-d55b24c7e44f', 'List professors grouped by department with a count...', 'List professors grouped by department with a count. Show department_name and professor_count.', 'university', 'Medium', 15, 'SELECT d.name AS department_name, COUNT(p.professor_id) AS professor_count FROM departments d LEFT JOIN professors p ON d.department_id = p.department_id GROUP BY d.department_id, d.name ORDER BY professor_count DESC;'),
('48777cb0-f67e-4551-9e67-5feb88c05438', 'Show total credit hours enrolled per student (sum ...', 'Show total credit hours enrolled per student (sum of all enrolled course credit_hours). Show student name and total_credits.', 'university', 'Medium', 15, 'SELECT s.first_name || '' '' || s.last_name AS student_name, SUM(c.credit_hours) AS total_credits FROM students s JOIN enrollments e ON s.student_id = e.student_id JOIN courses c ON e.course_id = c.course_id GROUP BY s.student_id ORDER BY total_credits DESC;'),
('33e02196-17bb-4c4e-8868-d510af553f74', 'Identify the student who is enrolled in the most c...', 'Identify the student who is enrolled in the most courses (across all semesters). Show student name and course_count.', 'university', 'Medium', 15, 'SELECT s.first_name || '' '' || s.last_name AS student_name, COUNT(e.enrollment_id) AS course_count FROM students s JOIN enrollments e ON s.student_id = e.student_id GROUP BY s.student_id ORDER BY course_count DESC LIMIT 1;'),
('49a19734-dc8a-415a-a595-853912a1da8e', 'Calculate the average final_score per semester. Sh...', 'Calculate the average final_score per semester. Show semester name and avg_score.', 'university', 'Medium', 15, 'SELECT s.name AS semester_name, ROUND(AVG(g.final_score), 2) AS avg_score FROM semesters s JOIN enrollments e ON s.semester_id = e.semester_id JOIN grades g ON e.enrollment_id = g.grade_id GROUP BY s.semester_id ORDER BY avg_score DESC;'),
('29c6638a-19f3-4736-af5f-fe5782fb0e98', 'Find the department with the highest average stude...', 'Find the department with the highest average student GPA (avg final_score). Show department_name and avg_gpa.', 'university', 'Medium', 15, 'SELECT d.name AS department_name, ROUND(AVG(g.final_score), 2) AS avg_gpa FROM grades g JOIN enrollments e ON g.grade_id = e.enrollment_id JOIN courses c ON e.course_id = c.course_id JOIN departments d ON c.department_id = d.department_id GROUP BY d.department_id ORDER BY avg_gpa DESC LIMIT 1;'),
('a5458eea-a8b7-44b3-8100-b7aa0de42b63', 'Show how many students are enrolled in each sectio...', 'Show how many students are enrolled in each section (A/B/C). Show section and student_count.', 'university', 'Medium', 15, 'SELECT section, COUNT(*) AS student_count FROM enrollments GROUP BY section ORDER BY student_count DESC;'),
('7c361900-544c-4baf-b002-f64e2667b847', 'List all students enrolled in the current semester...', 'List all students enrolled in the current semester (semester_id = 5). Show first_name and last_name.', 'university', 'Medium', 15, 'SELECT DISTINCT s.first_name, s.last_name FROM students s JOIN enrollments e ON s.student_id = e.student_id WHERE e.semester_id = 5;'),
('cecf0ea6-8557-4f53-b948-a593899061dd', 'Rank students by their average final score using D...', 'Rank students by their average final score using DENSE_RANK. Show student name, avg_score, and rank.', 'university', 'Hard', 25, 'SELECT student_name, avg_score, DENSE_RANK() OVER (ORDER BY avg_score DESC) AS student_rank FROM (SELECT s.first_name || '' '' || s.last_name AS student_name, ROUND(AVG(g.final_score), 2) AS avg_score FROM students s JOIN enrollments e ON s.student_id = e.student_id JOIN grades g ON e.enrollment_id = g.grade_id GROUP BY s.student_id) ORDER BY student_rank;'),
('3d22b1d6-579c-44ea-8686-052800d597b4', 'For each department, find the top-scoring student ...', 'For each department, find the top-scoring student using ROW_NUMBER(). Show department_name, student_name, avg_score, and row_num where row_num = 1.', 'university', 'Hard', 25, 'SELECT department_name, student_name, avg_score FROM (SELECT d.name AS department_name, s.first_name || '' '' || s.last_name AS student_name, ROUND(AVG(g.final_score), 2) AS avg_score, ROW_NUMBER() OVER (PARTITION BY d.department_id ORDER BY AVG(g.final_score) DESC) AS rn FROM students s JOIN enrollments e ON s.student_id = e.student_id JOIN grades g ON e.enrollment_id = g.grade_id JOIN courses c ON e.course_id = c.course_id JOIN departments d ON c.department_id = d.department_id GROUP BY d.department_id, s.student_id) WHERE rn = 1 ORDER BY department_name;'),
('9ce9bc12-c490-4a6f-839a-e30e167bc564', 'Use a recursive CTE to build the course prerequisi...', 'Use a recursive CTE to build the course prerequisite chain. Show course title and its direct prerequisite title at every level.', 'university', 'Hard', 25, 'WITH RECURSIVE prereq_chain AS (SELECT course_id, title, prereq_course_id, title AS root_title, 0 AS depth FROM courses WHERE prereq_course_id IS NULL UNION ALL SELECT c.course_id, c.title, c.prereq_course_id, pc.root_title, pc.depth + 1 FROM courses c JOIN prereq_chain pc ON c.prereq_course_id = pc.course_id) SELECT title AS course_title, root_title AS root_course, depth FROM prereq_chain ORDER BY root_title, depth;'),
('5cc1dd74-9631-4f8b-adcb-cb0c7ab42e81', 'For each student with multiple enrollments, compar...', 'For each student with multiple enrollments, compare their grade score in each semester to the previous one using LAG. Show student_id, semester_id, avg_score, and prev_score.', 'university', 'Hard', 25, 'SELECT student_id, semester_id, avg_score, LAG(avg_score) OVER (PARTITION BY student_id ORDER BY semester_id) AS prev_score FROM (SELECT e.student_id, e.semester_id, ROUND(AVG(g.final_score), 2) AS avg_score FROM enrollments e JOIN grades g ON e.enrollment_id = g.grade_id GROUP BY e.student_id, e.semester_id) ORDER BY student_id, semester_id;'),
('134f300a-eee4-4dea-a3a1-09bbd03eaae6', 'Find students whose final score improved (was high...', 'Find students whose final score improved (was higher) in every subsequent enrollment compared to their first enrollment. Show student_id and first_score.', 'university', 'Hard', 25, 'WITH scored AS (SELECT e.student_id, e.enrollment_id, g.final_score, LAG(g.final_score) OVER (PARTITION BY e.student_id ORDER BY e.enrollment_id) AS prev_score FROM enrollments e JOIN grades g ON e.enrollment_id = g.grade_id), improving AS (SELECT student_id, MIN(final_score) AS first_score, SUM(CASE WHEN prev_score IS NOT NULL AND final_score <= prev_score THEN 1 ELSE 0 END) AS bad_cnt FROM scored GROUP BY student_id HAVING bad_cnt = 0 AND COUNT(*) > 1) SELECT student_id, first_score FROM improving ORDER BY student_id;'),
('0fc4f10b-1ff3-469f-8f4a-fbebeed48726', 'Show the top 2 courses by enrollment in each semes...', 'Show the top 2 courses by enrollment in each semester using RANK(). Show semester_name, course title, enrollment_count, and rank for rank <= 2.', 'university', 'Hard', 25, 'WITH ranked AS (SELECT s.name AS semester_name, c.title, COUNT(e.enrollment_id) AS enrollment_count, RANK() OVER (PARTITION BY s.semester_id ORDER BY COUNT(e.enrollment_id) DESC) AS rn FROM semesters s JOIN enrollments e ON s.semester_id = e.semester_id JOIN courses c ON e.course_id = c.course_id GROUP BY s.semester_id, c.course_id) SELECT * FROM ranked WHERE rn <= 2 ORDER BY semester_name, rn;'),
('16d817d6-049d-47b8-bf9e-ca01749dae07', 'Calculate a rolling average of final_score for eac...', 'Calculate a rolling average of final_score for each student over their enrollments (ordered by enrollment_id). Show student_id, enrollment_id, final_score, rolling_avg.', 'university', 'Hard', 25, 'SELECT e.student_id, e.enrollment_id, g.final_score, ROUND(AVG(g.final_score) OVER (PARTITION BY e.student_id ORDER BY e.enrollment_id ROWS UNBOUNDED PRECEDING), 2) AS rolling_avg FROM enrollments e JOIN grades g ON e.enrollment_id = g.grade_id ORDER BY e.student_id, e.enrollment_id;'),
('ca459b36-12d5-4095-b4cf-5edab75b4117', 'Find pairs of students who share the same advisor ...', 'Find pairs of students who share the same advisor and are enrolled in at least one common course. Show student1_name, student2_name, and shared_advisor_id.', 'university', 'Hard', 25, 'SELECT DISTINCT s1.first_name || '' '' || s1.last_name AS student1_name, s2.first_name || '' '' || s2.last_name AS student2_name, s1.advisor_id AS shared_advisor_id FROM enrollments e1 JOIN enrollments e2 ON e1.course_id = e2.course_id AND e1.student_id < e2.student_id JOIN students s1 ON e1.student_id = s1.student_id JOIN students s2 ON e2.student_id = s2.student_id WHERE s1.advisor_id = s2.advisor_id AND s1.advisor_id IS NOT NULL ORDER BY shared_advisor_id;'),
('94e973a8-25bc-49a1-9b9b-a525edc4138e', 'Calculate NTILE(3) (thirds) of students by their a...', 'Calculate NTILE(3) (thirds) of students by their average grade score. Show student_name, avg_score, and tier (1=top third, 3=bottom third).', 'university', 'Hard', 25, 'SELECT student_name, avg_score, NTILE(3) OVER (ORDER BY avg_score DESC) AS tier FROM (SELECT s.first_name || '' '' || s.last_name AS student_name, ROUND(AVG(g.final_score), 2) AS avg_score FROM students s JOIN enrollments e ON s.student_id = e.student_id JOIN grades g ON e.enrollment_id = g.grade_id GROUP BY s.student_id) ORDER BY tier, avg_score DESC;'),
('914833b2-5aa2-409d-a9ac-b268b04c09b6', 'Use a CTE to identify professors whose advisees co...', 'Use a CTE to identify professors whose advisees consistently score above 85. Show professor_name and avg_advisee_score. Only include professors with at least 2 advisees.', 'university', 'Hard', 25, 'WITH scores AS (SELECT p.professor_id, p.first_name || '' '' || p.last_name AS professor_name, COUNT(DISTINCT s.student_id) AS advisee_count, ROUND(AVG(g.final_score), 2) AS avg_advisee_score FROM professors p JOIN students s ON p.professor_id = s.advisor_id JOIN enrollments e ON s.student_id = e.student_id JOIN grades g ON e.enrollment_id = g.grade_id GROUP BY p.professor_id) SELECT professor_name, avg_advisee_score FROM scores WHERE avg_advisee_score > 85 AND advisee_count >= 2 ORDER BY avg_advisee_score DESC;'),
('2339bc2e-fdf7-4bd8-893c-af2e4fb79cd2', 'For each course enrollment, show the next course t...', 'For each course enrollment, show the next course the student enrolled in (ordered by enrollment_id). Show student_id, current_course_title, and next_course_title.', 'university', 'Hard', 25, 'SELECT e.student_id, c.title AS current_course_title, LEAD(c.title) OVER (PARTITION BY e.student_id ORDER BY e.enrollment_id) AS next_course_title FROM enrollments e JOIN courses c ON e.course_id = c.course_id ORDER BY e.student_id, e.enrollment_id;'),
('f147a44e-b0be-4434-9914-96cece64932f', 'Find courses where all enrolled students received ...', 'Find courses where all enrolled students received an A grade. Show course title and total_students.', 'university', 'Hard', 25, 'SELECT c.title, COUNT(e.enrollment_id) AS total_students FROM courses c JOIN enrollments e ON c.course_id = e.course_id JOIN grades g ON e.enrollment_id = g.grade_id GROUP BY c.course_id HAVING SUM(CASE WHEN g.letter_grade != ''A'' THEN 1 ELSE 0 END) = 0 ORDER BY total_students DESC;'),
('b39d4c10-58c6-484e-846a-aacb507e0ab7', 'Create a semester-over-semester comparison: for ea...', 'Create a semester-over-semester comparison: for each course, show enrollment in Fall 2023 vs Fall 2022, and the change. Show course_title, fall23_count, fall22_count, change.', 'university', 'Hard', 25, 'SELECT c.title AS course_title, SUM(CASE WHEN e.semester_id = 3 THEN 1 ELSE 0 END) AS fall23_count, SUM(CASE WHEN e.semester_id = 1 THEN 1 ELSE 0 END) AS fall22_count, SUM(CASE WHEN e.semester_id = 3 THEN 1 ELSE 0 END) - SUM(CASE WHEN e.semester_id = 1 THEN 1 ELSE 0 END) AS change FROM courses c LEFT JOIN enrollments e ON c.course_id = e.course_id GROUP BY c.course_id HAVING fall23_count > 0 OR fall22_count > 0 ORDER BY change DESC;'),
('1f8916e3-bc2d-4ee8-ae20-d108c3072dbb', 'Identify students who scored in the top 10% in the...', 'Identify students who scored in the top 10% in their major (by average final score). Show student name, major, avg_score, and percentile.', 'university', 'Hard', 25, 'WITH scored AS (SELECT s.student_id, s.first_name || '' '' || s.last_name AS student_name, s.major, ROUND(AVG(g.final_score), 2) AS avg_score FROM students s JOIN enrollments e ON s.student_id = e.student_id JOIN grades g ON e.enrollment_id = g.grade_id GROUP BY s.student_id) SELECT student_name, major, avg_score, NTILE(10) OVER (PARTITION BY major ORDER BY avg_score DESC) AS decile FROM scored WHERE decile = 1 ORDER BY major, avg_score DESC;'),
('079ca2bc-cf7b-469b-8d25-31b98e4f191a', 'Calculate cumulative credit hours earned per stude...', 'Calculate cumulative credit hours earned per student across semesters (ordered by semester start_date). Show student_id, semester_name, semester_credits, and running_total_credits.', 'university', 'Hard', 25, 'WITH sem_credits AS (SELECT e.student_id, s.name AS semester_name, s.start_date, SUM(c.credit_hours) AS semester_credits FROM enrollments e JOIN courses c ON e.course_id = c.course_id JOIN semesters s ON e.semester_id = s.semester_id GROUP BY e.student_id, s.semester_id) SELECT student_id, semester_name, semester_credits, SUM(semester_credits) OVER (PARTITION BY student_id ORDER BY start_date ROWS UNBOUNDED PRECEDING) AS running_total_credits FROM sem_credits ORDER BY student_id, start_date;');
